function repairPhoneHistoryNewMarks_() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet) return {updated: 0, createdColumn: false};
  const columnResult = ensurePhoneHistoryNewMarkColumn_({silent: true});
  if (sheet.getLastRow() < 2) return {updated: 0, createdColumn: columnResult.created || columnResult.moved || Boolean(columnResult.removedDuplicates)};
  const headers = getHeaders_(sheet);
  const newCol = headers.indexOf(PHONE_NEW_MARK_HEADER) + 1;
  if (newCol <= 0) return {updated: 0, createdColumn: columnResult.created};

  try { repairPhoneHistoryStatusDropdown_(sheet); } catch (e) {
    console.log("電話対応プルダウン修復をスキップ: " + e.message);
  }

  const rowCount = sheet.getLastRow() - 1;
  const values = sheet.getRange(2, 1, rowCount, headers.length).getValues();
  const marks = values.map(row => {
    const obj = objectFromRow(headers, row);
    return [getPhoneNewMarkText_(obj["電話対応"], obj)];
  });
  sheet.getRange(2, newCol, rowCount, 1).setValues(marks);
  formatPhoneNewMarkColumn_(sheet);
  try { repairPhoneHistoryReadCheckboxes_(sheet); } catch (e) {
    console.log("電話履歴の既読チェック修復をスキップ: " + e.message);
  }
  try { repairPhoneHistoryMobileNotifyColumns_(sheet); } catch (e) {
    console.log("電話履歴のスマホ通知用列修復をスキップ: " + e.message);
  }
  try { repairPhoneHistoryNotifyRecipientColumns_(sheet); } catch (e) {
    console.log("電話履歴通知先列修復をスキップ: " + e.message);
  }
  try { repairPhoneHistoryDoneCheckColumn_(sheet); } catch (e) {
    console.log("電話履歴の完了チェック修復をスキップ: " + e.message);
  }
  return {updated: marks.length, createdColumn: columnResult.created || columnResult.moved || Boolean(columnResult.removedDuplicates)};
}

function repairPhoneHistoryReadCheckboxes_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return 0;

  clearSettingsCache_();
  const members = getPersonalMembers_();
  let headers = getHeaders_(sheet);
  if (headers.indexOf(READ_HEADER) >= 0) {
    ensurePersonalCheckColumns_(sheet, members);
    headers = getHeaders_(sheet);
  }

  setCheckboxesForDataRows(sheet);
  applyPersonalCheckColumnLayout_(sheet);
  try { rebuildPersonalCheckGroupForSheet_(sheet); } catch (e) {}
  return getCheckboxHeadersForSheet_(sheet).length;
}




function isPhoneHistoryDoneCheckHeader_(header) {
  return String(header || "") === PHONE_DONE_CHECK_HEADER;
}

function isPhoneHistoryLegacyStatusActionHeader_(header) {
  return PHONE_LEGACY_STATUS_ACTION_HEADERS.indexOf(String(header || "")) >= 0;
}

function handlePhoneHistoryDoneCheckEdit_(sheet, row, checked) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return {status: ""};

  // p61br:
  // 完了チェックを利用者操作の正とする。
  // 先にチェックボックスの表示値を明示的に確定し、隠し内部列の「電話対応=完了」が残っていても
  // 後続の修復処理で勝手に再チェックされないようにする。
  ensurePhoneHistoryDoneCheckColumn_(sheet);
  const headers = getHeaders_(sheet);
  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  if (doneCol > 0) {
    const doneCell = sheet.getRange(row, doneCol);
    doneCell.insertCheckboxes();
    doneCell.setValue(checked === true);
  }

  const nextStatus = checked === true ? "完了" : "";
  setPhoneHistoryInternalDoneState_(sheet, row, checked === true, headers);
  applyPhoneHistoryStatusForRow_(sheet, row, nextStatus);

  // applyPhoneHistoryStatusForRow_ 内でも完了チェックを同期するため、最後にもう一度、利用者のOFF/ONを優先して確定する。
  if (doneCol > 0) {
    const doneCell = sheet.getRange(row, doneCol);
    doneCell.insertCheckboxes();
    doneCell.setValue(checked === true);
  }

  return {status: nextStatus};
}

function repairPhoneHistoryDoneCheckColumn() {
  const lock = acquireCompanyPackLock_("電話履歴の完了チェックを作成/修復");
  if (!lock) return;
  try {
    const result = repairPhoneHistoryDoneCheckColumn_();
    toast_("電話履歴の完了チェックを修復しました（追加:" + result.created + "列 / 旧操作列削除:" + result.removed + "列 / チェック修復:" + result.rows + "行 / FALSE表示掃除:" + (result.cleaned || 0) + "セル）。");
  } catch (err) {
    toast_("電話履歴の完了チェック修復でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function repairPhoneHistoryDoneCheckColumn_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {created: 0, removed: 0, rows: 0, cleaned: 0};
  const result = ensurePhoneHistoryDoneCheckColumn_(sheet);
  const rows = syncPhoneHistoryDoneCheckColumn_(sheet);
  const cleaned = cleanPhoneHistoryDoneCheckFalseDisplay_(sheet);
  formatPhoneHistoryDoneCheckColumn_(sheet);
  return {created: result.created || 0, removed: result.removed || 0, rows: rows, cleaned: cleaned};
}

function ensurePhoneHistoryDoneCheckColumn_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {created: 0, removed: 0};

  let created = 0;
  let removed = 0;
  let headers = getHeaders_(sheet);
  let statusCol = headers.indexOf("電話対応") + 1; // p61bv: 旧列が残っている場合だけ参照

  let doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  if (doneCol <= 0) {
    // p61bd: 電話対応は最後尾の内部列へ寄せるため、完了チェックは日常入力列側（担当の後）へ追加する。
    let insertAfterCol = headers.indexOf("担当") + 1;
    if (insertAfterCol <= 0) insertAfterCol = headers.indexOf("内容") + 1;
    if (insertAfterCol <= 0) insertAfterCol = statusCol;
    if (insertAfterCol <= 0) insertAfterCol = Math.max(headers.length, 1);
    sheet.insertColumnAfter(insertAfterCol);
    sheet.getRange(1, insertAfterCol + 1).setValue(PHONE_DONE_CHECK_HEADER);
    created++;
  }

  // p61ba: p61azの3操作列が残っている場合は、完了操作だけ完了チェックへ引き継いでから削除する。
  headers = getHeaders_(sheet);
  statusCol = headers.indexOf("電話対応") + 1;
  doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  const legacyCols = PHONE_LEGACY_STATUS_ACTION_HEADERS
    .map(function(header) { return {header: header, col: headers.indexOf(header) + 1}; })
    .filter(function(item) { return item.col > 0; });

  const lastRow = Math.max(sheet.getLastRow(), 1);
  const legacyDoneCol = headers.indexOf(PHONE_ACTION_DONE_HEADER) + 1;
  const shouldMigrateDoneValues = created > 0 || legacyDoneCol > 0;

  // p61br:
  // 完了チェック列が既にある通常運用中は、ここで全行を「電話対応=完了」から再チェックしない。
  // 既存の完了チェックOFFを勝手にTRUEへ戻す原因になるため、作成直後または旧「完了操作」列の移行時だけ値を統合する。
  if (shouldMigrateDoneValues && lastRow >= 2 && doneCol > 0) {
    const rowCount = lastRow - 1;
    const statusValues = statusCol > 0 ? sheet.getRange(2, statusCol, rowCount, 1).getValues() : [];
    const doneValues = sheet.getRange(2, doneCol, rowCount, 1).getValues();
    let legacyDoneValues = [];
    if (legacyDoneCol > 0) {
      legacyDoneValues = sheet.getRange(2, legacyDoneCol, rowCount, 1).getValues();
    }

    const cleanedStatusValues = [];
    const cleanedDoneValues = [];
    for (let i = 0; i < rowCount; i++) {
      const status = normalizePhoneStatus_(statusValues[i] ? statusValues[i][0] : "");
      const oldDone = legacyDoneValues[i] && (legacyDoneValues[i][0] === true || String(legacyDoneValues[i][0]).toUpperCase() === "TRUE");
      const doneState = parsePhoneHistoryDoneCheckValue_(doneValues[i] ? doneValues[i][0] : "");
      const isDone = oldDone || (doneState.hasValue ? doneState.checked : status === "完了");
      cleanedStatusValues.push([isDone ? "完了" : ""]);
      cleanedDoneValues.push([isDone]);
    }
    if (statusCol > 0) sheet.getRange(2, statusCol, rowCount, 1).setValues(cleanedStatusValues);
    sheet.getRange(2, doneCol, rowCount, 1).setValues(cleanedDoneValues);
  }

  // 旧操作列は右から削除し、列ずれを防ぐ。
  headers = getHeaders_(sheet);
  PHONE_LEGACY_STATUS_ACTION_HEADERS
    .map(function(header) { return headers.indexOf(header) + 1; })
    .filter(function(col) { return col > 0; })
    .sort(function(a, b) { return b - a; })
    .forEach(function(col) {
      try {
        sheet.deleteColumn(col);
        removed++;
      } catch (e) {
        console.log("電話履歴の旧対応操作列削除をスキップ: " + e.message);
      }
    });

  formatPhoneHistoryDoneCheckColumn_(sheet);
  return {created: created, removed: removed};
}

function parsePhoneHistoryDoneCheckValue_(value) {
  const text = String(value === null || value === undefined ? "" : value).trim().toUpperCase();
  const hasBooleanValue = value === true || value === false || text === "TRUE" || text === "FALSE";
  return {
    hasValue: hasBooleanValue,
    checked: value === true || text === "TRUE"
  };
}

function setPhoneHistoryInternalDoneState_(sheet, row, checked, headers) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return;
  headers = headers && headers.length ? headers : getHeaders_(sheet);
  const statusCol = headers.indexOf("電話対応") + 1;
  const completedCol = headers.indexOf("対応完了日時") + 1;

  if (statusCol > 0) {
    const statusCell = sheet.getRange(row, statusCol);
    if (checked) {
      statusCell.setValue("完了");
    } else {
      statusCell.clearContent();
    }
    try { statusCell.clearDataValidations(); } catch (e) {}
  }

  if (completedCol > 0) {
    const completedCell = sheet.getRange(row, completedCol);
    completedCell.setNumberFormat("yyyy/mm/dd hh:mm");
    if (checked) {
      const current = completedCell.getValue();
      if (!current || isDateOnlyLike_(current)) completedCell.setValue(new Date());
      completedCell.setNumberFormat("yyyy/mm/dd hh:mm");
    } else {
      completedCell.clearContent();
      completedCell.setNumberFormat("yyyy/mm/dd hh:mm");
    }
  }
}

function setPhoneHistoryDoneCheckForRow_(sheet, row, phoneStatus) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return false;
  let headers = getHeaders_(sheet);
  let doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  if (doneCol <= 0) {
    ensurePhoneHistoryDoneCheckColumn_(sheet);
    headers = getHeaders_(sheet);
    doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  }
  if (doneCol <= 0) return false;

  const rowValues = sheet.getRange(row, 1, 1, headers.length).getValues()[0];
  const rowObj = objectFromRow(headers, rowValues);
  const statusCol = headers.indexOf("電話対応") + 1;
  const rawStatus = phoneStatus !== undefined ? phoneStatus : (statusCol > 0 ? rowValues[statusCol - 1] : "");
  const status = normalizePhoneStatus_(rawStatus);
  const meaningful = isMeaningfulPhoneHistoryRowObject_(rowObj);
  const cell = sheet.getRange(row, doneCol);
  const rawDoneValue = cell.getValue();
  const doneState = parsePhoneHistoryDoneCheckValue_(rawDoneValue);

  // p61br:
  // phoneStatus が明示されている場合は、その呼び出し元の状態を正とする。
  // phoneStatus が未指定の修復・手動整理では、見えている完了チェックのTRUE/FALSEを正とする。
  // これにより、隠し列「電話対応=完了」が残っていても、利用者が完了チェックをOFFにした行は再チェックされない。
  let shouldBeDone;
  if (phoneStatus !== undefined) {
    shouldBeDone = status === "完了";
  } else if (doneState.hasValue) {
    shouldBeDone = doneState.checked;
  } else {
    shouldBeDone = status === "完了";
  }

  if (!meaningful) {
    cell.clearContent().clearDataValidations();
    setPhoneHistoryInternalDoneState_(sheet, row, false, headers);
    return true;
  }

  cell.insertCheckboxes();
  cell.setValue(shouldBeDone);
  setPhoneHistoryInternalDoneState_(sheet, row, shouldBeDone, headers);
  return true;
}

function syncPhoneHistoryDoneCheckForRow_(sheet, row, phoneStatus) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return false;
  const headers = getHeaders_(sheet);
  if (headers.indexOf(PHONE_DONE_CHECK_HEADER) < 0) return false;
  return setPhoneHistoryDoneCheckForRow_(sheet, row, phoneStatus);
}

function syncPhoneHistoryDoneCheckColumn_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  ensurePhoneHistoryDoneCheckColumn_(sheet);
  const scanLastRow = getPhoneHistoryDoneCheckScanLastRow_(sheet);
  let updated = 0;
  for (let row = 2; row <= scanLastRow; row++) {
    if (setPhoneHistoryDoneCheckForRow_(sheet, row)) updated++;
  }
  return updated;
}

function getPhoneHistoryDoneCheckScanLastRow_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return 1;
  const maxRows = sheet.getMaxRows();
  const lastRow = Math.max(sheet.getLastRow(), 1);
  const applyLastRow = Math.max(getApplyRowCount_(sheet) + 1, MIN_DATA_ROWS_FOR_VALIDATION + 1);
  return Math.min(maxRows, Math.max(lastRow, applyLastRow));
}

function isCheckboxValidationRule_(rule) {
  try {
    return !!rule && rule.getCriteriaType && rule.getCriteriaType() === SpreadsheetApp.DataValidationCriteria.CHECKBOX;
  } catch (e) {
    return false;
  }
}

function cleanPhoneHistoryDoneCheckFalseDisplay_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  const headers = getHeaders_(sheet);
  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  if (doneCol <= 0) return 0;

  const scanLastRow = getPhoneHistoryDoneCheckScanLastRow_(sheet);
  if (scanLastRow < 2) return 0;

  const rowCount = scanLastRow - 1;
  const values = sheet.getRange(2, 1, rowCount, headers.length).getValues();
  const doneRange = sheet.getRange(2, doneCol, rowCount, 1);
  const doneValues = doneRange.getValues();
  const validations = doneRange.getDataValidations();
  let cleaned = 0;

  for (let i = 0; i < rowCount; i++) {
    const row = i + 2;
    const rowObj = objectFromRow(headers, values[i]);
    const meaningful = isMeaningfulPhoneHistoryRowObject_(rowObj);
    const raw = doneValues[i][0];
    const rawText = String(raw || "").toUpperCase();
    const hasCheckbox = isCheckboxValidationRule_(validations[i] && validations[i][0]);
    const looksLikeDetachedBoolean = raw === true || raw === false || rawText === "TRUE" || rawText === "FALSE";

    if (!meaningful) {
      if (raw !== "" || hasCheckbox) {
        sheet.getRange(row, doneCol).clearContent().clearDataValidations();
        cleaned++;
      }
      continue;
    }

    if (looksLikeDetachedBoolean && !hasCheckbox) {
      sheet.getRange(row, doneCol).insertCheckboxes();
      sheet.getRange(row, doneCol).setValue(raw === true || rawText === "TRUE");
      cleaned++;
    }
  }

  return cleaned;
}

function formatPhoneHistoryDoneCheckColumn_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return;
  const headers = getHeaders_(sheet);
  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  const statusCol = headers.indexOf("電話対応") + 1;

  if (doneCol > 0) {
    try {
      sheet.setColumnWidth(doneCol, 62);
      sheet.getRange(1, doneCol)
        .setFontWeight("bold")
        .setHorizontalAlignment("center")
        .setVerticalAlignment("middle")
        .setWrap(true)
        .setBackground("#d9ead3")
        .setFontColor("#274e13");
      const rowCount = Math.max(sheet.getLastRow(), MIN_DATA_ROWS_FOR_VALIDATION + 1);
      sheet.getRange(2, doneCol, Math.min(sheet.getMaxRows() - 1, Math.max(rowCount - 1, 1)), 1)
        .setHorizontalAlignment("center")
        .setVerticalAlignment("middle");
    } catch (e) {}
  }

  // 電話対応は内部状態として残すが、通常入力では完了チェックを使うため非表示へ寄せる。
  if (statusCol > 0) {
    try {
      sheet.getRange(2, statusCol, Math.max(1, sheet.getMaxRows() - 1), 1).clearDataValidations();
      sheet.setColumnWidth(statusCol, 70);
      sheet.hideColumns(statusCol);
    } catch (e) {}
  }
}

function syncSharedUsersToPhoneNotifySettings() {
  const lock = acquireCompanyPackLock_("共有ユーザーを電話通知先候補へ反映");
  if (!lock) return;
  try {
    const result = syncSharedUsersToPhoneNotifySettings_();
    toast_("共有ユーザーを電話通知先候補へ反映しました（追加:" + result.added + "件 / 既存:" + result.existing + "件）。必要な人だけ設定シートで残してください。");
  } catch (err) {
    toast_("共有ユーザーの電話通知先反映でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function syncSharedUsersToPhoneNotifySettings_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const settings = ensureSettingsSheet_();
  const file = DriveApp.getFileById(ss.getId());
  const users = [];

  function addUser_(user, role) {
    if (!user) return;
    let email = "";
    let name = "";
    try { email = String(user.getEmail() || "").trim(); } catch (e) {}
    try { name = String(user.getName() || "").trim(); } catch (e) {}
    if (!email) return;
    users.push({email: email, name: name || email, role: role});
  }

  try { addUser_(file.getOwner(), "オーナー"); } catch (e) {}
  try { file.getEditors().forEach(function(u) { addUser_(u, "編集者"); }); } catch (e) {}
  try { file.getViewers().forEach(function(u) { addUser_(u, "閲覧者"); }); } catch (e) {}

  const unique = {};
  users.forEach(function(u) {
    const key = String(u.email || "").toLowerCase();
    if (!key) return;
    if (!unique[key]) unique[key] = u;
  });

  const lastRow = settings.getLastRow();
  const existingEmails = {};
  if (lastRow >= 2) {
    const values = settings.getRange(2, 1, lastRow - 1, Math.max(settings.getLastColumn(), 3)).getValues();
    values.forEach(function(row) {
      const type = String(row[0] || "").trim();
      if (type !== PHONE_NOTIFY_SETTINGS_TYPE) return;
      const value = String(row[1] || "").trim();
      const note = String(row[2] || "").trim();
      const email = extractEmailAddress_(note) || extractEmailAddress_(value);
      if (email) existingEmails[email.toLowerCase()] = true;
    });
  }

  const rows = [];
  Object.keys(unique).sort().forEach(function(key) {
    const u = unique[key];
    if (existingEmails[key]) return;
    rows.push([PHONE_NOTIFY_SETTINGS_TYPE, u.name || u.email, u.email + " / " + u.role]);
  });

  if (rows.length) {
    settings.getRange(settings.getLastRow() + 1, 1, rows.length, 3).setValues(rows);
  }
  clearSettingsCache_();
  return {added: rows.length, existing: Object.keys(existingEmails).length};
}

function extractEmailAddress_(text) {
  const m = String(text || "").match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return m ? m[0] : "";
}

function getPhoneNotifyRecipients_() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("設定");
  if (!sheet || sheet.getLastRow() < 2) return [];
  const values = sheet.getRange(2, 1, sheet.getLastRow() - 1, Math.max(sheet.getLastColumn(), 3)).getValues();
  const seenEmail = {};
  const seenLabel = {};
  const list = [];

  values.forEach(function(row) {
    const type = String(row[0] || "").trim();
    if (type !== PHONE_NOTIFY_SETTINGS_TYPE) return;
    const rawName = String(row[1] || "").trim();
    const rawNote = String(row[2] || "").trim();
    if (/OFF|無効|停止|通知しない/i.test(rawNote)) return;
    const email = extractEmailAddress_(rawNote) || extractEmailAddress_(rawName);
    if (!email) return;
    const key = email.toLowerCase();
    if (seenEmail[key]) return;
    seenEmail[key] = true;
    let label = rawName && !extractEmailAddress_(rawName) ? rawName : email;
    if (seenLabel[label]) label = label + " <" + email + ">";
    seenLabel[label] = true;
    list.push({label: label, name: label, email: email});
  });

  return list.sort(function(a, b) { return String(a.label).localeCompare(String(b.label), "ja"); });
}

function getPhoneNotifyRecipientLabels_() {
  return getPhoneNotifyRecipients_().map(function(r) { return r.label; });
}

function getPhoneNotifyRecipientEmails_() {
  return getPhoneNotifyRecipients_().map(function(r) { return r.email; });
}

function findPhoneNotifyRecipientByLabel_(label) {
  const key = String(label || "").trim();
  if (!key) return null;
  const list = getPhoneNotifyRecipients_();
  return list.find(function(r) { return r.label === key || r.email === key; }) || null;
}

function findPhoneNotifyRecipientByEmail_(email) {
  const key = String(email || "").trim().toLowerCase();
  if (!key) return null;
  const list = getPhoneNotifyRecipients_();
  return list.find(function(r) { return String(r.email || "").toLowerCase() === key; }) || null;
}


function getPhoneNotifyEmailCandidateList_() {
  const candidates = [];
  const seen = {};
  function add(value) {
    const email = extractEmailAddress_(value) || String(value || "").trim();
    if (!email || !isEmailLike_(email)) return;
    const key = email.toLowerCase();
    if (seen[key]) return;
    seen[key] = true;
    candidates.push(email);
  }

  getPhoneNotifyRecipientEmails_().forEach(add);

  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (sheet && sheet.getLastRow() >= 2) {
    const headers = getHeaders_(sheet);
    const emailCol = headers.indexOf(PHONE_NOTIFY_EMAIL_HEADER) + 1;
    if (emailCol > 0) {
      const values = sheet.getRange(2, emailCol, sheet.getLastRow() - 1, 1).getDisplayValues();
      values.forEach(function(row) { add(row[0]); });
    }
  }

  return candidates.sort(function(a, b) { return String(a).localeCompare(String(b), "ja"); });
}

function addPhoneNotifyEmailToSettingsIfNeeded_(email) {
  const value = extractEmailAddress_(email) || String(email || "").trim();
  if (!value || !isEmailLike_(value)) return false;

  const sheet = ensureSettingsSheet_();
  const lastRow = sheet.getLastRow();
  const existing = lastRow >= 2 ? sheet.getRange(2, 1, lastRow - 1, Math.max(sheet.getLastColumn(), 3)).getValues() : [];
  const key = value.toLowerCase();
  const exists = existing.some(function(row) {
    const type = String(row[0] || "").trim();
    if (type !== PHONE_NOTIFY_SETTINGS_TYPE) return false;
    const name = String(row[1] || "").trim();
    const note = String(row[2] || "").trim();
    const rowEmail = extractEmailAddress_(note) || extractEmailAddress_(name);
    return rowEmail && rowEmail.toLowerCase() === key;
  });
  if (exists) return false;

  sheet.getRange(sheet.getLastRow() + 1, 1, 1, 3).setValues([[PHONE_NOTIFY_SETTINGS_TYPE, value, "電話履歴入力から自動追加"]]);
  clearSettingsCache_();
  return true;
}

function rebuildPhoneNotifyEmailSettingsFromPhoneHistory_() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getLastRow() < 2) return 0;
  const headers = getHeaders_(sheet);
  const emailCol = headers.indexOf(PHONE_NOTIFY_EMAIL_HEADER) + 1;
  if (emailCol <= 0) return 0;

  const values = sheet.getRange(2, emailCol, sheet.getLastRow() - 1, 1).getDisplayValues();
  let added = 0;
  values.forEach(function(row) {
    if (addPhoneNotifyEmailToSettingsIfNeeded_(row[0])) added++;
  });
  clearSettingsCache_();
  return added;
}

function repairPhoneNotifyEmailDropdownP61CM_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {added: 0, formatted: false};
  const added = rebuildPhoneNotifyEmailSettingsFromPhoneHistory_();
  formatPhoneNotificationRecipientColumns_(sheet);
  return {added: added, formatted: true};
}

function getPhoneNotifyRecipientSourceRange_(kind) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let helper = ss.getSheetByName(PHONE_STATUS_DROPDOWN_HELPER_SHEET_NAME);
  if (!helper) helper = ss.insertSheet(PHONE_STATUS_DROPDOWN_HELPER_SHEET_NAME);
  const col = kind === "email" ? 3 : 2;
  const header = kind === "email" ? "電話通知先メール候補" : "電話通知先候補";
  const items = kind === "email" ? getPhoneNotifyEmailCandidateList_() : getPhoneNotifyRecipientLabels_();
  const values = [[""]].concat(uniqueList_(items).map(function(v) { return [v]; }));
  helper.getRange(1, col).setValue(header);
  helper.getRange(2, col, Math.max(values.length, 1), 1).clearContent();
  helper.getRange(2, col, values.length, 1).setValues(values);
  helper.setColumnWidth(col, kind === "email" ? 220 : 160);
  try { if (!helper.isSheetHidden()) helper.hideSheet(); } catch (e) {}
  return helper.getRange(2, col, values.length, 1);
}

function repairPhoneHistoryNotifyRecipientColumns() {
  const lock = acquireCompanyPackLock_("電話履歴の通知先列修復");
  if (!lock) return;
  try {
    const result = repairPhoneHistoryNotifyRecipientColumns_();
    toast_("電話履歴の通知先列を修復しました（列追加:" + result.created + " / 再計算:" + result.updated + "行）。");
  } catch (err) {
    toast_("電話履歴の通知先列修復でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function repairPhoneHistoryNotifyRecipientColumns_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {created: 0, updated: 0};
  const created = ensurePhoneHistoryNotificationColumns_(sheet).created || 0;
  let headers = getHeaders_(sheet);
  const rowCount = Math.max(sheet.getLastRow() - 1, 0);
  let updated = 0;
  for (let r = 2; r <= rowCount + 1; r++) {
    updatePhoneNotificationRecipientForRow_(sheet, r);
    updated++;
  }
  const added = rebuildPhoneNotifyEmailSettingsFromPhoneHistory_();
  formatPhoneNotificationRecipientColumns_(sheet);
  return {created: created, updated: updated, added: added};
}

function ensurePhoneHistoryNotificationColumns_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {created: 0};
  let created = 0;
  let headers = getHeaders_(sheet);
  const desired = [
    PHONE_NOTIFY_TO_HEADER,
    PHONE_NOTIFY_EMAIL_HEADER,
    PHONE_NOTIFY_METHOD_HEADER,
    PHONE_MOBILE_NOTIFY_HEADER,
    PHONE_MOBILE_MESSAGE_HEADER,
    PHONE_EMAIL_NOTIFY_HEADER,
    PHONE_EMAIL_SENT_AT_HEADER
  ];

  let afterCol = headers.indexOf("通知") + 1;
  if (afterCol <= 0) afterCol = headers.indexOf("対応メモ") + 1;
  if (afterCol <= 0) afterCol = Math.max(sheet.getLastColumn(), 1);

  desired.forEach(function(header) {
    headers = getHeaders_(sheet);
    if (headers.indexOf(header) >= 0) {
      afterCol = headers.indexOf(header) + 1;
      return;
    }
    sheet.insertColumnAfter(afterCol);
    sheet.getRange(1, afterCol + 1).setValue(header);
    created++;
    afterCol = afterCol + 1;
  });

  formatPhoneNotificationRecipientColumns_(sheet);
  return {created: created};
}

function formatPhoneNotificationRecipientColumns_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return;
  const headers = getHeaders_(sheet);
  const rowCount = Math.max(getApplyRowCount_(sheet), 300);
  const count = Math.max(1, Math.min(rowCount, sheet.getMaxRows() - 1));
  const toCol = headers.indexOf(PHONE_NOTIFY_TO_HEADER) + 1;
  const emailCol = headers.indexOf(PHONE_NOTIFY_EMAIL_HEADER) + 1;
  const methodCol = headers.indexOf(PHONE_NOTIFY_METHOD_HEADER) + 1;
  const mailCol = headers.indexOf(PHONE_EMAIL_NOTIFY_HEADER) + 1;
  const sentCol = headers.indexOf(PHONE_EMAIL_SENT_AT_HEADER) + 1;

  if (toCol > 0) {
    try {
      const rule = SpreadsheetApp.newDataValidation().requireValueInRange(getPhoneNotifyRecipientSourceRange_("label"), true).setAllowInvalid(false).build();
      sheet.getRange(2, toCol, count, 1).setDataValidation(rule).setVerticalAlignment("middle");
      sheet.setColumnWidth(toCol, 140);
    } catch (e) {}
  }
  if (emailCol > 0) {
    try {
      // p61cm:
      // 通知先メールは「候補表示＋候補外手入力OK」。
      // 候補元は、設定シートの電話通知先メール＋電話履歴で過去に入力済みのメール。
      // setAllowInvalid(true) にして、初めて入力するメールも弾かない。
      const rule = SpreadsheetApp.newDataValidation()
        .requireValueInRange(getPhoneNotifyRecipientSourceRange_("email"), true)
        .setAllowInvalid(true)
        .build();
      sheet.getRange(2, emailCol, count, 1)
        .setDataValidation(rule)
        .setNumberFormat("@")
        .setVerticalAlignment("middle");
      sheet.setColumnWidth(emailCol, 220);
    } catch (e) {}
  }
  if (methodCol > 0) {
    try {
      setDropdownForRowsUltraLight_(sheet, methodCol, [PHONE_NOTIFY_METHOD_APPSHEET, PHONE_NOTIFY_METHOD_EMAIL, PHONE_NOTIFY_METHOD_BOTH], count, false);
      sheet.setColumnWidth(methodCol, 95);
    } catch (e) {}
  }
  if (mailCol > 0) {
    try {
      setDropdownForRowsUltraLight_(sheet, mailCol, [PHONE_EMAIL_NOTIFY_TARGET, PHONE_EMAIL_NOTIFY_SENT, PHONE_EMAIL_NOTIFY_SKIP], count, false);
      sheet.setColumnWidth(mailCol, 95);
    } catch (e) {}
  }
  if (sentCol > 0) {
    try {
      sheet.getRange(2, sentCol, count, 1).clearDataValidations().setNumberFormat("yyyy/mm/dd hh:mm").setVerticalAlignment("middle");
      sheet.setColumnWidth(sentCol, 145);
    } catch (e) {}
  }
}

function updatePhoneNotificationRecipientForRow_(sheet, row, phoneStatus) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return;
  ensurePhoneHistoryNotificationColumns_(sheet);
  const headers = getHeaders_(sheet);
  const toCol = headers.indexOf(PHONE_NOTIFY_TO_HEADER) + 1;
  const emailCol = headers.indexOf(PHONE_NOTIFY_EMAIL_HEADER) + 1;
  const methodCol = headers.indexOf(PHONE_NOTIFY_METHOD_HEADER) + 1;
  const mailCol = headers.indexOf(PHONE_EMAIL_NOTIFY_HEADER) + 1;
  const sentCol = headers.indexOf(PHONE_EMAIL_SENT_AT_HEADER) + 1;
  if (toCol <= 0 || emailCol <= 0 || methodCol <= 0 || mailCol <= 0) return;

  const values = sheet.getRange(row, 1, 1, headers.length).getValues()[0];
  const obj = objectFromRow(headers, values);
  const status = normalizePhoneStatus_(phoneStatus !== undefined ? phoneStatus : obj["電話対応"]);
  const isTarget = getPhoneMobileNotifyFlag_(status, obj) === PHONE_MOBILE_NOTIFY_TARGET;

  let to = String(obj[PHONE_NOTIFY_TO_HEADER] || "").trim();
  let email = String(obj[PHONE_NOTIFY_EMAIL_HEADER] || "").trim();
  let method = String(obj[PHONE_NOTIFY_METHOD_HEADER] || "").trim();
  const assignee = String(obj["担当"] || "").trim();

  if (!to && assignee) {
    const byAssignee = findPhoneNotifyRecipientByLabel_(assignee);
    if (byAssignee) to = byAssignee.label;
  }
  if (to && !email) {
    const recipient = findPhoneNotifyRecipientByLabel_(to);
    if (recipient) email = recipient.email;
  }
  if (email && !to) {
    const recipient = findPhoneNotifyRecipientByEmail_(email);
    if (recipient) to = recipient.label;
  }
  if (email) {
    try {
      if (addPhoneNotifyEmailToSettingsIfNeeded_(email)) {
        // 設定シートに追加された場合、次回以降の候補に出るようキャッシュと候補補助範囲を更新する。
        clearSettingsCache_();
        try { formatPhoneNotificationRecipientColumns_(sheet); } catch (fmtErr) {}
      }
    } catch (e) {
      console.log("電話履歴 通知先メール候補追加をスキップ: " + e.message);
    }
  }
  if (!method && (to || email)) method = PHONE_NOTIFY_METHOD_EMAIL;

  if (toCol > 0) sheet.getRange(row, toCol).setValue(to);
  if (emailCol > 0) sheet.getRange(row, emailCol).setValue(email);
  if (methodCol > 0) sheet.getRange(row, methodCol).setValue(method);

  let mailFlag = "";
  if (!isMeaningfulPhoneHistoryRowObject_(obj)) {
    mailFlag = "";
  } else if (!isTarget) {
    mailFlag = PHONE_EMAIL_NOTIFY_SKIP;
  } else if (email && (method === PHONE_NOTIFY_METHOD_EMAIL || method === PHONE_NOTIFY_METHOD_BOTH || !method)) {
    const sentAt = sentCol > 0 ? sheet.getRange(row, sentCol).getValue() : "";
    mailFlag = sentAt ? PHONE_EMAIL_NOTIFY_SENT : PHONE_EMAIL_NOTIFY_TARGET;
  } else {
    mailFlag = PHONE_EMAIL_NOTIFY_SKIP;
  }
  sheet.getRange(row, mailCol).setValue(mailFlag);
}

function sendPendingPhoneHistoryEmailNotifications() {
  const lock = acquireCompanyPackLock_("電話履歴メール通知送信");
  if (!lock) return;
  try {
    const result = sendPendingPhoneHistoryEmailNotifications_();
    toast_("電話履歴メール通知を送信しました（送信:" + result.sent + "件 / スキップ:" + result.skipped + "件）。");
  } catch (err) {
    toast_("電話履歴メール通知でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function sendPendingPhoneHistoryEmailNotifications_() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet) return {sent: 0, skipped: 0};
  repairPhoneHistoryNotifyRecipientColumns_(sheet);
  const headers = getHeaders_(sheet);
  const rowCount = Math.max(sheet.getLastRow() - 1, 0);
  let sent = 0;
  let skipped = 0;
  for (let row = 2; row <= rowCount + 1; row++) {
    const result = sendPhoneHistoryEmailForRow_(sheet, row, false);
    if (result.sent) sent++;
    else skipped++;
  }
  return {sent: sent, skipped: skipped};
}

function sendPhoneHistoryEmailForRow_(sheet, row, force) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return {sent: false, reason: "invalid"};
  ensurePhoneHistoryNotificationColumns_(sheet);
  const headers = getHeaders_(sheet);
  const values = sheet.getRange(row, 1, 1, headers.length).getValues()[0];
  const obj = objectFromRow(headers, values);
  const email = String(obj[PHONE_NOTIFY_EMAIL_HEADER] || "").trim();
  const method = String(obj[PHONE_NOTIFY_METHOD_HEADER] || "").trim();
  const mailFlag = String(obj[PHONE_EMAIL_NOTIFY_HEADER] || "").trim();
  const sentAt = obj[PHONE_EMAIL_SENT_AT_HEADER];
  const status = normalizePhoneStatus_(obj["電話対応"]);

  if (!isMeaningfulPhoneHistoryRowObject_(obj)) return {sent: false, reason: "draft"};
  if (getPhoneMobileNotifyFlag_(status, obj) !== PHONE_MOBILE_NOTIFY_TARGET) return {sent: false, reason: "not-target"};
  if (!email) return {sent: false, reason: "no-email"};
  if (!(method === PHONE_NOTIFY_METHOD_EMAIL || method === PHONE_NOTIFY_METHOD_BOTH || !method)) return {sent: false, reason: "method"};
  if (!force && sentAt) return {sent: false, reason: "sent"};
  if (!force && mailFlag && mailFlag !== PHONE_EMAIL_NOTIFY_TARGET) return {sent: false, reason: "flag"};

  const subject = "【電話履歴】新しい未対応電話があります";
  const body = buildPhoneEmailNotifyBody_(obj);
  MailApp.sendEmail({to: email, subject: subject, body: body});

  const sentCol = headers.indexOf(PHONE_EMAIL_SENT_AT_HEADER) + 1;
  const mailCol = headers.indexOf(PHONE_EMAIL_NOTIFY_HEADER) + 1;
  if (sentCol > 0) sheet.getRange(row, sentCol).setValue(new Date()).setNumberFormat("yyyy/mm/dd hh:mm");
  if (mailCol > 0) sheet.getRange(row, mailCol).setValue(PHONE_EMAIL_NOTIFY_SENT);
  return {sent: true};
}

function buildPhoneEmailNotifyBody_(rowObj) {
  const lines = [];
  lines.push(buildPhoneMobileNotifyMessage_(rowObj));
  lines.push("");
  lines.push("このメールは社内共有業務管理システムの電話履歴から自動送信されています。");
  lines.push("対応後は電話履歴の電話対応を「対応中」「折返し」「完了」などへ変更してください。");
  return lines.join("\n");
}

function phoneHistoryEmailNotificationOnEdit(e) {
  try {
    if (!e || !e.range) return;
    const sheet = e.range.getSheet();
    if (!sheet || sheet.getName() !== "電話履歴" || e.range.getRow() <= 1) return;
    const headers = getHeaders_(sheet);
    const startCol = e.range.getColumn();
    const endCol = startCol + e.range.getNumColumns() - 1;
    const edited = [];
    for (let col = startCol; col <= endCol; col++) edited.push(String(headers[col - 1] || ""));
    const watched = ["日付", "時間", "相手", "折り返し電話番号", "内容", "担当", "電話対応", PHONE_NOTIFY_TO_HEADER, PHONE_NOTIFY_EMAIL_HEADER, PHONE_NOTIFY_METHOD_HEADER];
    if (!edited.some(function(h) { return watched.includes(h); })) return;
    const startRow = Math.max(e.range.getRow(), 2);
    const endRow = e.range.getRow() + e.range.getNumRows() - 1;
    for (let row = startRow; row <= endRow; row++) {
      updatePhoneNotificationRecipientForRow_(sheet, row);
      sendPhoneHistoryEmailForRow_(sheet, row, false);
    }
  } catch (err) {
    console.log("phoneHistoryEmailNotificationOnEdit error: " + err.message);
  }
}

function installPhoneHistoryEmailNotificationTrigger() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  deletePhoneHistoryEmailNotificationTrigger_(false);
  ScriptApp.newTrigger("phoneHistoryEmailNotificationOnEdit").forSpreadsheet(ss).onEdit().create();
  toast_("電話履歴メール通知トリガーを設定しました。初回は権限承認が必要です。");
}

function deletePhoneHistoryEmailNotificationTrigger() {
  const deleted = deletePhoneHistoryEmailNotificationTrigger_(true);
  toast_("電話履歴メール通知トリガーを解除しました（" + deleted + "件）。");
}

function deletePhoneHistoryEmailNotificationTrigger_(silent) {
  let deleted = 0;
  ScriptApp.getProjectTriggers().forEach(function(t) {
    if (t.getHandlerFunction && t.getHandlerFunction() === "phoneHistoryEmailNotificationOnEdit") {
      ScriptApp.deleteTrigger(t);
      deleted++;
    }
  });
  return deleted;
}

function repairPhoneHistoryMobileNotifyColumns() {
  const lock = acquireCompanyPackLock_("電話履歴のスマホ通知用列修復");
  if (!lock) return;
  try {
    const result = repairPhoneHistoryMobileNotifyColumns_();
    toast_("電話履歴のスマホ通知用列を修復しました（列追加:" + result.created + " / 再計算:" + result.updated + "行）。AppSheet Bot側で「スマホ通知=通知対象」を条件にしてください。");
  } catch (err) {
    toast_("電話履歴のスマホ通知用列修復でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function repairPhoneHistoryMobileNotifyColumns_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {created: 0, updated: 0};

  const created = ensurePhoneHistoryNotificationColumns_(sheet).created || 0;
  let headers = getHeaders_(sheet);
  const notifyCol = headers.indexOf(PHONE_MOBILE_NOTIFY_HEADER) + 1;
  const messageCol = headers.indexOf(PHONE_MOBILE_MESSAGE_HEADER) + 1;
  if (notifyCol <= 0 || messageCol <= 0) return {created: created, updated: 0};

  const rowCount = Math.max(sheet.getLastRow() - 1, 0);
  if (rowCount > 0) {
    const values = sheet.getRange(2, 1, rowCount, headers.length).getValues();
    const notifyValues = [];
    const messageValues = [];
    values.forEach(rowValues => {
      const obj = objectFromRow(headers, rowValues);
      const flag = getPhoneMobileNotifyFlag_(obj["電話対応"], obj);
      notifyValues.push([flag]);
      messageValues.push([flag === PHONE_MOBILE_NOTIFY_TARGET ? buildPhoneMobileNotifyMessage_(obj) : ""]);
    });
    sheet.getRange(2, notifyCol, rowCount, 1).setValues(notifyValues);
    sheet.getRange(2, messageCol, rowCount, 1).setValues(messageValues);
  }

  formatPhoneMobileNotifyColumns_(sheet);
  return {created: created, updated: rowCount};
}

function ensurePhoneHistoryMobileNotifyColumns_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {created: 0};

  // p61ar: 通知先/メール通知列も同じ通知系列としてまとめて確認する。
  return ensurePhoneHistoryNotificationColumns_(sheet);
}

function ensurePhoneHistoryMobileNotifyColumns_Legacy_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {created: 0};

  let created = 0;
  let headers = getHeaders_(sheet);

  if (headers.indexOf(PHONE_MOBILE_NOTIFY_HEADER) < 0) {
    let afterCol = headers.indexOf("通知") + 1;
    if (afterCol <= 0) afterCol = headers.indexOf("対応メモ") + 1;
    if (afterCol <= 0) afterCol = Math.max(sheet.getLastColumn(), 1);
    sheet.insertColumnAfter(afterCol);
    sheet.getRange(1, afterCol + 1).setValue(PHONE_MOBILE_NOTIFY_HEADER);
    created++;
    headers = getHeaders_(sheet);
  }

  if (headers.indexOf(PHONE_MOBILE_MESSAGE_HEADER) < 0) {
    let afterCol = headers.indexOf(PHONE_MOBILE_NOTIFY_HEADER) + 1;
    if (afterCol <= 0) afterCol = headers.indexOf("通知") + 1;
    if (afterCol <= 0) afterCol = Math.max(sheet.getLastColumn(), 1);
    sheet.insertColumnAfter(afterCol);
    sheet.getRange(1, afterCol + 1).setValue(PHONE_MOBILE_MESSAGE_HEADER);
    created++;
  }

  formatPhoneMobileNotifyColumns_(sheet);
  return {created: created};
}

function formatPhoneMobileNotifyColumns_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return;
  try { formatPhoneNotificationRecipientColumns_(sheet); } catch (e) {}
  const headers = getHeaders_(sheet);
  const notifyCol = headers.indexOf(PHONE_MOBILE_NOTIFY_HEADER) + 1;
  const messageCol = headers.indexOf(PHONE_MOBILE_MESSAGE_HEADER) + 1;
  const rowCount = getApplyRowCount_(sheet);

  if (notifyCol > 0) {
    try {
      setDropdownForRowsUltraLight_(sheet, notifyCol, [PHONE_MOBILE_NOTIFY_TARGET, PHONE_MOBILE_NOTIFY_SKIP], rowCount, false);
      sheet.setColumnWidth(notifyCol, 90);
      sheet.getRange(1, notifyCol, Math.min(sheet.getMaxRows(), Math.max(sheet.getLastRow(), MIN_DATA_ROWS_FOR_VALIDATION + 1)), 1)
        .setHorizontalAlignment("center")
        .setVerticalAlignment("middle");
    } catch (e) {}
  }

  if (messageCol > 0) {
    try {
      sheet.getRange(2, messageCol, rowCount, 1).clearDataValidations().setWrap(true).setVerticalAlignment("middle");
      sheet.setColumnWidth(messageCol, 260);
    } catch (e) {}
  }
}

function updatePhoneMobileNotifyForRow_(sheet, row, phoneStatus) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return;
  ensurePhoneHistoryNotificationColumns_(sheet);
  const headers = getHeaders_(sheet);
  const notifyCol = headers.indexOf(PHONE_MOBILE_NOTIFY_HEADER) + 1;
  const messageCol = headers.indexOf(PHONE_MOBILE_MESSAGE_HEADER) + 1;
  if (notifyCol <= 0 || messageCol <= 0) return;

  const rowValues = sheet.getRange(row, 1, 1, headers.length).getValues()[0];
  const obj = objectFromRow(headers, rowValues);
  const flag = getPhoneMobileNotifyFlag_(phoneStatus !== undefined ? phoneStatus : obj["電話対応"], obj);
  sheet.getRange(row, notifyCol).setValue(flag);
  sheet.getRange(row, messageCol).setValue(flag === PHONE_MOBILE_NOTIFY_TARGET ? buildPhoneMobileNotifyMessage_(obj) : "");
}

function getPhoneMobileNotifyFlag_(phoneStatus, rowObj) {
  if (!rowObj || !isPhoneNewMarkTargetRowObject_(rowObj)) return "";
  const status = resolvePhoneStatusForRow_(phoneStatus, rowObj);

  // p61bh:
  // AppSheet/メールの新着通知も、画面の新着●と同じ考え方に寄せる。
  // 対応メモが入った電話は、未完了でも「誰かが見た/対応に入った」とみなし、
  // 新着通知の対象から外す。完了までは通常の通知列「要確認」で追う。
  if (status === "完了" || ["中止", "不要", "対象外"].includes(status)) return PHONE_MOBILE_NOTIFY_SKIP;
  if (phoneHistoryCellHasValue_(rowObj["対応メモ"])) return PHONE_MOBILE_NOTIFY_SKIP;
  return PHONE_MOBILE_NOTIFY_TARGET;
}

function buildPhoneMobileNotifyMessage_(rowObj) {
  const lines = ["新しい電話履歴があります"];
  const dateText = formatPhoneNotifyValue_(rowObj["日付"], "yyyy/MM/dd");
  const timeText = formatPhoneNotifyValue_(rowObj["時間"], "HH:mm");
  const party = String(rowObj["相手"] || "").trim();
  const phone = String(rowObj["折り返し電話番号"] || "").trim();
  const content = String(rowObj["内容"] || "").trim();
  const assignee = String(rowObj["担当"] || "").trim();

  if (dateText || timeText) lines.push("日時：" + joinText(dateText, timeText));
  if (party) lines.push("相手：" + party);
  if (phone) lines.push("番号：" + phone);
  if (content) lines.push("内容：" + content);
  if (assignee) lines.push("担当：" + assignee);
  return lines.join("\n");
}

function formatPhoneNotifyValue_(value, pattern) {
  if (value === null || value === undefined || value === "") return "";
  try {
    if (value instanceof Date && !isNaN(value.getTime())) {
      const tz = SpreadsheetApp.getActive().getSpreadsheetTimeZone() || Session.getScriptTimeZone() || "Asia/Tokyo";
      return Utilities.formatDate(value, tz, pattern || "yyyy/MM/dd HH:mm");
    }
  } catch (e) {}
  return String(value || "").trim();
}

function buildPhoneScheduleContent_(r) {
  const base = joinText(r["相手"], joinText(r["折り返し電話番号"], r["内容"]));
  const mark = getPhoneNewMarkText_(r["電話対応"], r);
  return mark ? "【新着】" + base : base;
}

function normalizePhoneHistoryCompletionColumns_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return;
  ensurePhoneHistoryNewMarkColumn_({silent: true});

  const headers = getHeaders_(sheet);
  const noticeCol = headers.indexOf("通知") + 1;
  const phoneNewCol = headers.indexOf(PHONE_NEW_MARK_HEADER) + 1;
  const dateCol = headers.indexOf("日付") + 1;
  if (sheet.getLastRow() < 2) return;

  const rowCount = sheet.getLastRow() - 1;
  const values = sheet.getRange(2, 1, rowCount, headers.length).getValues();
  const noticeValues = [];
  const phoneNewValues = [];

  values.forEach(rowValues => {
    const obj = objectFromRow(headers, rowValues);
    const status = resolvePhoneStatusForRow_(obj["電話対応"], obj);
    const dateValue = dateCol > 0 ? rowValues[dateCol - 1] : "";
    noticeValues.push([getPhoneNoticeText_(dateValue, status, obj)]);
    phoneNewValues.push([getPhoneNewMarkText_(status, obj)]);
  });

  if (noticeCol > 0) {
    sheet.getRange(2, noticeCol, rowCount, 1).setValues(noticeValues);
  }

  if (phoneNewCol > 0) {
    sheet.getRange(2, phoneNewCol, rowCount, 1).setValues(phoneNewValues);
  }

  try { repairPhoneHistoryMobileNotifyColumns_(sheet); } catch (e) {
    console.log("電話履歴のスマホ通知用列修復をスキップ: " + e.message);
  }
}

function getPhoneNoticeText_(dateValue, phoneStatus, rowObj) {
  const status = resolvePhoneStatusForRow_(phoneStatus, rowObj);

  // p61am:
  // 電話履歴は「日付の期限管理」ではなく「対応状況管理」。
  // 翌日になっただけで期限切れにすると、古い未対応電話が全部赤くなりすぎる。
  // 古い順ソート＋新着印で目立たせ、通知は対応状況だけで判定する。
  const hasPhoneContent = rowObj ? isMeaningfulPhoneHistoryRowObject_(rowObj) : true;
  if (!hasPhoneContent) return "";

  if (status === "完了") return "完了";
  if (status === "中止" || status === "不要" || status === "対象外") return "";

  // 空欄/未対応/対応中/折返し/その他未完了は、期限切れではなく要確認で統一。
  return "要確認";
}

function isDateOnlyLike_(value) {
  if (!(value instanceof Date) || isNaN(value.getTime())) return false;
  return value.getHours() === 0
    && value.getMinutes() === 0
    && value.getSeconds() === 0
    && value.getMilliseconds() === 0;
}

function formatPhoneCompletedAtColumn_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return;

  const headers = getHeaders_(sheet);
  const completedCol = headers.indexOf("対応完了日時") + 1;
  if (completedCol <= 0) return;

  const rowCount = Math.max(getApplyRowCount_(sheet), 300);
  sheet.getRange(2, completedCol, rowCount, 1)
    .setNumberFormat("yyyy/mm/dd hh:mm")
    .clearDataValidations();

  try {
    sheet.setColumnWidth(completedCol, 145);
  } catch (e) {}
}


function removePhoneHistoryFilterBeforeSort_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return "";
  try {
    const filter = sheet.getFilter();
    if (!filter) return "";
    const rangeA1 = filter.getRange().getA1Notation();
    filter.remove();
    SpreadsheetApp.flush();
    return rangeA1;
  } catch (e) {
    console.log("電話履歴ソート前のフィルタ解除をスキップ: " + e.message);
    return "";
  }
}

function restorePhoneHistoryFilterAfterSort_(sheet, rangeA1) {
  if (!sheet || sheet.getName() !== "電話履歴" || !rangeA1) return;
  try {
    if (sheet.getFilter()) return;
    sheet.getRange(rangeA1).createFilter();
  } catch (e) {
    console.log("電話履歴ソート後のフィルタ再作成をスキップ: " + e.message);
  }
}

function sortPhoneHistoryRowsForDisplay_(values, headers) {
  const dataRows = [];
  const draftRows = [];
  const emptyRows = [];

  (values || []).forEach(function(row) {
    if (isMeaningfulPhoneHistoryRow_(headers, row)) {
      dataRows.push(row);
    } else if (isBusinessDataRow_(headers, row, "電話履歴")) {
      draftRows.push(row);
    } else {
      emptyRows.push(row);
    }
  });

  dataRows.sort(function(a, b) {
    return comparePhoneHistoryDisplayRows_(a, b, headers);
  });

  draftRows.sort(function(a, b) {
    return comparePhoneDraftDateTime_(a, b, headers);
  });

  return dataRows.concat(draftRows, emptyRows);
}

function comparePhoneHistoryDisplayRows_(a, b, headers) {
  const ao = getPhoneSortOrder_(a, headers);
  const bo = getPhoneSortOrder_(b, headers);
  if (ao !== bo) return ao - bo;

  // p61bp:
  // グループ内は「中身の濃さ」より日時を優先する。
  // 新着/完了前/完了後すべて古い順にし、見た目の違和感を減らす。
  const dateCompare = comparePhoneDateTimeByOrder_(a, b, headers, ao);
  if (dateCompare !== 0) return dateCompare;

  const ac = getPhoneDataCompletenessRank_(a, headers);
  const bc = getPhoneDataCompletenessRank_(b, headers);
  if (ac !== bc) return ac - bc;

  const ai = String(a[headers.indexOf("相手")] || "");
  const bi = String(b[headers.indexOf("相手")] || "");
  return ai.localeCompare(bi, "ja");
}

function sortPhoneHistorySheet() {
  sortPhoneHistorySheet_();
  toast_("電話履歴を新着→完了前→完了後の順に整理しました。各グループ内は古い順です。");
}

function sortPhoneHistorySheet_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("電話履歴");
  if (!sheet || sheet.getLastRow() < 3) return;

  normalizePhoneHistoryCompletionColumns_(sheet);

  const filterRangeA1 = removePhoneHistoryFilterBeforeSort_(sheet);
  try {
    const headers = getHeaders_(sheet);
    const lastRow = sheet.getLastRow();
    const lastCol = headers.length;
    const rowCount = getPhoneHistorySortRowCount_(sheet, lastRow);
    if (rowCount <= 1 || lastCol <= 0) return;

    const range = sheet.getRange(2, 1, rowCount, lastCol);
    const values = range.getValues();
    const sorted = sortPhoneHistoryRowsForDisplay_(values, headers);

    range.setValues(sorted);
    setCheckboxesForDataRows(sheet);
    applyPersonalCheckColumnLayout_(sheet);
    formatPhoneCompletedAtColumn_(sheet);
    SpreadsheetApp.flush();
  } finally {
    restorePhoneHistoryFilterAfterSort_(sheet, filterRangeA1);
  }
}

function shouldAutoSortPhoneHistoryAfterEdit_(editedHeaders) {
  if (!editedHeaders || !editedHeaders.length) return false;

  // p61bm:
  // 相手・折り返し電話番号・内容・担当を入力した時点で、電話履歴は実データとして成立する。
  // ここを自動ソート対象に含めないと、新着行が完了済み行の下に残るため、電話履歴だけ軽量整理する。
  // 備考や通知系は入力中に行が動きすぎないよう、通常は対象外にする。
  const autoSortHeaders = [
    "日付",
    "時間",
    "相手",
    "折り返し電話番号",
    "内容",
    "担当",
    "対応メモ",
    PHONE_DONE_CHECK_HEADER,
    "電話対応"
  ];
  return editedHeaders.some(function(header) {
    return autoSortHeaders.indexOf(String(header || "")) >= 0;
  });
}

function autoSortPhoneHistoryAfterEdit_(sheet, editedHeaders) {
  if (!sheet || sheet.getName() !== "電話履歴") return false;
  if (!shouldAutoSortPhoneHistoryAfterEdit_(editedHeaders || [])) return false;

  // p61bj:
  // 自動ソートで全体修復・全行通知再計算まで行うと重くなるため、
  // 値の並び替えと完了チェック表示の最低限復旧だけに限定する。
  // 対象も使用行＋少しの予備行に絞る。
  try {
    sortPhoneHistorySheetAutoLight_(sheet);
    return true;
  } catch (err) {
    console.log("電話履歴の自動軽量ソートをスキップ: " + err.message);
    return false;
  }
}

function sortPhoneHistorySheetAutoLight_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return false;

  const headers = getHeaders_(sheet);
  if (!headers.length || sheet.getLastRow() < 3) return false;

  const lastCol = headers.length;
  const rowCount = getPhoneHistoryAutoSortRowCount_(sheet);
  if (rowCount <= 1) return false;

  const filterRangeA1 = removePhoneHistoryFilterBeforeSort_(sheet);
  try {
    const range = sheet.getRange(2, 1, rowCount, lastCol);
    const values = range.getValues();
    range.setValues(sortPhoneHistoryRowsForDisplay_(values, headers));

    try {
      repairPhoneHistoryDoneCheckDisplayForRange_(sheet, 2, rowCount);
    } catch (e) {
      console.log("電話履歴の自動ソート後チェックボックス復旧をスキップ: " + e.message);
    }

    try { formatPhoneCompletedAtColumnLight_(sheet); } catch (e) {}
    SpreadsheetApp.flush();
    return true;
  } finally {
    restorePhoneHistoryFilterAfterSort_(sheet, filterRangeA1);
  }
}

function getPhoneHistoryAutoSortRowCount_(sheet) {
  if (!sheet) return 0;
  const availableRows = Math.max(sheet.getMaxRows() - 1, 1);
  const usedRows = Math.max(sheet.getLastRow() - 1, 1);
  // 使用行だけだと、直下の下書きや空行が混ざる時に境界が見にくいため、
  // 予備行を少しだけ含める。300行固定の全修復にはしない。
  const withBuffer = usedRows + 10;
  return Math.min(availableRows, Math.max(usedRows, withBuffer));
}

function formatPhoneCompletedAtColumnLight_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return;
  const headers = getHeaders_(sheet);
  const completedCol = headers.indexOf("対応完了日時") + 1;
  if (completedCol <= 0) return;
  const rowCount = Math.min(Math.max(sheet.getLastRow() - 1, 1) + 10, Math.max(sheet.getMaxRows() - 1, 1));
  sheet.getRange(2, completedCol, rowCount, 1).setNumberFormat("yyyy/mm/dd hh:mm").clearDataValidations();
}

function repairPhoneHistoryDoneCheckDisplayForRange_(sheet, startRow, rowCount) {
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  const headers = getHeaders_(sheet);
  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  if (doneCol <= 0 || rowCount <= 0) return 0;

  const maxRows = sheet.getMaxRows();
  const safeStart = Math.max(Number(startRow || 2), 2);
  const safeCount = Math.min(Number(rowCount || 1), Math.max(maxRows - safeStart + 1, 0));
  if (safeCount <= 0) return 0;

  const values = sheet.getRange(safeStart, 1, safeCount, headers.length).getValues();
  let fixed = 0;
  for (let i = 0; i < safeCount; i++) {
    const row = safeStart + i;
    const obj = objectFromRow(headers, values[i]);
    const meaningful = isMeaningfulPhoneHistoryRowObject_(obj);
    const status = normalizePhoneStatus_(obj["電話対応"]);
    const cell = sheet.getRange(row, doneCol);

    if (!meaningful) {
      const raw = cell.getValue();
      if (raw !== "") {
        cell.clearContent().clearDataValidations();
        fixed++;
      }
      continue;
    }

    const doneState = parsePhoneHistoryDoneCheckValue_(obj[PHONE_DONE_CHECK_HEADER]);
    const shouldBeDone = doneState.hasValue ? doneState.checked : status === "完了";
    cell.insertCheckboxes();
    cell.setValue(shouldBeDone);
    setPhoneHistoryInternalDoneState_(sheet, row, shouldBeDone, headers);
    fixed++;
  }
  return fixed;
}

function comparePhoneDraftDateTime_(a, b, headers) {
  // p61ak:
  // 日付だけ・時間だけなどの下書き行は、実データの直下にまとめたうえで
  // 日付・時間が分かるものを古い順にする。
  // 日付も時間もない下書きは最後へ置く。
  const at = getPhoneDraftDateTimeValue_(a, headers);
  const bt = getPhoneDraftDateTimeValue_(b, headers);
  const ah = at !== null;
  const bh = bt !== null;

  if (ah && !bh) return -1;
  if (!ah && bh) return 1;
  if (!ah && !bh) return 0;
  if (at === bt) return 0;
  return at - bt;
}

function getPhoneDraftDateTimeValue_(row, headers) {
  const dateCol = headers.indexOf("日付");
  const timeCol = headers.indexOf("時間");

  const d = dateCol >= 0 ? toDateOnly_(row[dateCol]) : null;
  const hm = timeCol >= 0 ? extractHourMinuteForSheet_(row[timeCol]) : null;

  if (d) {
    let base = d.getTime();
    if (hm) {
      base += hm.hour * 60 * 60 * 1000;
      base += hm.minute * 60 * 1000;
    }
    return base;
  }

  if (hm) {
    return hm.hour * 60 * 60 * 1000 + hm.minute * 60 * 1000;
  }

  return null;
}

function comparePhoneDateTimeByOrder_(a, b, headers, order) {
  // p61bp:
  // 未完了も完了済みも、同じ状態グループ内では古い電話ほど上に出す。
  // 完了済みだけ新しい順にすると未完了との境目が分かりにくいため、古い順へ統一する。
  // 日付がない実データは、同じ状態グループ内では日付ありの下へ置く。
  const at = getPhoneDateTimeValue_(a, headers);
  const bt = getPhoneDateTimeValue_(b, headers);
  const ah = at > 0;
  const bh = bt > 0;

  if (ah && !bh) return -1;
  if (!ah && bh) return 1;
  if (!ah && !bh) return 0;
  if (at === bt) return 0;

  return at - bt; // 全グループ古い順
}

function getPhoneDataCompletenessRank_(row, headers) {
  // 1: 通常データ（内容/担当/対応メモなど、処理に必要な中身あり）
  // 2: 情報薄い電話データ（相手/番号だけでも電話として意味がある）
  // 9: その他。通常ここには来ないが、安全側で最後にする。
  if (phoneHistoryRowHasAnyValue_(row, headers, ["内容", "担当", "対応メモ"])) return 1;
  if (phoneHistoryRowHasAnyValue_(row, headers, ["相手", "折り返し電話番号"])) return 2;
  return 9;
}

function phoneHistoryRowHasAnyValue_(row, headers, targetHeaders) {
  return targetHeaders.some(header => {
    const col = headers.indexOf(header);
    if (col < 0) return false;
    return phoneHistoryCellHasValue_(row[col]);
  });
}

function phoneHistoryCellHasValue_(value) {
  if (value === true) return true;
  if (value === false || value === null || value === undefined) return false;
  if (value instanceof Date) return !isNaN(value.getTime());
  return String(value).trim() !== "";
}

function getPhoneHistorySortRowCount_(sheet, lastRow) {
  if (!sheet) return 0;

  // p61ah:
  // getLastRow() だけを並べ替えると、日付だけの下書き行が実データ直下に残る。
  // ただし全1000行以上を毎回触ると重くなるため、通常の入力規則範囲程度までを対象にし、
  // その範囲内の下部へ下書き行を送る。
  const availableRows = Math.max(sheet.getMaxRows() - 1, 1);
  const usedRows = Math.max((lastRow || sheet.getLastRow()) - 1, 1);
  const minimumSortRows = Math.min(availableRows, MIN_DATA_ROWS_FOR_VALIDATION);
  return Math.min(availableRows, Math.max(usedRows, minimumSortRows));
}

function getPhoneSortOrder_(row, headers) {
  const statusCol = headers.indexOf("電話対応");
  const memoCol = headers.indexOf("対応メモ");
  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER);
  const newCol = headers.indexOf(PHONE_NEW_MARK_HEADER);

  const rowObj = objectFromRow(headers, row);
  const status = resolvePhoneStatusForRow_(statusCol >= 0 ? row[statusCol] : "", rowObj);
  const hasMemo = memoCol >= 0 ? phoneHistoryCellHasValue_(row[memoCol]) : false;
  const doneState = doneCol >= 0 ? parsePhoneHistoryDoneCheckValue_(row[doneCol]) : {hasValue: false, checked: false};
  const doneChecked = doneState.hasValue && doneState.checked;
  const newMark = newCol >= 0 ? String(row[newCol] || "").trim() : "";

  // p61br:
  // 完了チェック列がある場合は、その表示値を正とする。
  // 隠し列「電話対応=完了」が残っていても、完了チェックがOFFなら完了後へ送らない。
  if (doneChecked || (!doneState.hasValue && status === "完了")) return 4;
  if (["中止", "不要", "対象外"].includes(status)) return 5;
  if (newMark === PHONE_NEW_MARK_TEXT) return 1;

  // 新着印が未再計算でも、未完了かつ対応メモなしなら新着扱いにする。
  if ((status === "" || status === "未対応") && !hasMemo) return 1;

  // 対応メモあり、または旧状態の対応中/折返しは完了前グループ。
  if ((status === "" || status === "未対応") && hasMemo) return 2;
  if (status === "対応中" || status === "折返し") return 2;
  return 3;
}

function getPhoneDateTimeValue_(row, headers) {
  const dateCol = headers.indexOf("日付");
  const timeCol = headers.indexOf("時間");

  const d = dateCol >= 0 ? toDateOnly_(row[dateCol]) : null;
  if (!d) return 0;

  let base = d.getTime();
  const t = timeCol >= 0 ? row[timeCol] : null;

  const hm = extractHourMinuteForSheet_(t);
  if (hm) {
    base += hm.hour * 60 * 60 * 1000;
    base += hm.minute * 60 * 1000;
  }

  return base;
}


function setupNewBetaClean() {
  // v9.7.9:
  // Apps Scriptエディタの実行ボタンから実行した場合、
  // SpreadsheetApp.getUi() が使えず「Cannot call SpreadsheetApp.getUi() from this context」で止まるため、
  // 新セットアップ本体から確認ダイアログは外す。
  // 実行前確認は、メニュー名・手順シート・バックアップ運用で行う。
  const lock = LockService.getDocumentLock();
  if (!lock.tryLock(30000)) {
    toast_("他の処理中です。時間をおいて再実行してください。");
    return;
  }

  try {
    clearSettingsCache_();
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    ensureSettingsSheet_();
    const headersMap = getSheetHeaders_();

    Object.keys(headersMap).forEach(name => {
      let sheet = ss.getSheetByName(name);
      if (!sheet) sheet = ss.insertSheet(name);
      resetSheetForSetup_(sheet, headersMap[name].length);
      setupSheet_(sheet, headersMap[name]);
    });

    createSqlSheets();
    createProcedureSheet();
    createCompanyManagementExplanationSheet();
    createLedgerOutputSettings();
    reorderSheets_();
    formatInputSheetsForLongText();
    markSummaryDirty_();
    toast_("新規ベータを作成しました。次に『ベータ確認準備（軽量）』を実行してください。");
  } finally {
    lock.releaseLock();
  }
}

