function getPhoneStatusDropdownList_() {
  // p61ax:
  // Google Sheetsの矢印付きプルダウンは、空欄セルでEnterを押すと
  // 先頭候補が自動入力されることがある。
  // 電話履歴では「空欄 = 未対応扱い」に統一し、セルに未対応を残さないため、
  // 候補は実際に入力してよい状態だけにする。
  return ["対応中", "折返し", "完了"];
}

function getPhoneStatusDropdownSourceRange_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let helper = ss.getSheetByName(PHONE_STATUS_DROPDOWN_HELPER_SHEET_NAME);
  if (!helper) {
    helper = ss.insertSheet(PHONE_STATUS_DROPDOWN_HELPER_SHEET_NAME);
  }

  // p61au:
  // A2は本当の空欄ではなくゼロ幅スペースにする。
  // 本当の空欄だとGoogle SheetsがEnter時にスキップし、対応中を入れることがあるため。
  // onEdit/修復時にはゼロ幅スペースを空欄へ戻す。
  const values = [
    [PHONE_STATUS_BLANK_LABEL],
    ["対応中"],
    ["折返し"],
    ["完了"]
  ];

  try {
    helper.getRange(1, 1).setValue("電話対応候補");
    helper.getRange(2, 1, Math.max(values.length, 1), 1).clearContent();
    helper.getRange(2, 1, values.length, 1).setValues(values);
    helper.getRange(1, 1, values.length + 1, 1).setNumberFormat("@");
    helper.setColumnWidth(1, 120);
    if (!helper.isSheetHidden()) helper.hideSheet();
  } catch (e) {
    console.log("電話対応候補の補助範囲作成をスキップ: " + e.message);
  }

  return helper.getRange(2, 1, values.length, 1);
}

function getPhoneStatusValidationRule_() {
  // p61ax:
  // 電話履歴の電話対応列は、Enter操作で先頭候補が勝手に入る問題を避けるため、
  // 入力規則そのものを使わない。
  // この関数は互換用に残すが、呼び出し元では setDataValidation しない。
  return null;
}

function isLegacyPhoneStatusBlankValue_(value) {
  const status = String(value || "").trim();
  return status === CLEAR_LABEL || status === PHONE_STATUS_BLANK_LABEL || status === "未選択" || status === "未対応";
}

function repairPhoneHistoryStatusDropdownForRow_(sheet, row, headers) {
  if (!sheet || sheet.getName() !== "電話履歴" || row <= 1) return false;
  headers = headers && headers.length ? headers : getHeaders_(sheet);
  const statusCol = headers.indexOf("電話対応") + 1;
  if (statusCol <= 0) return false;

  const cell = sheet.getRange(row, statusCol);
  const current = String(cell.getValue() || "").trim();

  // p61ax:
  // 電話対応列はプルダウン/入力規則を完全に使わない。
  // 空欄=未対応扱いに統一し、旧版で残った空欄化用の値は消す。
  if (isLegacyPhoneStatusBlankValue_(current)) {
    cell.clearContent();
  }

  try {
    cell.clearDataValidations();
  } catch (e) {
    console.log("電話対応の行入力規則削除をスキップ: " + e.message);
  }

  return false;
}

function repairPhoneHistoryStatusDropdown_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return 0;

  const headers = getHeaders_(sheet);
  const statusCol = headers.indexOf("電話対応") + 1;
  if (statusCol <= 0) return 0;

  // p61ax:
  // 電話対応列は列全体から入力規則を削除する。
  // getApplyRowCount_() 範囲だけだと下の行に古いプルダウンが残るため、
  // シート最大行までまとめて掃除する。
  const count = Math.max(1, sheet.getMaxRows() - 1);
  const statusRange = sheet.getRange(2, statusCol, count, 1);

  try {
    const currentValues = statusRange.getValues();
    const cleanedStatusValues = currentValues.map(row => {
      const value = row[0];
      return [isLegacyPhoneStatusBlankValue_(value) ? "" : value];
    });
    statusRange.setValues(cleanedStatusValues);
  } catch (e) {
    console.log("電話対応の旧値掃除をスキップ: " + e.message);
  }

  try {
    statusRange.clearDataValidations();
  } catch (e) {
    console.log("電話対応の入力規則削除をスキップ: " + e.message);
  }

  try {
    sheet.setColumnWidth(statusCol, 90);
  } catch (e) {}

  return count;
}


function clearPhoneResponseColumnValidation_(sheet, col, options) {
  if (!sheet || col <= 0) return 0;
  options = options || {};

  const maxRows = Math.max(sheet.getMaxRows(), 2);
  const count = options.allRows
    ? Math.max(maxRows - 1, 1)
    : Math.max(1, Math.min(Number(options.rowCount || getApplyRowCount_(sheet) || 1), maxRows - 1));

  const range = sheet.getRange(2, col, count, 1);

  try {
    range.setNumberFormat("@").clearDataValidations();
  } catch (e) {
    console.log(sheet.getName() + " 電話対応列の入力規則削除をスキップ: " + e.message);
  }

  if (options.clearLegacy === true) {
    try {
      const values = range.getValues();
      let changed = 0;
      const next = values.map(function(row) {
        const value = row[0];
        if (isLegacyPhoneStatusBlankValue_(value)) {
          changed++;
          return [""];
        }
        return [value];
      });
      if (changed > 0) range.setValues(next);
    } catch (e) {
      console.log(sheet.getName() + " 電話対応列の旧値掃除をスキップ: " + e.message);
    }
  }

  try { sheet.setColumnWidth(col, 90); } catch (e) {}
  return count;
}

function repairAllPhoneResponseColumnValidations() {
  const lock = acquireCompanyPackLock_("電話対応列の入力規則を全シートから削除");
  if (!lock) return;
  try {
    const result = repairAllPhoneResponseColumnValidations_();
    toast_("電話対応列の入力規則を削除しました（対象:" + result.columns + "列 / 掃除:" + result.rows + "行）。電話対応は空欄=未対応扱い、対応中/折返し/完了は手入力です。");
  } catch (err) {
    toast_("電話対応列の入力規則削除でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function repairAllPhoneResponseColumnValidations_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const result = {sheets: 0, columns: 0, rows: 0};
  const targetNames = Array.from(new Set(getInputSheetNames_().concat(["一覧スケジュール", "要確認一覧", "過去一覧"])));

  targetNames.forEach(function(name) {
    const sheet = ss.getSheetByName(name);
    if (!sheet || sheet.getLastColumn() < 1) return;
    const headers = getHeaders_(sheet);
    if (!headers.length) return;

    let sheetColumns = 0;
    headers.forEach(function(header, index) {
      if (String(header || "").trim() !== "電話対応") return;
      const cleared = clearPhoneResponseColumnValidation_(sheet, index + 1, {allRows: true, clearLegacy: true});
      result.rows += cleared;
      result.columns++;
      sheetColumns++;
    });

    if (sheetColumns > 0) result.sheets++;
  });

  return result;
}

function diagnosePhoneStatusDropdown() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const phoneSheet = ss.getSheetByName("電話履歴");
  const out = getOrCreatePhoneStatusDropdownDiagnosticSheet_(ss);
  out.clear();
  out.clearFormats();

  const nowText = Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "yyyy/MM/dd HH:mm:ss");
  const rows = [];
  rows.push(["項目", "値", "補足"]);
  rows.push(["診断作成日時", nowText, "実シートに現在貼られている入力規則を確認"]);
  rows.push(["SYSTEM_VERSION", SYSTEM_VERSION, "p61ay以降は全シートの電話対応列で入力規則そのものを使わない方針"]);
  rows.push(["対象シート", "電話履歴", phoneSheet ? "OK" : "電話履歴シートが見つかりません"]);
  rows.push(["想定候補", getPhoneStatusDropdownList_().map(formatDropdownDiagnosticValue_).join(" / "), "コード上の候補"]);

  let helperInfo = "未確認";
  try {
    const source = getPhoneStatusDropdownSourceRange_();
    const values = source.getDisplayValues().map(function(r) { return formatDropdownDiagnosticValue_(r[0]); }).join(" / ");
    helperInfo = source.getSheet().getName() + "!" + source.getA1Notation() + " = " + values;
  } catch (e) {
    helperInfo = "取得失敗: " + e.message;
  }
  rows.push(["候補元補助範囲", helperInfo, "p61awでは電話対応の本体入力規則は直接リスト＋プルダウン非表示を使用。旧範囲候補が残っていないか確認用"]);
  rows.push(["", "", ""]);

  const headerRowIndex = rows.length + 1;
  rows.push(["行", "電話対応値", "実データ判定", "入力規則タイプ", "候補元", "候補値", "先頭候補", "未対応を含む", "対応中が先頭", "メモ"]);

  if (!phoneSheet) {
    out.getRange(1, 1, rows.length, rows[0].length).setValues(rows);
    formatPhoneStatusDropdownDiagnosticSheet_(out, rows.length, rows[0].length, headerRowIndex);
    SpreadsheetApp.getUi().alert("電話履歴シートが見つかりません。");
    return;
  }

  const headers = getHeaders_(phoneSheet);
  const statusCol = headers.indexOf("電話対応") + 1;
  if (statusCol <= 0) {
    rows.push(["-", "-", "-", "-", "-", "-", "-", "-", "-", "電話対応列が見つかりません"]);
    out.getRange(1, 1, rows.length, Math.max(10, rows[0].length)).setValues(padRows_(rows, 10));
    formatPhoneStatusDropdownDiagnosticSheet_(out, rows.length, 10, headerRowIndex);
    SpreadsheetApp.getUi().alert("電話履歴に電話対応列が見つかりません。");
    return;
  }

  const lastRow = Math.max(phoneSheet.getLastRow(), 2);
  const checkRows = Math.max(20, Math.min(Math.max(lastRow - 1, 1), 120));
  const values = phoneSheet.getRange(2, 1, checkRows, headers.length).getValues();
  const validations = phoneSheet.getRange(2, statusCol, checkRows, 1).getDataValidations();

  let oldRuleCount = 0;
  let firstMitaiouCount = 0;
  let firstTaiouchuCount = 0;
  let noRuleMeaningfulCount = 0;

  for (let i = 0; i < checkRows; i++) {
    const sheetRow = i + 2;
    const rowValues = values[i];
    const obj = objectFromRow(headers, rowValues);
    const isMeaningful = isMeaningfulPhoneHistoryRowObject_(obj);
    const rule = validations[i] && validations[i][0];
    const info = describeDataValidationRuleForDiagnostic_(rule);
    const currentValue = formatDropdownDiagnosticValue_(rowValues[statusCol - 1]);

    const containsMitaiou = info.candidates.indexOf("未対応") >= 0;
    const firstIsMitaiou = info.firstCandidate === "未対応";
    const firstIsTaiouchu = info.firstCandidate === "対応中";
    if (containsMitaiou || firstIsMitaiou) oldRuleCount++;
    if (firstIsMitaiou) firstMitaiouCount++;
    if (firstIsTaiouchu) firstTaiouchuCount++;
    if (isMeaningful && !rule) noRuleMeaningfulCount++;

    let memo = "";
    if (firstIsMitaiou) memo = "古い候補の可能性: Enterで未対応になりやすい";
    else if (firstIsTaiouchu) memo = "先頭が対応中: Enterで対応中になりやすい";
    else if (containsMitaiou) memo = "候補内に未対応あり: p61at以降の想定外";
    else if (isMeaningful && !rule) memo = "実データ行だが入力規則なし";
    else if (!isMeaningful && rule) memo = "下書き/空行に入力規則あり: Enter事故の原因候補";

    rows.push([
      sheetRow,
      currentValue,
      isMeaningful ? "実データ" : "空行/下書き",
      info.type,
      info.source,
      info.candidates.map(formatDropdownDiagnosticValue_).join(" / "),
      formatDropdownDiagnosticValue_(info.firstCandidate),
      containsMitaiou ? "あり" : "なし",
      firstIsTaiouchu ? "はい" : "いいえ",
      memo
    ]);
  }

  rows.splice(6, 0, ["未対応候補の残り", oldRuleCount, "0が理想"]);
  rows.splice(7, 0, ["先頭が未対応の行", firstMitaiouCount, "0が理想"]);
  rows.splice(8, 0, ["先頭が対応中の行", firstTaiouchuCount, "0が理想。ここが多いとEnterで対応中になる"]);
  rows.splice(9, 0, ["実データなのに入力規則なし", noRuleMeaningfulCount, "候補を出したい行では0が理想"]);

  const colCount = 10;
  out.getRange(1, 1, rows.length, colCount).setValues(padRows_(rows, colCount));
  formatPhoneStatusDropdownDiagnosticSheet_(out, rows.length, colCount, headerRowIndex + 4);
  SpreadsheetApp.getUi().alert("電話対応プルダウン診断を作成しました。\n「" + PHONE_STATUS_DROPDOWN_DIAG_SHEET_NAME + "」を確認してください。\n\n特に『先頭が未対応の行』『先頭が対応中の行』が0か確認してください。");
}

function getOrCreatePhoneStatusDropdownDiagnosticSheet_(ss) {
  let sheet = ss.getSheetByName(PHONE_STATUS_DROPDOWN_DIAG_SHEET_NAME);
  if (!sheet) sheet = ss.insertSheet(PHONE_STATUS_DROPDOWN_DIAG_SHEET_NAME);
  try { sheet.showSheet(); } catch (e) {}
  try { ss.setActiveSheet(sheet); } catch (e) {}
  return sheet;
}

function describeDataValidationRuleForDiagnostic_(rule) {
  if (!rule) {
    return {type: "なし", source: "", candidates: [], firstCandidate: ""};
  }
  let type = "不明";
  let source = "";
  let candidates = [];
  try {
    type = String(rule.getCriteriaType());
    const args = rule.getCriteriaValues();
    if (rule.getCriteriaType() === SpreadsheetApp.DataValidationCriteria.VALUE_IN_LIST) {
      candidates = (args && args[0]) ? args[0].map(function(v) { return String(v || ""); }) : [];
      source = "直接リスト";
    } else if (rule.getCriteriaType() === SpreadsheetApp.DataValidationCriteria.VALUE_IN_RANGE) {
      const range = args && args[0];
      if (range) {
        source = range.getSheet().getName() + "!" + range.getA1Notation();
        candidates = range.getValues().map(function(r) { return String(r[0] || ""); });
      }
    } else if (rule.getCriteriaType() === SpreadsheetApp.DataValidationCriteria.CHECKBOX) {
      source = "チェックボックス";
      candidates = [];
    } else {
      source = "その他";
      candidates = [];
    }
  } catch (e) {
    type = "取得失敗";
    source = e.message;
    candidates = [];
  }
  return {
    type: type,
    source: source,
    candidates: candidates,
    firstCandidate: candidates.length ? candidates[0] : ""
  };
}

function formatDropdownDiagnosticValue_(value) {
  const s = String(value === null || value === undefined ? "" : value);
  if (s === "") return "[空欄]";
  if (s === PHONE_STATUS_BLANK_LABEL) return "[ゼロ幅空欄]";
  if (s.replace(/\u200B/g, "") === "") return "[ゼロ幅空欄]";
  return s;
}

function padRows_(rows, colCount) {
  return rows.map(function(row) {
    const copy = row.slice(0, colCount);
    while (copy.length < colCount) copy.push("");
    return copy;
  });
}

function formatPhoneStatusDropdownDiagnosticSheet_(sheet, rowCount, colCount, detailHeaderRow) {
  if (!sheet) return;
  try {
    sheet.setFrozenRows(1);
    sheet.getRange(1, 1, 1, colCount).setBackground("#d9ead3").setFontWeight("bold");
    if (detailHeaderRow && detailHeaderRow <= rowCount) {
      sheet.getRange(detailHeaderRow, 1, 1, colCount).setBackground("#cfe2f3").setFontWeight("bold");
    }
    sheet.getRange(1, 1, rowCount, colCount).setVerticalAlignment("middle").setWrap(true);
    sheet.setColumnWidth(1, 110);
    sheet.setColumnWidth(2, 180);
    sheet.setColumnWidth(3, 150);
    sheet.setColumnWidth(4, 190);
    sheet.setColumnWidth(5, 220);
    sheet.setColumnWidth(6, 360);
    sheet.setColumnWidth(7, 150);
    sheet.setColumnWidth(8, 130);
    sheet.setColumnWidth(9, 150);
    sheet.setColumnWidth(10, 300);
    createFilterSafely_(sheet, colCount);
  } catch (e) {
    console.log("電話対応プルダウン診断シート整形をスキップ: " + e.message);
  }
}


function createDropdownDesignDiagnosticSheet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const out = getOrCreateDropdownDesignDiagnosticSheet_(ss);
  out.clear();
  out.clearFormats();

  const nowText = Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "yyyy/MM/dd HH:mm:ss");
  const rows = [];
  rows.push(["分類", "シート", "列", "入力規則", "先頭候補", "候補値", "リスク", "推奨", "理由", "運用メモ"]);
  rows.push(["概要", "全体", "診断作成日時", "", nowText, "", "", "", "実シートに現在貼られている入力規則を確認します", "プルダウンで空欄のまま抜けたい時はEnterよりEsc/他セルクリックが安全"]);
  rows.push(["概要", "全体", "SYSTEM_VERSION", "", SYSTEM_VERSION, "", "", "", "p61bv: 電話対応/対応完了日時は廃止、通知系は非表示、既読グループは復旧", "電話履歴では通知系をhideColumns()で隠し、既読・個人確認だけ＋展開を残します"]);

  const targetNames = getDropdownDesignDiagnosticTargetSheetNames_(ss);
  targetNames.forEach(function(sheetName) {
    const sheet = ss.getSheetByName(sheetName);
    if (!sheet || sheet.getLastColumn() < 1) return;

    const headers = getHeaders_(sheet);
    if (!headers.length) return;
    const maxRows = sheet.getMaxRows();
    const checkRows = Math.max(1, Math.min(Math.max(sheet.getLastRow() - 1, 1), 80, Math.max(maxRows - 1, 1)));

    headers.forEach(function(header, index) {
      const headerText = String(header || "").trim();
      if (!headerText) return;

      const col = index + 1;
      const ruleInfo = getColumnDataValidationDiagnosticInfo_(sheet, col, checkRows);
      const shouldShow = ruleInfo.ruleCount > 0 || isLikelyDropdownDesignTargetColumn_(sheetName, headerText);
      if (!shouldShow) return;

      const assessment = assessDropdownDesignColumn_(sheetName, headerText, ruleInfo);
      rows.push([
        assessment.category,
        sheetName,
        dropdownDiagnosticColumnLabel_(col) + "列 " + headerText,
        ruleInfo.type + (ruleInfo.ruleCount > 0 ? " / " + ruleInfo.ruleCount + "行" : ""),
        formatDropdownDiagnosticValue_(ruleInfo.firstCandidate),
        ruleInfo.candidates.map(formatDropdownDiagnosticValue_).join(" / "),
        assessment.risk,
        assessment.recommendation,
        assessment.reason,
        assessment.operationNote
      ]);
    });
  });

  if (rows.length <= 3) {
    rows.push(["結果", "全体", "対象なし", "", "", "", "低", "確認のみ", "入力規則のある列が見つかりませんでした", ""]);
  }

  const colCount = 10;
  out.getRange(1, 1, rows.length, colCount).setValues(padRows_(rows, colCount));
  formatDropdownDesignDiagnosticSheet_(out, rows.length, colCount);
  SpreadsheetApp.getUi().alert("プルダウン設計チェックを作成しました。\n「" + DROPDOWN_DESIGN_DIAG_SHEET_NAME + "」を確認してください。\n\n電話対応以外は基本プルダウン維持、空欄に意味がある列だけ個別に見直す方針です。");
}

function getOrCreateDropdownDesignDiagnosticSheet_(ss) {
  let sheet = ss.getSheetByName(DROPDOWN_DESIGN_DIAG_SHEET_NAME);
  if (!sheet) sheet = ss.insertSheet(DROPDOWN_DESIGN_DIAG_SHEET_NAME);
  try { sheet.showSheet(); } catch (e) {}
  try { ss.setActiveSheet(sheet); } catch (e) {}
  return sheet;
}

function getDropdownDesignDiagnosticTargetSheetNames_(ss) {
  const names = getInputSheetNames_().concat([
    "一覧スケジュール", "要確認一覧", "過去一覧", "資格かんたん登録", "資格一括登録", "資格マスタ", "運転免許明細"
  ]);
  const existingNames = {};
  ss.getSheets().forEach(function(sheet) {
    existingNames[sheet.getName()] = true;
  });
  return Array.from(new Set(names.filter(function(name) { return existingNames[name]; })));
}

function getColumnDataValidationDiagnosticInfo_(sheet, col, checkRows) {
  const count = Math.max(1, Math.min(Number(checkRows || 1), Math.max(sheet.getMaxRows() - 1, 1)));
  let firstRule = null;
  let ruleCount = 0;
  try {
    const validations = sheet.getRange(2, col, count, 1).getDataValidations();
    validations.forEach(function(row) {
      const rule = row && row[0];
      if (rule) {
        ruleCount++;
        if (!firstRule) firstRule = rule;
      }
    });
  } catch (e) {
    return {type: "取得失敗", source: e.message, candidates: [], firstCandidate: "", ruleCount: 0};
  }

  const info = describeDataValidationRuleForDiagnostic_(firstRule);
  info.ruleCount = ruleCount;
  return info;
}

function isLikelyDropdownDesignTargetColumn_(sheetName, header) {
  if (header === "電話対応") return true;
  if (header === PHONE_DONE_CHECK_HEADER) return true;
  if (header === READ_HEADER) return true;
  if (getPersonalMembers_().indexOf(header) >= 0) return true;

  const common = [
    "担当", "入力者", "利用者", "投稿者", "記入者", "所有者", "修理依頼者", "対象者", "代理担当", "確認者",
    "社用車", "車両名", "修理業者", "重要度", "コピー有無", "返却済", "区分", "取得区分", "保有状況",
    "支払方法", "経理確認", "精算状態", "確認方法", "対象シート", "困り度", "税", "資料区分", "資料テーマ",
    "テーマ", "トピック", "季節区分", "イラスト状態", "状態", "対応状況", "車検状態", "通知",
    PHONE_NOTIFY_TO_HEADER, PHONE_NOTIFY_EMAIL_HEADER, PHONE_NOTIFY_METHOD_HEADER, PHONE_MOBILE_NOTIFY_HEADER, PHONE_EMAIL_NOTIFY_HEADER
  ];
  if (common.indexOf(header) >= 0) return true;
  if (sheetName === "資格管理" && ["資格名", "区分", "取得区分", "保有状況", "コピー有無", "状態"].indexOf(header) >= 0) return true;
  return false;
}

function assessDropdownDesignColumn_(sheetName, header, info) {
  const type = String(info.type || "");
  const candidates = info.candidates || [];
  const first = candidates.length ? String(candidates[0] || "") : "";
  const hasRule = (info.ruleCount || 0) > 0;

  if (header === "電話対応") {
    return {
      category: "空欄に意味あり",
      risk: hasRule ? "高" : "低",
      recommendation: hasRule ? "入力規則削除" : "維持",
      reason: "電話対応は空欄=未対応/未入力扱いのため、プルダウンEnter確定と相性が悪い列です",
      operationNote: "p61ay以降は入力規則なし。電話履歴は完了チェックで完了だけ操作します"
    };
  }

  if (type.indexOf("CHECKBOX") >= 0 || header === PHONE_DONE_CHECK_HEADER || header === READ_HEADER || getPersonalMembers_().indexOf(header) >= 0) {
    return {
      category: "チェックボックス",
      risk: "低",
      recommendation: "維持",
      reason: "候補選択ではなくON/OFF操作なので、プルダウン先頭候補問題とは別です",
      operationNote: "EnterよりSpace/クリックで切替が分かりやすいです"
    };
  }

  if (!hasRule) {
    return {
      category: "自由入力/規則なし",
      risk: "低",
      recommendation: "維持",
      reason: "現在この列には入力規則がありません",
      operationNote: "候補ミスが多い列だけ個別にプルダウン化を検討します"
    };
  }

  if (["担当", "入力者", "利用者", "投稿者", "記入者", "所有者", "修理依頼者", "対象者", "代理担当", "確認者", "社用車", "車両名", "修理業者", "資格名", "区分", "資料テーマ", "テーマ", "トピック"].indexOf(header) >= 0) {
    return {
      category: "入力補助",
      risk: first === CLEAR_LABEL ? "低〜中" : "低",
      recommendation: "維持",
      reason: "表記ゆれ防止のメリットが大きい列です",
      operationNote: "候補を選ぶ時はEnterでOK。空欄のまま抜けたい時はEscまたは他セルクリックが安全です"
    };
  }

  if (["状態", "対応状況", "車検状態"].indexOf(header) >= 0) {
    return {
      category: "状態管理",
      risk: first === CLEAR_LABEL ? "中" : "中〜高",
      recommendation: "基本維持・先頭候補確認",
      reason: "状態列は選択補助の価値が高い一方、Enterで先頭候補が入る可能性があります",
      operationNote: "空欄を残したい運用なら操作列/チェック化を検討。通常は状態を選ぶ列としてEnter確定を許容します"
    };
  }

  if (first === CLEAR_LABEL) {
    return {
      category: "プルダウン",
      risk: "低〜中",
      recommendation: "維持",
      reason: "先頭が空欄に戻すなので、Enterで値が消える方向の挙動になり得ます",
      operationNote: "空欄にしたくない時はEnter連打を避け、候補選択はクリック/矢印キーで確認します"
    };
  }

  return {
    category: "プルダウン",
    risk: "中",
    recommendation: "先頭候補確認",
    reason: "Enterで先頭候補が確定される可能性があります",
    operationNote: "先頭候補を入っても困らない値にするか、空欄に意味がある列は入力規則なしへ変更します"
  };
}

function dropdownDiagnosticColumnLabel_(col) {
  let n = Number(col || 0);
  let label = "";
  while (n > 0) {
    const rem = (n - 1) % 26;
    label = String.fromCharCode(65 + rem) + label;
    n = Math.floor((n - 1) / 26);
  }
  return label || "?";
}

function formatDropdownDesignDiagnosticSheet_(sheet, rowCount, colCount) {
  if (!sheet) return;
  try {
    sheet.setFrozenRows(1);
    sheet.getRange(1, 1, 1, colCount).setBackground("#d9ead3").setFontWeight("bold");
    sheet.getRange(1, 1, rowCount, colCount).setWrap(true).setVerticalAlignment("middle");
    sheet.setColumnWidth(1, 120);
    sheet.setColumnWidth(2, 160);
    sheet.setColumnWidth(3, 170);
    sheet.setColumnWidth(4, 160);
    sheet.setColumnWidth(5, 130);
    sheet.setColumnWidth(6, 320);
    sheet.setColumnWidth(7, 90);
    sheet.setColumnWidth(8, 160);
    sheet.setColumnWidth(9, 360);
    sheet.setColumnWidth(10, 360);
    createFilterSafely_(sheet, colCount);
  } catch (e) {
    console.log("プルダウン設計チェック整形をスキップ: " + e.message);
  }
}

