function sortInputSheetsByDateTimeLight_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sortedSheets = 0;
  let sortedRows = 0;

  // p61aa:
  // 一括ソートも、単純な日付昇順ではなく各シートの専用ルールを優先する。
  // これにより、休み管理・見積書・日報などで「完了済みが上に来る」事故を抑える。
  const targetNames = [
    "出先予定",
    "工事予定",
    "見積書",
    "安全書類管理",
    "安全教育資料集",
    "安全教育資料候補",
    "安全教育概要チェック",
    "安全教育使用履歴",
    HOLIDAY_MANAGEMENT_SHEET_NAME,
    "会議予定",
    "行事予定",
    "社用車予約",
    "日報",
    "日報レシート管理",
    "備品修理管理",
    "個人ToDo",
    "お知らせ",
    "フィードバック"
  ];

  targetNames.forEach(function(name) {
    const sheet = ss.getSheetByName(name);
    if (!sheet || sheet.getLastRow() < 3) return;
    if (name === "見積書") {
      const count = sortEstimateSheetByDateTime_();
      if (count > 0) {
        sortedSheets++;
        sortedRows += count;
      }
      return;
    }

    const config = getActiveSheetDateTimeSortConfig_(name);
    if (!config) return;
    const count = sortSheetRowsByDateTimeSmart_(sheet, config);
    if (count > 0) {
      sortedSheets++;
      sortedRows += count;
    }
  });

  try {
    sortPhoneHistorySheet_();
    sortedSheets++;
    sortedRows += Math.max(0, (ss.getSheetByName("電話履歴") || {getLastRow: () => 1}).getLastRow() - 1);
  } catch (e) {}

  try { sortVehicleInspectionSheetByDue_(); sortedSheets++; } catch (e) {}
  try { sortDriverLicenseManagementByDue_({silent: true, skipRepair: true}); sortedSheets++; } catch (e) {}

  return {sortedSheets: sortedSheets, sortedRows: sortedRows};
}



function sortActiveSheetByDateTimeSmart() {
  const lock = acquireCompanyPackLock_("今のシートだけ日時ソート");
  if (!lock) return;
  try {
    const result = sortActiveSheetByDateTimeSmart_();
    toast_(result.message);
    return result;
  } catch (err) {
    toast_("今のシートだけ日時ソートでエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function sortActiveSheetByDateTimeSmart_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getActiveSheet();
  if (!sheet) return {count: 0, message: "アクティブシートがありません。"};
  const name = sheet.getName();

  if (name === "電話履歴") {
    sortPhoneHistorySheet_();
    return {count: Math.max(0, sheet.getLastRow() - 1), message: "電話履歴を新着・対応中・完了・下書き順に整理しました。"};
  }

  if (name === HOLIDAY_MANAGEMENT_SHEET_NAME) {
    const count = sortHolidayManagementSheet_();
    return {count: count, message: "休み管理を状態＋休み開始日順に整理しました（" + count + "行）。"};
  }

  if (name === "見積書") {
    const count = sortEstimateSheetByDateTime_();
    return {count: count, message: "見積書を提出依頼・返答待ち・提出済み順に整理しました（" + count + "行）。"};
  }

  if (name === "車検管理") {
    sortVehicleInspectionSheetByDue_();
    return {count: Math.max(0, sheet.getLastRow() - 1), message: "車検管理を車検期限が近い順に整理しました。"};
  }

  if (name === "運転免許管理") {
    sortDriverLicenseManagementByDue_({silent: true, skipRepair: true});
    return {count: Math.max(0, sheet.getLastRow() - 1), message: "運転免許管理を有効期限が近い順に整理しました。"};
  }

  if (name === "資格管理") {
    const count = sortQualificationManagementByOwner_();
    return {count: count, message: "資格管理を所有者＋資格マスタ順に整理しました（" + count + "件）。"};
  }

  const config = getActiveSheetDateTimeSortConfig_(name);
  if (!config) {
    return {count: 0, message: "このシートは日時ソート対象外です: " + name};
  }

  const count = sortSheetRowsByDateTimeSmart_(sheet, config);
  if (count <= 0) {
    return {count: 0, message: name + " は整理対象のデータ行がありません。"};
  }
  return {count: count, message: name + " を今のシートだけ日時ソートしました（" + count + "行）。"};
}

function getActiveSheetDateTimeSortConfig_(sheetName) {
  const configs = getAllDateTimeSortConfigsForCheck_();
  return configs[sheetName] || null;
}



function sortSheetRowsByDateTimeSmart_(sheet, config) {
  if (!sheet || sheet.getLastRow() < 3) return 0;
  const headers = getHeaders_(sheet);
  if (!headers.length) return 0;

  const lastCol = headers.length;
  const rowCount = sheet.getLastRow() - 1;
  const values = sheet.getRange(2, 1, rowCount, lastCol).getValues();
  const dataRows = values.filter(row => isBusinessDataRow_(headers, row, sheet.getName()));
  const emptyRows = values.filter(row => !isBusinessDataRow_(headers, row, sheet.getName()));
  if (dataRows.length <= 1) return 0;

  dataRows.sort((a, b) => {
    const ag = getStatusSortGroupForDateTime_(headers, a, config);
    const bg = getStatusSortGroupForDateTime_(headers, b, config);
    if (ag !== bg) return ag - bg;

    const av = getRowDateTimeSortValue_(headers, a, config.dates || [], config.times || []);
    const bv = getRowDateTimeSortValue_(headers, b, config.dates || [], config.times || []);
    if (av !== bv) return config.dateOrder === "desc" ? bv - av : av - bv;

    return String(a.join(" ")).localeCompare(String(b.join(" ")), "ja");
  });

  sheet.getRange(2, 1, dataRows.length + emptyRows.length, lastCol).setValues(dataRows.concat(emptyRows));
  setCheckboxesForDataRows(sheet);
  try { hideSystemColumnsForSheet_(sheet); } catch (e) {}
  return dataRows.length;
}

function getStatusSortGroupForDateTime_(headers, row, config) {
  const statusHeader = config.statusHeader || "状態";
  const idx = headers.indexOf(statusHeader);
  if (idx < 0) return 0;
  const status = String(row[idx] || "").trim();
  const completed = config.completed || [];
  if (completed.indexOf(status) >= 0) return 1;
  return 0;
}

function sortEstimateSheetByDateTime_() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("見積書");
  if (!sheet || sheet.getLastRow() < 3) return 0;

  const headers = getHeaders_(sheet);
  if (!headers.length) return 0;

  const lastCol = headers.length;
  const rowCount = sheet.getLastRow() - 1;
  const values = sheet.getRange(2, 1, rowCount, lastCol).getValues();

  // p61cf:
  // 通知では「返答待ち=完了」とするが、シート内の整理では完了済みの一番下へ落とさない。
  // 見積書は、提出依頼 → 返答待ち → 提出済み → 空欄/下書き の順にする。
  const dataRows = values.filter(row => isBusinessDataRow_(headers, row, sheet.getName()));
  const emptyRows = values.filter(row => !isBusinessDataRow_(headers, row, sheet.getName()));
  if (dataRows.length <= 1) return 0;

  dataRows.sort(function(a, b) {
    const ag = getEstimateStatusSortGroup_(headers, a);
    const bg = getEstimateStatusSortGroup_(headers, b);
    if (ag !== bg) return ag - bg;

    const av = getRowDateTimeSortValue_(headers, a, ["提出年月日", "日付", "日時"], []);
    const bv = getRowDateTimeSortValue_(headers, b, ["提出年月日", "日付", "日時"], []);
    if (av !== bv) return av - bv; // 同じ状態内は古い提出年月日を上にして、放置を見つけやすくする。

    return String(a.join(" ")).localeCompare(String(b.join(" ")), "ja");
  });

  sheet.getRange(2, 1, dataRows.length + emptyRows.length, lastCol).setValues(dataRows.concat(emptyRows));
  setCheckboxesForDataRows(sheet);
  try { hideSystemColumnsForSheet_(sheet); } catch (e) {}
  return dataRows.length;
}

function getEstimateStatusSortGroup_(headers, row) {
  const idx = headers.indexOf("状態");
  const status = idx >= 0 ? normalizeEstimateStatus_(row[idx]) : "";

  if (status === "提出依頼") return 0;
  if (status === "返答待ち") return 1;
  if (status === "提出済み") return 2;

  // 件名や金額だけ入っている下書きは、提出依頼/返答待ち/提出済みの下へ残す。
  return 3;
}

function sortSheetRowsByDateTime_(sheet, dateHeaders, timeHeaders) {
  if (!sheet || sheet.getLastRow() < 3) return 0;
  const headers = getHeaders_(sheet);
  if (!headers.length) return 0;

  const lastCol = headers.length;
  const rowCount = sheet.getLastRow() - 1;
  const values = sheet.getRange(2, 1, rowCount, lastCol).getValues();
  const dataRows = values.filter(row => isBusinessDataRow_(headers, row, sheet.getName()));
  const emptyRows = values.filter(row => !isBusinessDataRow_(headers, row, sheet.getName()));
  if (dataRows.length <= 1) return 0;

  dataRows.sort((a, b) => {
    const av = getRowDateTimeSortValue_(headers, a, dateHeaders, timeHeaders);
    const bv = getRowDateTimeSortValue_(headers, b, dateHeaders, timeHeaders);
    if (av !== bv) return av - bv;
    return String(a.join(" ")).localeCompare(String(b.join(" ")), "ja");
  });

  sheet.getRange(2, 1, dataRows.length + emptyRows.length, lastCol).setValues(dataRows.concat(emptyRows));
  setCheckboxesForDataRows(sheet);
  return dataRows.length;
}

function getRowDateTimeSortValue_(headers, row, dateHeaders, timeHeaders) {
  let dateValue = null;
  (dateHeaders || []).some(header => {
    const idx = headers.indexOf(header);
    if (idx < 0) return false;
    const value = row[idx];
    if (value) {
      dateValue = value;
      return true;
    }
    return false;
  });

  let timeValue = null;
  (timeHeaders || []).some(header => {
    const idx = headers.indexOf(header);
    if (idx < 0) return false;
    const value = row[idx];
    if (value) {
      timeValue = value;
      return true;
    }
    return false;
  });

  return getCombinedDateTimeSortValue_(dateValue, timeValue);
}

function getCombinedDateTimeSortValue_(dateValue, timeValue) {
  const d = toDateOnly_(dateValue);
  if (!d) return Number.MAX_SAFE_INTEGER;
  const hm = extractHourMinuteForSheet_(timeValue);
  if (hm) d.setHours(hm.hour, hm.minute, 0, 0);
  return d.getTime();
}

function getDateTimeSortValue_(value) {
  if (!value) return Number.MAX_SAFE_INTEGER;
  if (value instanceof Date && !isNaN(value.getTime())) return value.getTime();
  const d = new Date(value);
  return isNaN(d.getTime()) ? Number.MAX_SAFE_INTEGER : d.getTime();
}

function createSortRuleCheckSheet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("ソート設定チェック");
  if (!sheet) sheet = ss.insertSheet("ソート設定チェック");
  sheet.clear();
  sheet.clearFormats();

  const headers = ["シート", "並び順", "日付基準", "時間基準", "状態の扱い", "方向", "備考"];
  const rows = [];

  rows.push(["電話履歴", "新着/未対応 → 対応中/折返し → その他未完了 → 完了 → 下書き", "日付", "時間", "空欄/未対応だけ新着●。対応中/折返しは新着なし", "新しい順", "日付だけ行は下書き扱い"]);
  rows.push([HOLIDAY_MANAGEMENT_SHEET_NAME, "申請中/予定/承認済 → 取得済/却下/取消", "休み開始日 → 休み終了日 → 申請日", "なし", "取得済/却下/取消は下", "近い順", "休み管理専用"]);
  rows.push(["車検管理", "期限が近い順", "車検期限/車検予定日", "なし", "更新済は通常下", "近い順", "専用ソート"]);
  rows.push(["運転免許管理", "有効期限が近い順", "免許証有効期限", "なし", "失効/更新予定など注意対象重視", "近い順", "専用ソート"]);
  rows.push(["資格管理", "所有者＋資格マスタ表示順", "更新期限は通知側", "なし", "所有者単位", "マスタ順", "専用ソート"]);
  rows.push(["見積書", "提出依頼 → 返答待ち → 提出済み → 空欄・下書き", "提出年月日", "なし", "返答待ちは通知完了だが、並び順では提出依頼の次", "古い順", "見積書専用ソート"]);

  const configs = getAllDateTimeSortConfigsForCheck_();
  Object.keys(configs).sort(function(a, b) { return a.localeCompare(b, "ja"); }).forEach(function(name) {
    if (["電話履歴", HOLIDAY_MANAGEMENT_SHEET_NAME, "車検管理", "運転免許管理", "資格管理", "見積書"].indexOf(name) >= 0) return;
    const c = configs[name];
    rows.push([
      name,
      c.statusHeader ? "未完了系 → 完了/中止系" : "日付順",
      (c.dates || []).join(" → "),
      (c.times || []).join(" → ") || "なし",
      c.statusHeader ? c.statusHeader + " / 完了扱い: " + (c.completed || []).join("・") : "状態判定なし",
      c.dateOrder === "desc" ? "新しい順" : "近い順",
      "今のシートだけ日時ソート・一括日付順整理で使用"
    ]);
  });

  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);
  if (rows.length) sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
  sheet.setFrozenRows(1);
  sheet.getRange(1, 1, 1, headers.length).setFontWeight("bold").setBackground("#d9ead3");
  sheet.autoResizeColumns(1, headers.length);
  try { sheet.setColumnWidth(2, 260); sheet.setColumnWidth(5, 300); sheet.setColumnWidth(7, 260); } catch (e) {}
  toast_("日時ソート設定チェックを作成しました。各シートの並び順を確認できます。");
}

