function appendExternalCheckSheetStructureDiagnosticsLightP61DS_(ss, rows) {
  let headersMap = {};
  try { headersMap = getSheetHeaders_(); } catch (e) { headersMap = {}; }
  const names = Object.keys(headersMap);
  rows.push(["シート構成", "対象シート数", "必須ヘッダー定義", "情報", names.length + "シート", "存在確認とヘッダー確認だけ実行"]);

  names.forEach(name => {
    const s = ss.getSheetByName(name);
    if (!s) {
      rows.push(["シート構成", name, "シート存在", "NG", "シートがありません", "必要なシートなら作成/修復メニューを実行"]);
      return;
    }
    let headers = [];
    try { headers = getHeaders_(s); } catch (e) { headers = []; }
    const expected = headersMap[name] || [];
    const missing = expected.filter(h => headers.indexOf(h) < 0);
    const detail = "行数:" + s.getLastRow() + " / 列数:" + s.getLastColumn() + (missing.length ? " / 不足:" + missing.join(", ") : " / 必須ヘッダーOK");
    rows.push(["シート構成", name, "存在・必須ヘッダー", missing.length ? "要確認" : "OK", detail, missing.length ? "列名変更・列削除・旧列残りを確認" : ""]);
  });
}

