function getMaskedListSummaryForDiagnostic_(list, unit, note) {
  const count = Array.isArray(list) ? list.filter(v => String(v || "").trim()).length : 0;
  return count + unit + "（匿名化済み: " + note + "）";
}

function buildRepairVendorDiagnosticSummary_(vendors) {
  const count = Array.isArray(vendors) ? vendors.length : 0;
  const testLikeCount = (vendors || []).filter(v => isLikelyTestValueForDiagnostic_(v)).length;
  return "登録件数: " + count + "件（名称は匿名化済み）" + (testLikeCount ? " / テスト値候補: " + testLikeCount + "件" : "");
}

function isLikelyTestValueForDiagnostic_(value) {
  const text = String(value || "").trim();
  if (!text) return false;
  if (/^(test|sample|dummy|auto_test|テスト|サンプル)/i.test(text)) return true;
  if (/^(あ+|い+|う+|え+|お+|a+|x+|ん+)$/i.test(text)) return true;
  if (/sam+p+u*r*u*/i.test(text)) return true;
  return false;
}

function sanitizeExternalCheckDiagnosticRows_(rows) {
  const sensitiveWords = buildExternalCheckDiagnosticSensitiveWords_();
  return rows.map(row => row.map(value => sanitizeExternalCheckDiagnosticCell_(value, sensitiveWords)));
}

function buildExternalCheckDiagnosticSensitiveWords_() {
  const words = [];
  try { words.push.apply(words, getStaffMembers_()); } catch (e) {}
  try { words.push.apply(words, getPersonalMembers_()); } catch (e) {}
  try { words.push.apply(words, getRepairVendors_()); } catch (e) {}

  // 車両名は短い値（例: 4t, 3t）を全置換すると文章が崩れやすいため、4文字以上だけ安全マスク対象にする。
  try {
    getCompanyVehicles_().forEach(v => {
      const text = String(v || "").trim();
      if (text.length >= 4) words.push(text);
    });
  } catch (e) {}

  return uniqueList_(words)
    .map(v => String(v || "").trim())
    .filter(v => v && v.length >= 2 && v !== CLEAR_LABEL)
    .sort((a, b) => b.length - a.length);
}

function sanitizeExternalCheckDiagnosticCell_(value, sensitiveWords) {
  let text = value == null ? "" : String(value);

  // メール・電話番号は診断に混ざった場合だけマスクする。
  text = text.replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, "[メールアドレス]");
  text = text.replace(/0\d{1,4}[-ー－ ]?\d{1,4}[-ー－ ]?\d{3,4}/g, "[電話番号]");

  (sensitiveWords || []).forEach(word => {
    const escaped = String(word).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    if (!escaped) return;
    text = text.replace(new RegExp(escaped, "g"), "[非表示]");
  });

  return text;
}

