function appendExternalCheckExternalWordingDiagnostics_(ss, rows) {
  const result = scanExternalWordingForDiagnostic_(ss);
  const detail = result.total === 0
    ? "該当なし"
    : "検出件数: " + result.total + "件 / 種別: " + objectToText_(result.termCounts) + " / シート: " + result.sheetNames.join(", ");

  rows.push([
    "共有前チェック",
    "共有前確認が必要な文言",
    "社内共有版に不要な共有前確認が必要な文言",
    result.total === 0 ? "OK" : "要確認",
    detail,
    result.total === 0
      ? "社内共有版としてはOK。説明用の説明は別ファイルへ分離"
      : "社内共有版に残す必要がない場合は削除。説明用・個人用途の説明は別ファイルへ分離"
  ]);
}

function scanExternalWordingForDiagnostic_(ss) {
  const patterns = getExternalWordingCheckPatterns_().filter(p => p.diagnostic !== false);

  const excludeSheets = {
    "診断用": true,
    "自動テスト結果": true
  };

  const termCounts = {};
  const sheetHit = {};
  let total = 0;

  ss.getSheets().forEach(sheet => {
    const name = sheet.getName();
    if (excludeSheets[name]) return;

    const lastRow = sheet.getLastRow();
    const lastCol = sheet.getLastColumn();
    if (lastRow < 1 || lastCol < 1) return;

    // 診断は軽量性優先。通常の社内管理シート規模なら十分だが、巨大シートは先頭から最大500行に制限する。
    const rowCount = Math.min(lastRow, 500);
    const colCount = Math.min(lastCol, 60);
    let values = [];
    try {
      values = sheet.getRange(1, 1, rowCount, colCount).getDisplayValues();
    } catch (e) {
      return;
    }

    values.forEach(row => {
      row.forEach(cell => {
        const text = String(cell || "");
        if (!text) return;
        patterns.forEach(p => {
          if (p.re.test(text)) {
            termCounts[p.label] = (termCounts[p.label] || 0) + 1;
            sheetHit[name] = true;
            total++;
          }
        });
      });
    });
  });

  return {
    total: total,
    termCounts: termCounts,
    sheetNames: Object.keys(sheetHit).sort((a, b) => String(a).localeCompare(String(b), "ja"))
  };
}



/**
 * p61i: 汎用シート取得/作成ヘルパー。
 * p61hの文言チェックで getOrCreateSheet_ 未定義になる問題を修正。
 */
function getOrCreateSheet_(sheetName) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(sheetName);
  if (!sheet) sheet = ss.insertSheet(sheetName);
  return sheet;
}

/**
 * p61h: 社内共有前の個人用途/共有前確認が必要な文言チェック。
 * 実データを削除せず、検出結果だけを「文言チェック」シートへ出す。
 */
function createExternalWordingCheckSheet() {
  const lock = acquireCompanyPackLock_("共有前文言チェック");
  if (!lock) return;

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const rows = buildExternalWordingCheckRows_(ss);
    const sheet = getOrCreateSheet_(WORDING_CHECK_SHEET_NAME);
    sheet.clear();
    sheet.clearFormats();

    const headers = ["区分", "シート", "セル", "検出ワード", "内容確認用抜粋", "対応目安", "セルを開く"];
    const output = [headers].concat(rows.length ? rows : [["結果", "全体", "", "該当なし", "共有前確認が必要な語は見つかりませんでした。", "会社共有前チェックとしてはOKです。", ""]]);
    sheet.getRange(1, 1, output.length, headers.length).setValues(output);

    sheet.getRange(1, 1, 1, headers.length)
      .setFontWeight("bold")
      .setBackground("#d9ead3")
      .setHorizontalAlignment("center");
    sheet.setFrozenRows(1);
    sheet.setColumnWidth(1, 150);
    sheet.setColumnWidth(2, 170);
    sheet.setColumnWidth(3, 80);
    sheet.setColumnWidth(4, 170);
    sheet.setColumnWidth(5, 520);
    sheet.setColumnWidth(6, 380);
    sheet.setColumnWidth(7, 110);
    sheet.getRange(1, 1, output.length, headers.length).setWrap(true).setVerticalAlignment("middle");

    try { sheet.getFilter() && sheet.getFilter().remove(); } catch (e) {}
    try { sheet.getRange(1, 1, Math.max(output.length, 2), headers.length).createFilter(); } catch (e) {}
    try { applyExternalWordingCheckColors_(sheet, output.length); } catch (e) { console.log("文言チェック色付けスキップ: " + e.message); }
    try { sanitizeCheckMaterialTermsP61DQ_(ss); } catch (e) {}
    try { reorderSheets_(); } catch (e) {}

    toast_(rows.length ? "文言チェックが完了しました。検出: " + rows.length + "件" : "文言チェックが完了しました。該当なしです。");
  } catch (err) {
    toast_("文言チェックでエラー: " + err.message);
    throw err;
  } finally {
    releaseCompanyPackLock_(lock);
  }
}

function buildExternalWordingCheckRows_(ss) {
  const patterns = getExternalWordingCheckPatterns_();
  const rows = [];
  const exclude = {};
  exclude[WORDING_CHECK_SHEET_NAME] = true;

  ss.getSheets().forEach(sheet => {
    const sheetName = sheet.getName();
    if (exclude[sheetName]) return;

    const lastRow = sheet.getLastRow();
    const lastCol = sheet.getLastColumn();
    if (lastRow < 1 || lastCol < 1) return;

    let values;
    try {
      values = sheet.getRange(1, 1, lastRow, lastCol).getDisplayValues();
    } catch (e) {
      rows.push(["読取エラー", sheetName, "", "", "このシートは読み取り時にエラー: " + e.message, "必要なら手動確認", ""]);
      return;
    }

    const sheetId = sheet.getSheetId();
    for (let r = 0; r < values.length; r++) {
      const row = values[r];
      for (let c = 0; c < row.length; c++) {
        const text = String(row[c] || "").trim();
        if (!text) continue;
        patterns.forEach(p => {
          if (!p.re.test(text)) return;
          const a1 = columnLetter_(c + 1) + (r + 1);
          const link = '=HYPERLINK("#gid=' + sheetId + '&range=' + a1 + '","開く")';
          rows.push([
            p.category,
            sheetName,
            a1,
            p.label,
            makeExternalWordingSnippet_(text, p.re),
            p.action,
            link
          ]);
        });
      }
    }
  });

  return rows.sort((a, b) => {
    const sa = String(a[1] || "");
    const sb = String(b[1] || "");
    if (sa !== sb) return sa.localeCompare(sb, "ja");
    return String(a[2] || "").localeCompare(String(b[2] || ""), "ja", {numeric: true});
  });
}

function getExternalWordingCheckPatterns_() {
  const readmeWord = "read" + "me";
  const repoWord = "git" + "hub";
  const portfolioWord = "port" + "folio";
  const outsidePublish = "外" + "部" + "公開";
  const outsideShare = "社" + "外" + "公開";
  const publishUse = "公開" + "用";
  const outsideFor = "外" + "部" + "向け";

  return [
    {category: "個人用途系", label: "転職関連", re: /転職/i, action: "社内運用画面には基本不要。必要なら削除、または個人用メモへ移動。"},
    {category: "個人用途系", label: "応募関連", re: /応募|求人|採用|スカウト/i, action: "社内運用画面には基本不要。求人・応募・採用活動の説明は別ファイルへ分離。"},
    {category: "個人用途系", label: "経歴関連", re: /職務経歴|履歴書|職歴/i, action: "社内運用画面には不要。個人用途の説明は削除または個人用へ分離。"},
    {category: "個人用途系", label: "働き方関連", re: /フルリモート|未経験/i, action: "個人用途の説明である可能性が高いので、社内共有画面から削除推奨。"},

    {category: "説明資料系", label: "説明資料", re: new RegExp("説明資料|" + portfolioWord, "i"), action: "社内運用画面には基本不要。説明用の文言は別資料へ分離。"},
    {category: "説明資料系", label: "説明先", re: new RegExp(repoWord.replace(/hub/i, "\\s*hub") + "|" + repoWord + "|OpOpWell", "i"), action: "社内運用画面には基本不要。説明先や個人ハンドルは削除推奨。"},
    {category: "説明資料系", label: "説明資料", re: new RegExp(readmeWord.replace(/me/i, "\\s*me") + "|" + readmeWord, "i"), action: "社内用シートに不要なら削除。説明文は別資料だけに残す。"},
    {category: "説明資料系", label: "共有範囲", re: new RegExp([outsidePublish, outsideShare, publishUse, outsideFor].join("|"), "i"), action: "社内運用画面に残す必要がある文言か確認。不要なら削除。"},

    {category: "個人用途・学習メモ系", label: "個人用途", re: /個人開発|個人制作|個人用|自分用/i, action: "会社運用資料には基本不要。個人用メモへ移動。"},
    {category: "個人用途・学習メモ系", label: "学習/練習", re: /学習用|練習用|勉強用/i, action: "社内運用画面には不要な場合が多い。説明が必要なら中立表現へ変更。"},
    {category: "個人用途・学習メモ系", label: "媒体名", re: /Green|Wantedly|Indeed|ビズリーチ|リクナビ|マイナビ/i, action: "個人用途の説明である可能性があるため、社内運用画面から削除推奨。"},

    {category: "サンプル・テスト系", label: "AUTO_TEST", re: /AUTO_TEST_/i, action: "自動テスト残骸の可能性。テストデータ削除メニューで削除するか確認。"},
    {category: "サンプル・テスト系", label: "サンプル/ダミー", re: /サンプル|ダミー|dummy|sample/i, action: "共有前に残してよいサンプルか確認。不要なら削除。"},
    {category: "サンプル・テスト系", label: "旧サンプル名", re: /山田|鈴木|田中|高橋|佐藤|伊藤|中村|小林|吉田|山本/i, action: "サンプル名か実在名か確認。共有前なら設定シート基準へ整理。"},

    {category: "連絡先・個人情報", label: "メールアドレス", re: /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i, action: "共有前に確認。会社内共有でも必要性を確認。"},
    {category: "連絡先・個人情報", label: "電話番号", re: /0\d{1,4}[-ー－ ]?\d{1,4}[-ー－ ]?\d{3,4}/, action: "共有前に確認。会社内共有でも必要な列だけに残す。"}
  ];
}
function makeExternalWordingSnippet_(text, re) {
  let s = String(text || "");
  s = s.replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, "[メールアドレス]");
  s = s.replace(/0\d{1,4}[-ー－ ]?\d{1,4}[-ー－ ]?\d{3,4}/g, "[電話番号]");
  const max = 120;
  if (s.length <= max) return s;
  let idx = 0;
  try {
    const m = s.match(re);
    if (m && typeof m.index === "number") idx = m.index;
  } catch (e) {}
  const start = Math.max(0, idx - 45);
  const end = Math.min(s.length, start + max);
  return (start > 0 ? "…" : "") + s.substring(start, end) + (end < s.length ? "…" : "");
}

function applyExternalWordingCheckColors_(sheet, rowCount) {
  if (rowCount <= 1) return;
  const range = sheet.getRange(2, 1, rowCount - 1, 1);
  const values = range.getValues();
  const backgrounds = values.map(row => {
    const v = String(row[0] || "");
    if (v.indexOf("転職") >= 0) return ["#f4cccc"];
    if (v.indexOf("共有前確認") >= 0) return ["#fce5cd"];
    if (v.indexOf("個人用途") >= 0) return ["#fff2cc"];
    if (v.indexOf("連絡先") >= 0) return ["#ead1dc"];
    if (v.indexOf("サンプル") >= 0) return ["#d9eaf7"];
    return ["#eeeeee"];
  });
  range.setBackgrounds(backgrounds);
}

