  addTextRuleByHeader_(rules, sheet, headers, "取得区分", "免許", "#d0e0e3", rowCount);

  // 保有状況：ここを一番見落としにくくする。
  addTextRuleByHeader_(rules, sheet, headers, "保有状況", "保有", "#d9ead3", rowCount);
  addTextRuleByHeader_(rules, sheet, headers, "保有状況", "未確認", "#fff2cc", rowCount);
