function addTextRule_(rules, sheet, col, text, color, rowCount) {
  if (!col || col <= 0) return;
  const range = sheet.getRange(2, col, Math.max(rowCount || getApplyRowCount_(sheet), 1), 1);
  rules.push(SpreadsheetApp.newConditionalFormatRule().whenTextEqualTo(text).setBackground(color).setRanges([range]).build());
}

function columnLetter_(col) {
  let temp = "";
  let n = col;
  while (n > 0) {
    const rem = (n - 1) % 26;
    temp = String.fromCharCode(65 + rem) + temp;
    n = Math.floor((n - rem - 1) / 26);
  }
  return temp;
}

function applyStatusBackground_(sheet, col, startRow, numRows) {
  if (numRows <= 0) return;
  const range = sheet.getRange(startRow, col, numRows, 1);
  const values = range.getValues();
  const backgrounds = values.map(r => [String(r[0]) === "OK" ? "#d9ead3" : String(r[0]) === "NG" ? "#ea9999" : "#fff2cc"]);
  range.setBackgrounds(backgrounds);
}


/**
 * 既読・個人確認列の見た目だけを全シートで再調整する。
 * 空行チェックボックス削除、入力済み行だけチェックボックス表示、個人確認列の縦書き・折りたたみをまとめて行う。
 */
function applyReadDisplayToAllSheets() {
  const lock = LockService.getDocumentLock();
  if (!lock.tryLock(30000)) {
    toast_("他の処理中のため、既読表示の再調整をスキップしました");
    return;
  }

  try {
    Object.keys(getSheetHeaders_()).forEach(name => {
      const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(name);
      if (!sheet) return;
      setCheckboxesForDataRows(sheet);
      applyPersonalCheckColumnLayout_(sheet);
      applyColorRules(sheet);
    });
    rebuildCheckGroups();
    toast_("既読表示・個人確認列を再調整しました");
  } finally {
    lock.releaseLock();
  }
}

function applyPersonalCheckColumnLayout_(sheet) {
  if (!sheet || sheet.getLastColumn() < 1) return;

  const headers = getHeaders_(sheet);
  const members = getPersonalMembers_();
  const lastRow = Math.max(sheet.getLastRow(), 1);

  // v9.7.11:
  // setTextRotation(90) は「文字を横向きに回転」するだけで、
  // Google Sheets上では見た目が横向き/寝た文字に見える場合がある。
  // 既読・個人確認列の見出しは setVerticalText(true) で本当の縦書きにする。
  const checkHeaders = [READ_HEADER, ...members];

  checkHeaders.forEach(header => {
    const col = headers.indexOf(header) + 1;
    if (col <= 0) return;

    sheet.setColumnWidth(col, 44);

    try {
      const headerCell = sheet.getRange(1, col);
      headerCell
        .setVerticalText(true)
        .setHorizontalAlignment("center")
        .setVerticalAlignment("middle")
        .setWrap(false);

      if (lastRow >= 2) {
        sheet.getRange(2, col, lastRow - 1, 1)
          .setVerticalText(false)
          .setHorizontalAlignment("center")
          .setVerticalAlignment("middle");
      }
    } catch (e) {
      console.log(sheet.getName() + " の既読/個人確認列レイアウト調整をスキップ: " + e.message);
    }
  });
}

function rebuildCheckGroups() {
  resetColumnGroups_();
  createPersonalCheckColumnGroups_();
  toast_("共有用に内部列を非表示へ戻し、既読・個人確認の＋展開グループを復旧しました。");
}

function resetColumnGroups_() {
  // p61bv:
  // 全シートの列グループ解除はしない。電話履歴だけを対象にする。
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("電話履歴");
  if (!sheet) return 0;
  let removed = 0;
  try { removed += clearColumnGroupsForSheet_(sheet) || 0; } catch (e) {}
  try { deleteDeprecatedPhoneHistoryStatusColumns_(sheet); } catch (e2) {}
  try { hidePhoneHistoryInternalColumnsUltraLight_(sheet); } catch (e3) {}
  return removed;
}

function createPersonalCheckColumnGroups_() {
  // p61bv:
  // 共有メニューからは電話履歴の既読・個人確認グループだけを復旧する。
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("電話履歴");
  if (!sheet) return 0;
  try { return createPersonalCheckColumnGroupForSheet_(sheet) || 0; } catch (e) {
    console.log("電話履歴の既読/個人確認グループ作成をスキップ: " + e.message);
    return 0;
  }
}

function createPersonalCheckColumnGroupForSheet_(sheet) {
  if (!sheet || sheet.getLastColumn() < 1) return 0;

  const headers = getHeaders_(sheet);
  if (!headers.length || headers.indexOf(READ_HEADER) < 0) return 0;

  const checkboxHeaders = getCheckboxHeadersForSheet_(sheet);
  const personalHeaders = uniqueList_((checkboxHeaders || []).filter(function(header) {
    if (!header || header === READ_HEADER) return false;
    if (typeof LICENSE_TYPE_HEADERS !== "undefined" && LICENSE_TYPE_HEADERS.indexOf(header) >= 0) return false;
    return true;
  }));

  const personalCols = personalHeaders
    .map(function(header) { return headers.indexOf(header) + 1; })
    .filter(function(col) { return col > 0; });

  if (!personalCols.length) return 0;

  const startCol = Math.min.apply(null, personalCols);
  const endCol = Math.max.apply(null, personalCols);
  const width = endCol - startCol + 1;

  try {
    const groupRange = sheet.getRange(1, startCol, Math.max(sheet.getMaxRows(), 1), width);
    groupRange.shiftColumnGroupDepth(1);

    // 既読列は常時見せ、個人確認者列だけを＋で展開できるようにする。
    // collapse() が使える環境では折りたたんで＋表示に寄せる。
    try {
      const group = sheet.getColumnGroup(startCol, 1);
      if (group && typeof group.collapse === "function") group.collapse();
    } catch (e) {}
    return 1;
  } catch (e) {
    console.log(sheet.getName() + " の既読/個人確認グループ作成をスキップ: " + e.message);
    return 0;
  }
}

function rebuildPersonalCheckGroupForSheet_(sheet) {
  if (!sheet || sheet.getLastColumn() < 1) return;
  try { clearColumnGroupsForSheet_(sheet); } catch (e) {}
  try { hideSystemColumnsForSheet_(sheet); } catch (e2) {}
  if (sheet.getName && sheet.getName() === "電話履歴") {
    try { hidePhoneHistoryInternalColumnsUltraLight_(sheet); } catch (e3) {}
  }
  try { createPersonalCheckColumnGroupForSheet_(sheet); } catch (e4) {}
}


