function detectMonthGroupHeaderForSheet_(sheet) {
  if (!sheet || sheet.getLastColumn() < 1) return "";
  const headers = getHeaders_(sheet);
  const preferred = [
    "日付", "対象月", "使用月", "資料日付", "印刷日", "作成日", "作成日時", "更新日",
    "提出期限", "確認日", "休み開始日", "休み終了日", "期限", "開始日", "終了日", "車検期限", "車検予定日", "免許証有効期限", "更新期限"
  ];
  for (let i = 0; i < preferred.length; i++) {
    if (headers.indexOf(preferred[i]) >= 0) return preferred[i];
  }
  return "";
}

function formatMonthKeyForGrouping_(value) {
  const d = toDateOnly_(value);
  if (d) return Utilities.formatDate(d, Session.getScriptTimeZone(), "yyyy年MM月");

  const text = String(value || "").trim();
  if (!text) return "日付なし";
  if (text === "通年") return "通年";

  const ym = text.match(/(20\d{2}|19\d{2})\s*[年\/\-.]\s*(\d{1,2})\s*月?/);
  if (ym) return ym[1] + "年" + ("0" + ym[2]).slice(-2) + "月";

  const month = text.match(/^(\d{1,2})月$/);
  if (month) return ("0" + month[1]).slice(-2) + "月";

  const range = text.match(/^(\d{1,2})月\s*[〜～~\-]\s*(\d{1,2})月$/);
  if (range) return ("0" + range[1]).slice(-2) + "月〜" + ("0" + range[2]).slice(-2) + "月";

  return text;
}

