function cleanupScheduleOutputOldFormats() {
  // p61cr:
  // 行グループ解除/再作成は重く、一覧スケジュールの日常運用では使わない。
  // 旧書式整理は「フィルタ貼り直し・ヘッダー/列幅の最低限整理」だけにし、行グループは触らない。
  // 古い行グループを消したい場合だけ、別メニュー「一覧・要確認の行グループ解除（重い・一度だけ）」を使う。
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const targets = ["一覧スケジュール", "要確認一覧"];
  let fixed = 0;
  targets.forEach(function(name) {
    const sheet = ss.getSheetByName(name);
    if (!sheet) return;
    const headers = getSheetHeaders_()[name] || getHeaders_(sheet);
    try { removeFilter_(sheet); } catch (e) {}
    try { showRowsUpToLastData_(sheet); } catch (e) {}
    try { applyOutputSheetBasicFormatLight_(sheet, headers); } catch (e) {}
    try { createFilterSafely_(sheet, headers.length); } catch (e) {}
    fixed++;
  });
  toast_("一覧・要確認の旧書式を軽量整理しました（対象:" + fixed + "シート / 行グループは触っていません）。");
}

function resetScheduleOutputRowGroupsHeavy() {
  // p61cr:
  // 旧版で作った一覧スケジュール/要確認一覧の行グループを消すための一度きり想定の重い処理。
  // 日常更新や旧書式整理からは呼ばない。
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const targets = ["一覧スケジュール", "要確認一覧"];
  let fixed = 0;
  targets.forEach(function(name) {
    const sheet = ss.getSheetByName(name);
    if (!sheet) return;
    try { removeFilter_(sheet); } catch (e) {}
    try { clearAllRowGroupsAndShowRows_(sheet); } catch (e) {}
    try { showRowsUpToLastData_(sheet); } catch (e) {}
    try { createFilterSafely_(sheet, (getSheetHeaders_()[name] || getHeaders_(sheet)).length); } catch (e) {}
    fixed++;
  });
  toast_("一覧・要確認の行グループを解除しました（対象:" + fixed + "シート）。今後は月別グループ化を使わず、フィルタで月を確認してください。");
}

function showRowsUpToLastData_(sheet) {
  if (!sheet) return;
  const rows = Math.max(Math.min(sheet.getMaxRows(), Math.max(sheet.getLastRow() + 20, 2)), 2);
  try { sheet.showRows(1, rows); } catch (e) {}
}

function rebuildArchiveFromCurrentSchedule() {
  const ui = SpreadsheetApp.getUi();
  const res = ui.alert(
    "過去一覧を現在の一覧から作り直す",
    "過去一覧の明細を一度クリアして、現在の一覧スケジュールに残っている過去・完了系だけで作り直します。\n\n"
    + "元シート側で削除済みのデータは、作り直し後の過去一覧には戻りません。\n"
    + "車検履歴・免許更新履歴・資格更新履歴・帳簿PDF履歴は触りません。\n\n"
    + "続行しますか？",
    ui.ButtonSet.YES_NO
  );
  if (res !== ui.Button.YES) return;

  const lock = acquireCompanyPackLock_("過去一覧作り直し");
  if (!lock) return;

  try {
    createScheduleList();

    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const source = ss.getSheetByName("一覧スケジュール");
    let archive = ss.getSheetByName("過去一覧");
    if (!archive) archive = ss.insertSheet("過去一覧");

    const headers = getSheetHeaders_()["過去一覧"];
    setupSheet_(archive, headers);
    clearArchiveDataRowsAndGroups_(archive);

    const rows = collectArchiveRowsFromSchedule_(source);
    if (rows.length) appendObjectsToSheet_(archive, rows);

    groupArchiveByMonth();
    hideSystemColumnsForSheet_(archive);
    toast_("過去一覧を現在の一覧から作り直しました: " + rows.length + "件");
  } catch (err) {
    toast_("過去一覧作り直しでエラー: " + err.message);
    throw err;
  } finally {
    releaseCompanyPackLock_(lock);
  }
}

function clearArchiveDataRowsAndGroups_(archive) {
  if (!archive) return;
  clearAllRowGroupsAndShowRows_(archive);
  const headers = getSheetHeaders_()["過去一覧"] || getHeaders_(archive);
  const colCount = Math.max(headers.length || 1, archive.getLastColumn() || 1);
  const lastRow = Math.max(archive.getLastRow(), 2);
  if (lastRow >= 2) {
    try { archive.getRange(2, 1, lastRow - 1, colCount).clearContent().clearDataValidations(); } catch (e) {}
  }
  try { applyDataValidationByHeaders_(archive, headers); } catch (e) {}
}

function collectArchiveRowsFromSchedule_(source) {
  if (!source || source.getLastRow() < 2) return [];
  const h = getHeaders_(source);
  const values = source.getRange(2, 1, source.getLastRow() - 1, h.length).getValues();
  const today = toDateOnly_(new Date());
  const keys = new Set();
  const rows = [];

  values.forEach(v => {
    const r = objectFromRow(h, v);
    if (!shouldArchiveScheduleRow_(r, today)) return;
    const archiveRow = buildArchiveRowFromSchedule_(r);
    const key = buildArchiveKey_(archiveRow);
    if (keys.has(key)) return;
    keys.add(key);
    rows.push(archiveRow);
  });

  return rows;
}

function monthlyMaintenance() {
  // p56: 月次整理は、最新の一覧スケジュールを作り直してから過去一覧へ追加し、過去一覧だけを月別に折りたたむ。
  // 履歴シート（車検履歴・運転免許更新履歴・資格更新履歴・帳簿PDF履歴）は追記専用のため触らない。
  // 元の入力シートから勝手に削除しないため、会社共有中でも安全寄り。
  const lock = LockService.getDocumentLock();
  try {
    if (!lock.tryLock(3000)) {
      toast_("他の更新処理中のため、月次整理は実行しませんでした。少し待ってから再実行してください。");
      return;
    }
    createScheduleList();
    movePastItemsToArchive();
    groupArchiveByMonth();
    createAlertList();
    toast_("月次整理が完了しました（一覧更新＋過去一覧追加＋過去一覧の月別整理）。履歴シートは触っていません。");
  } catch (err) {
    toast_("月次整理でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function shouldArchiveScheduleRow_(row, today) {
  const d = toDateOnly_(row["日付"]);
  if (!d || d.getTime() >= today.getTime()) return false;
  return isArchiveCompletedScheduleRow_(row);
}

function isArchiveCompletedScheduleRow_(row) {
  const source = String(row["元シート"] || "").trim();
  const type = String(row["種類"] || "").trim();
  const status = String(row["状態"] || "").trim();
  const phone = String(row["電話対応"] || "").trim();

  // p54: シートごとの完了扱いを明確化。
  // 一覧スケジュールに残すべき未対応・期限注意の行は過去一覧へ入れない。
  if (source === "電話履歴" || type === "電話履歴") return phone === "完了" || status === "完了";
  if (source === "工事予定" || type === "工事予定") return ["完了", "請求済み", "中止"].includes(status);
  if (source === "見積書" || type === "見積書") return ["提出済み", "受注", "失注", "完了", "中止"].includes(status);
  if (source === "安全書類管理" || type === "安全書類") return ["提出済", "確認済", "不要", "中止", "完了"].includes(status);
  if (source === "社用車予約" || type === "社用車予約") return ["返却済", "完了", "中止"].includes(status);
  if (source === HOLIDAY_MANAGEMENT_SHEET_NAME || type === "休み") return ["取得済", "完了", "取消", "中止"].includes(status);
  if (source === "備品修理管理" || type === "備品修理") return ["返却済", "完了", "修理不可", "中止"].includes(status);
  if (source === "個人ToDo" || type === "ToDo") return ["完了", "中止"].includes(status);
  if (source === "日報" || type === "日報") return ["完了", "確認済"].includes(status);
  if (source === "日報レシート管理" || type === "日報レシート") return ["確認済", "精算済", "完了"].includes(status);

  // 車検・免許・資格は基本的に本体/履歴シートで管理する。
  // 一覧に出たものを過去一覧へ入れる場合だけ、明確な更新済み・完了系に限定する。
  if (source === "車検管理" || type === "車検") return ["更新済", "完了"].includes(status);
  if (source === "運転免許管理" || type === "運転免許") return ["更新済"].includes(status);
  if (source === "資格管理" || type === "資格") return ["更新済"].includes(status);

  return ["完了", "確認済", "更新済", "返却済", "中止", "請求済み", "提出済み", "精算済"].includes(status);
}

function buildArchiveRowFromSchedule_(r) {
  return {
    "日付": r["日付"],
    "種類": r["種類"],
    "内容": r["内容"],
    "担当": r["担当"],
    "状態": r["状態"],
    "通知": r["通知"],
    "元シート": r["元シート"],
    "備考": r["備考"],
    "移動日": new Date()
  };
}

function getExistingArchiveKeys_(archive) {
  const keys = new Set();
  if (!archive || archive.getLastRow() < 2) return keys;
  const headers = getHeaders_(archive);
  const values = archive.getRange(2, 1, archive.getLastRow() - 1, headers.length).getValues();
  values.forEach(v => {
    const row = objectFromRow(headers, v);
    keys.add(buildArchiveKey_(row));
  });
  return keys;
}

function buildArchiveKey_(row) {
  return [
    normalizeArchiveKeyValue_(row["日付"]),
    row["種類"],
    row["内容"],
    row["担当"],
    row["状態"],
    row["電話対応"],
    row["元シート"]
  ].map(v => String(v || "").trim()).join("||");
}

function normalizeArchiveKeyValue_(value) {
  if (value instanceof Date) return Utilities.formatDate(value, Session.getScriptTimeZone(), "yyyy-MM-dd HH:mm:ss");
  const d = toDateOnly_(value);
  if (d) return Utilities.formatDate(d, Session.getScriptTimeZone(), "yyyy-MM-dd");
  return value;
}

function appendObjectsToSheet_(sheet, objects) {
  if (!sheet || !objects || objects.length === 0) return;
  const headers = getHeaders_(sheet);
  if (!headers.length) return;
  const personal = getPersonalMembers_();
  const values = objects.map(obj => headers.map(header => {
    if (header === READ_HEADER || personal.includes(header) || LICENSE_TYPE_HEADERS.includes(header)) return obj[header] === true;
    return obj[header] !== undefined ? obj[header] : "";
  }));
  const startRow = Math.max(sheet.getLastRow() + 1, 2);
  const range = sheet.getRange(startRow, 1, values.length, headers.length);
  try {
    range.setValues(values);
  } catch (e) {
    // p61a:
    // システム側の初期データ・候補データ追加時に、古い入力規則が残っていて setValues が止まる場合がある。
    // 値を安全に入れたあと、ヘッダー基準の入力規則を貼り直す。
    if (!String(e && e.message || "").includes("入力規則")) throw e;
    range.clearDataValidations();
    range.setValues(values);
    const allHeaders = getSheetHeaders_()[sheet.getName()];
    if (allHeaders) {
      try { applyDataValidationByHeaders_(sheet, allHeaders); } catch (validationErr) { console.log("append後の入力規則再設定をスキップ: " + validationErr.message); }
    }
  }
  setCheckboxesForDataRows(sheet);
}

