function createFeedbackSheet() { setupSheetsIfMissing_(["フィードバック"]); }


function createSafetyDocumentSheet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("安全書類管理");
  if (!sheet) sheet = ss.insertSheet("安全書類管理");
  setupSheet_(sheet, getSheetHeaders_()["安全書類管理"]);
  updateNoticeColumnForSheet_(sheet);
  sortSafetyDocumentSheetByMonth_();
  formatSheetByName_("安全書類管理");
  toast_("安全書類管理シートを作成/修復しました");
}

function createSafetyDocumentsForCurrentMonth() {
  const today = new Date();
  createMonthlySafetyDocuments_(new Date(today.getFullYear(), today.getMonth(), 1));
}

function createSafetyDocumentsForNextMonth() {
  const today = new Date();
  createMonthlySafetyDocuments_(new Date(today.getFullYear(), today.getMonth() + 1, 1));
}

function createSafetyDocumentsForPromptMonth() {
  const ui = SpreadsheetApp.getUi();
  const res = ui.prompt(
    "月を指定して安全書類を作成",
    "作成する対象月を yyyy/mm または yyyy-mm で入力してください。例: 2026/07",
    ui.ButtonSet.OK_CANCEL
  );
  if (res.getSelectedButton() !== ui.Button.OK) return;
  const target = parseYearMonthInput_(res.getResponseText());
  if (!target) {
    ui.alert("対象月の形式が正しくありません。例: 2026/07");
    return;
  }
  createMonthlySafetyDocuments_(target);
}

function createMonthlySafetyDocuments_(targetMonthDate) {
  const lock = acquireCompanyPackLock_("月ごと安全書類作成");
  if (!lock) return;
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    let sheet = ss.getSheetByName("安全書類管理");
    if (!sheet) sheet = ss.insertSheet("安全書類管理");
    setupSheet_(sheet, getSheetHeaders_()["安全書類管理"]);

    const targetMonth = firstDayOfMonth_(targetMonthDate);
    const targetEnd = lastDayOfMonth_(targetMonth);
    const dueDate = new Date(targetMonth.getFullYear(), targetMonth.getMonth(), 5);
    const existingKeys = getExistingSafetyDocumentKeys_(sheet);
    const constructionRows = getConstructionRowsForSafetyDocuments_(ss, targetMonth, targetEnd);
    const rows = [];
    let skipped = 0;

    const addRow = (base) => {
      const row = buildMonthlySafetyDocumentRow_(base, targetMonth, dueDate);
      const key = buildSafetyDocumentKey_(row);
      if (existingKeys.has(key)) {
        skipped++;
        return;
      }
      existingKeys.add(key);
      rows.push(row);
    };

    if (constructionRows.length) {
      constructionRows.forEach(addRow);
    } else {
      addRow({"工事名": "月次共通", "現場": "全体", "依頼主": "", "担当": "", "備考": "対象月の工事予定が未登録のため共通行として作成"});
    }

    if (rows.length) {
      appendObjectsToSheet_(sheet, rows);
      ensureIdsForSheet_(sheet);
      updateNoticeColumnForSheet_(sheet);
      sortSafetyDocumentSheetByMonth_();
      formatSheetByName_("安全書類管理");
    }

    createScheduleList();
    createAlertList();
    toast_(formatYearMonthLabel_(targetMonth) + "の安全書類を作成しました: 新規 " + rows.length + "件 / 既存スキップ " + skipped + "件");
  } catch (err) {
    toast_("月ごと安全書類作成でエラー: " + err.message);
    throw err;
  } finally {
    releaseCompanyPackLock_(lock);
  }
}

function getConstructionRowsForSafetyDocuments_(ss, targetStart, targetEnd) {
  const sheet = ss.getSheetByName("工事予定");
  if (!sheet || sheet.getLastRow() < 2) return [];
  const headers = getHeaders_(sheet);
  const values = sheet.getRange(2, 1, sheet.getLastRow() - 1, headers.length).getValues();
  const rows = [];
  values.forEach(v => {
    const r = objectFromRow(headers, v);
    if (!isBusinessDataRow_(headers, v, "工事予定")) return;
    if (!shouldCreateSafetyDocumentForConstruction_(r, targetStart, targetEnd)) return;
    rows.push(r);
  });
  return rows;
}

function shouldCreateSafetyDocumentForConstruction_(row, targetStart, targetEnd) {
  const status = String(row["状態"] || "").trim();
  if (["完了", "請求済み", "中止", "対象外"].includes(status)) return false;
  const name = String(row["工事名"] || row["現場"] || "").trim();
  if (!name) return false;

  const start = toDateOnly_(row["開始日"] || row["契約日"]);
  const end = toDateOnly_(row["終了日"] || row["開始日"] || row["契約日"]);
  if (!start && !end) return false;
  const s = start || end;
  const e = end || start;
  return s.getTime() <= targetEnd.getTime() && e.getTime() >= targetStart.getTime();
}

function buildMonthlySafetyDocumentRow_(base, targetMonth, dueDate) {
  const obj = {
    "対象月": targetMonth,
    "作成日": new Date(),
    "工事名": base["工事名"] || "",
    "現場": base["現場"] || "",
    "書類区分": "月次",
    "書類名": "安全書類一式",
    "提出期限": dueDate,
    "提出先": base["依頼主"] || "",
    "担当": base["担当"] || "",
    "状態": "未作成",
    "確認日": "",
    "備考": base["備考"] || "月次安全書類の作成確認",
    "安全書類ID": buildRecordId_("安全書類管理")
  };
  obj["通知"] = getNoticeForRow_("安全書類管理", obj);
  return obj;
}

function getExistingSafetyDocumentKeys_(sheet) {
  const set = new Set();
  if (!sheet || sheet.getLastRow() < 2) return set;
  const headers = getHeaders_(sheet);
  const values = sheet.getRange(2, 1, sheet.getLastRow() - 1, headers.length).getValues();
  values.forEach(v => {
    const r = objectFromRow(headers, v);
    if (!isBusinessDataRow_(headers, v, "安全書類管理")) return;
    set.add(buildSafetyDocumentKey_(r));
  });
  return set;
}

function buildSafetyDocumentKey_(row) {
  return [
    formatYearMonthKey_(row["対象月"]),
    String(row["工事名"] || "").trim(),
    String(row["現場"] || "").trim(),
    String(row["書類名"] || "").trim()
  ].join("||");
}

function parseYearMonthInput_(text) {
  const s = String(text || "").trim();
  const m = s.match(/^(\d{4})[\/\-.年](\d{1,2})/);
  if (!m) return null;
  const y = Number(m[1]);
  const month = Number(m[2]);
  if (!y || month < 1 || month > 12) return null;
  return new Date(y, month - 1, 1);
}

function firstDayOfMonth_(value) {
  const d = toDateOnly_(value) || new Date();
  return new Date(d.getFullYear(), d.getMonth(), 1);
}

function lastDayOfMonth_(value) {
  const d = firstDayOfMonth_(value);
  return new Date(d.getFullYear(), d.getMonth() + 1, 0);
}

function formatYearMonthKey_(value) {
  const d = toDateOnly_(value);
  if (!d) return "";
  return Utilities.formatDate(new Date(d.getFullYear(), d.getMonth(), 1), Session.getScriptTimeZone(), "yyyy-MM");
}

function formatYearMonthLabel_(value) {
  const d = toDateOnly_(value);
  if (!d) return "対象月";
  return Utilities.formatDate(new Date(d.getFullYear(), d.getMonth(), 1), Session.getScriptTimeZone(), "yyyy年MM月");
}

function sortSafetyDocumentSheetByMonth_() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("安全書類管理");
  if (!sheet || sheet.getLastRow() < 3) return 0;
  return sortSheetRowsByDateTime_(sheet, ["対象月", "提出期限", "作成日"], []);
}


