function createSafetyEducationPrintForCurrentMonth() {
  const today = new Date();
  createSafetyEducationPrintForMonth_(new Date(today.getFullYear(), today.getMonth(), 1));
}

function createSafetyEducationPrintForNextMonth() {
  const today = new Date();
  createSafetyEducationPrintForMonth_(new Date(today.getFullYear(), today.getMonth() + 1, 1));
}

function createSafetyEducationPrintForPromptMonth() {
  const ui = SpreadsheetApp.getUi();
  const res = ui.prompt(
    "月を指定して安全教育印刷シートを作成",
    "作成する対象月を yyyy/mm または yyyy-mm で入力してください。例: 2026/07",
    ui.ButtonSet.OK_CANCEL
  );
  if (res.getSelectedButton() !== ui.Button.OK) return;
  const target = parseYearMonthInput_(res.getResponseText());
  if (!target) {
    ui.alert("対象月の形式が正しくありません。例: 2026/07");
    return;
  }
  createSafetyEducationPrintForMonth_(target);
}

function createSafetyEducationPrintForMonth_(targetMonthDate) {
  const lock = acquireCompanyPackLock_("安全教育印刷シート作成");
  if (!lock) return;
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    createSafetyEducationMaterialSheetIfMissing_();
    const targetMonth = firstDayOfMonth_(targetMonthDate);
    const materials = getSafetyEducationMaterialsForMonth_(ss, targetMonth);
    const printMaterials = limitSafetyEducationPrintMaterials_(materials);
    const printSheet = buildSafetyEducationPrintSheet_(ss, targetMonth, printMaterials, materials.length);
    if (printMaterials.length) markSafetyEducationOverviewRowsPrinted_(ss, targetMonth, printMaterials);
    ss.setActiveSheet(printSheet);
    const omitted = Math.max(0, materials.length - printMaterials.length);
    toast_(formatYearMonthLabel_(targetMonth) + "の承認済み安全教育資料を印刷シートへ反映しました。印刷資料:" + printMaterials.length + "件" + (omitted ? " / 未掲載:" + omitted + "件（1〜3資料に制限）" : ""));
  } catch (err) {
    toast_("安全教育印刷シート作成でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function createSafetyEducationMaterialSheetIfMissing_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("安全教育資料集");
  if (!sheet) sheet = ss.insertSheet("安全教育資料集");
  setupSheet_(sheet, getSheetHeaders_()["安全教育資料集"]);
  return sheet;
}

function getSafetyEducationMaterialsForMonth_(ss, targetMonth) {
  // p61:
  // 印刷対象は、概要チェックで「承認済み」になったものだけに限定する。
  // 旧p60のように資料集の全行を直接印刷すると、未確認資料が混ざるためここでは使わない。
  return getApprovedSafetyEducationMaterialsForMonth_(ss, targetMonth, false);
}

function limitSafetyEducationPrintMaterials_(materials) {
  return (materials || []).slice(0, SAFETY_EDUCATION_MONTHLY_PRINT_MAX_ITEMS);
}


function buildSafetyEducationPrintSheet_(ss, targetMonth, materials, totalApprovedCount) {
  let sheet = ss.getSheetByName("安全教育印刷");
  if (!sheet) sheet = ss.insertSheet("安全教育印刷");
  sheet.clear();
  sheet.clearFormats();
  try { sheet.getRange(1, 1, sheet.getMaxRows(), sheet.getMaxColumns()).breakApart(); } catch (e) {}

  const title = formatYearMonthLabel_(targetMonth) + " 安全教育資料";
  const approvedCount = typeof totalApprovedCount === "number" ? totalApprovedCount : (materials || []).length;
  const omitted = Math.max(0, approvedCount - (materials || []).length);
  ensureMinimumColumns_(sheet, 9);
  ensureMinimumRows_(sheet, 140);
  sheet.setHiddenGridlines(true);

  // p61j:
  // ここは管理表ではなく、印刷して配布・朝礼で読める資料形式に寄せる。
  // 画像生成/APIは使わず、概要チェックで承認済みになった文章だけをA4資料風に整形する。
  [1,2,3,4,5,6,7,8,9].forEach(c => sheet.setColumnWidth(c, [80,110,125,125,125,125,125,110,80][c - 1]));
  sheet.getRange(1, 1, 1, 9).merge().setValue(title)
    .setFontSize(20).setFontWeight("bold").setHorizontalAlignment("center").setBackground("#d9ead3");
  sheet.getRange(2, 1, 1, 9).merge().setValue("概要チェックで承認済みになった資料だけを、A4配布資料風にまとめます。月ごとの印刷量は1〜3資料程度です。")
    .setWrap(true).setFontSize(10).setVerticalAlignment("middle").setBackground("#f3f6f4");
  sheet.getRange(3, 1, 1, 9).merge().setValue("印刷目安：A4縦または横・幅に合わせる。イラストURLがある場合は画像欄へ表示を試み、ない場合はイラスト案を文字で表示します。" + (omitted ? "　未掲載:" + omitted + "件" : ""))
    .setWrap(true).setFontSize(9).setFontColor("#666666");

  let row = 5;
  if (!materials.length) {
    sheet.getRange(row, 1, 2, 9).merge().setValue("この月の承認済み安全教育資料がありません。資料候補を概要チェックへ反映し、状態を「承認済み」にしてから再作成してください。")
      .setWrap(true).setBackground("#fff2cc").setVerticalAlignment("middle");
    row += 4;
  } else {
    materials.forEach((m, index) => {
      row = writeSafetyEducationPrintDocumentBlock_(sheet, row, m, index + 1, targetMonth);
      row += 2;
    });
  }

  sheet.getRange(row + 1, 1, 1, 9).merge().setValue("共通確認欄　説明者：　　　　　　　　　確認者：　　　　　　　　　実施日：　　　　年　　　月　　　日")
    .setFontWeight("bold").setBackground("#fce5cd").setWrap(true);
  sheet.getRange(row + 3, 1, 1, 9).merge().setValue("注意：参考資料を丸写しせず、参考元を確認したうえで社内用の短い説明文として使用してください。")
    .setFontSize(10).setFontColor("#666666");

  sheet.setRowHeights(1, Math.max(row + 5, 40), 28);
  sheet.getRange(1, 1, Math.max(row + 5, 40), 9).setVerticalAlignment("middle").setWrap(true);
  try { sheet.setFrozenRows(0); } catch (e) {}
  try { sheet.getRange(1, 1, Math.max(row + 5, 40), 9).setFontFamily("Arial"); } catch (e) {}
  return sheet;
}

function writeSafetyEducationPrintDocumentBlock_(sheet, startRow, material, no, targetMonth) {
  const title = String(material["タイトル"] || "資料タイトル未入力").trim();
  const theme = String(material["テーマ"] || material["資料テーマ"] || "").trim();
  const category = String(material["資料区分"] || "").trim();
  const topic = String(material["トピック"] || "").trim();
  const overview = String(material["概要"] || material["概要案"] || "").trim();
  const points = String(material["重要ポイント"] || "").trim();
  const talk = String(material["現場で話すこと"] || material["朝礼で話すこと"] || "").trim();
  const source = String(material["参考元"] || "").trim();
  const url = String(material["参考URL"] || "").trim();
  const attachment = String(material["添付ファイルURL"] || "").trim();
  const illustrationUrl = String(material["イラストURL"] || "").trim();
  const illustrationText = String(material["イラスト案"] || material["イラスト指示"] || "").trim();
  const note = String(material["備考"] || "").trim();

  let row = startRow;
  const headline = "資料" + no + "　" + formatYearMonthLabel_(targetMonth) + "　安全教育";
  sheet.getRange(row, 1, 1, 9).merge().setValue(headline)
    .setFontSize(16).setFontWeight("bold").setHorizontalAlignment("center").setBackground("#d9eaf7");
  row++;

  sheet.getRange(row, 1, 1, 2).merge().setValue("テーマ").setFontWeight("bold").setBackground("#eaf4e2");
  sheet.getRange(row, 3, 1, 3).merge().setValue(theme || category || "未設定").setFontWeight("bold");
  sheet.getRange(row, 6, 1, 1).setValue("トピック").setFontWeight("bold").setBackground("#eaf4e2");
  sheet.getRange(row, 7, 1, 3).merge().setValue(topic || title);
  row++;

  sheet.getRange(row, 1, 1, 9).merge().setValue(title)
    .setFontSize(18).setFontWeight("bold").setHorizontalAlignment("center").setBackground("#fff2cc");
  row++;

  // 本文エリア。左側に文章、右側にイラスト欄を置く。
  const bodyStart = row;
  sheet.getRange(row, 1, 1, 6).merge().setValue("1. 今月のポイント")
    .setFontWeight("bold").setBackground("#d9ead3");
  sheet.getRange(row, 7, 1, 3).merge().setValue("イラスト・掲示欄")
    .setFontWeight("bold").setBackground("#eadcf8");
  row++;

  sheet.getRange(row, 1, 3, 6).merge().setValue(overview || "概要を入力してください。")
    .setWrap(true).setVerticalAlignment("top").setFontSize(11);
  const illustrationRange = sheet.getRange(row, 7, 5, 3).merge();
  setSafetyEducationIllustrationCell_(illustrationRange, illustrationUrl, illustrationText);
  row += 3;

  sheet.getRange(row, 1, 1, 6).merge().setValue("2. 重要ポイント")
    .setFontWeight("bold").setBackground("#fce5cd");
  row++;
  sheet.getRange(row, 1, 4, 6).merge().setValue(formatSafetyEducationPointList_(points))
    .setWrap(true).setVerticalAlignment("top").setFontSize(11);
  row += 4;

  sheet.getRange(row, 1, 1, 9).merge().setValue("3. 朝礼で話すこと")
    .setFontWeight("bold").setBackground("#d9ead3");
  row++;
  sheet.getRange(row, 1, 3, 9).merge().setValue(talk || "朝礼・安全教育で話す内容を入力してください。")
    .setWrap(true).setVerticalAlignment("top").setFontSize(12).setBackground("#f3f9f1");
  row += 3;

  sheet.getRange(row, 1, 1, 9).merge().setValue("4. 現場で確認すること")
    .setFontWeight("bold").setBackground("#cfe2f3");
  row++;
  sheet.getRange(row, 1, 3, 9).merge().setValue(buildSafetyEducationChecklistText_(material))
    .setWrap(true).setVerticalAlignment("top");
  row += 3;

  const backStart = row;
  sheet.getRange(row, 1, 1, 9).merge().setValue("確認・記録欄")
    .setFontWeight("bold").setHorizontalAlignment("center").setBackground("#f3f3f3");
  row++;
  sheet.getRange(row, 1, 1, 2).merge().setValue("参考元").setFontWeight("bold").setBackground("#f3f3f3");
  sheet.getRange(row, 3, 1, 7).merge().setValue(source || "参考元未入力。承認前に確認してください。");
  row++;
  sheet.getRange(row, 1, 1, 2).merge().setValue("参考URL/添付").setFontWeight("bold").setBackground("#f3f3f3");
  sheet.getRange(row, 3, 1, 7).merge().setValue([url, attachment].filter(Boolean).join(" / ") || "URLなし");
  row++;
  sheet.getRange(row, 1, 2, 9).merge().setValue("□ 内容確認　□ 参加者へ説明　□ 質問確認　□ 記録保管\n説明者：　　　　　　　　　確認者：　　　　　　　　　実施日：　　　　年　　　月　　　日")
    .setWrap(true).setBackground("#fff2cc");
  row += 2;
  sheet.getRange(row, 1, 2, 9).merge().setValue("参加者・メモ：\n")
    .setWrap(true).setVerticalAlignment("top");
  row += 2;
  if (note) {
    sheet.getRange(row, 1, 1, 2).merge().setValue("備考").setFontWeight("bold").setBackground("#f3f3f3");
    sheet.getRange(row, 3, 1, 7).merge().setValue(note);
    row++;
  }

  const endRow = row - 1;
  sheet.getRange(startRow, 1, endRow - startRow + 1, 9).setBorder(true, true, true, true, true, true, "#999999", SpreadsheetApp.BorderStyle.SOLID);
  sheet.getRange(bodyStart, 1, Math.max(1, backStart - bodyStart), 9).setBackground(null);
  try { sheet.getRange(startRow, 1, endRow - startRow + 1, 9).setWrap(true); } catch (e) {}
  return row;
}

// 旧名互換。旧呼び出しでも資料形式で出す。
function writeSafetyEducationPrintBlock_(sheet, startRow, material, no) {
  const month = firstDayOfMonth_(material["対象月"] || material["使用月"] || new Date());
  return writeSafetyEducationPrintDocumentBlock_(sheet, startRow, material, no, month);
}

function setSafetyEducationIllustrationCell_(range, illustrationUrl, illustrationText) {
  const url = String(illustrationUrl || "").trim();
  const text = String(illustrationText || "").trim();
  try {
    if (url && /^https?:\/\//i.test(url)) {
      const safeUrl = url.replace(/"/g, '""');
      range.setFormula('=IMAGE("' + safeUrl + '", 1)');
      range.setHorizontalAlignment("center").setVerticalAlignment("middle");
      return;
    }
  } catch (e) {
    // IMAGE関数が使えないURLでも、資料としてURL/案は残す。
  }
  range.setValue(url ? "画像URL: " + url : (text || "イラストなし（文章だけで使用可）"))
    .setWrap(true).setVerticalAlignment("top").setFontSize(10).setBackground("#f6eefc");
}

function formatSafetyEducationPointList_(points) {
  const raw = String(points || "").trim();
  if (!raw) return "・重要ポイントを入力してください。";
  const parts = raw.split(/[／、,\n]+/).map(s => s.trim()).filter(Boolean);
  if (!parts.length) return raw;
  return parts.map(p => "・" + p).join("\n");
}

function buildSafetyEducationChecklistText_(material) {
  const theme = String(material["テーマ"] || material["資料テーマ"] || "").trim();
  const title = String(material["タイトル"] || "").trim();
  const topic = String(material["トピック"] || "").trim();
  const joined = [theme, title, topic, material["重要ポイント"], material["朝礼で話すこと"]].join(" ");
  const checks = [];
  if (/熱中症|WBGT|暑|水分|冷却|休憩/.test(joined)) {
    checks.push("□ WBGT値・気温・湿度を確認した");
    checks.push("□ 休憩場所・水分補給・冷却用品の場所を確認した");
    checks.push("□ 体調不良時の報告先を確認した");
  } else if (/重機|車両|バック|誘導|死角/.test(joined)) {
    checks.push("□ 重機・車両の動線と立入禁止範囲を確認した");
    checks.push("□ 誘導者と運転者の合図を確認した");
    checks.push("□ 死角に入らないことを共有した");
  } else if (/凍結|転倒|足元|滑り/.test(joined)) {
    checks.push("□ 通路・足場・乗降場所の凍結や段差を確認した");
    checks.push("□ 危険箇所を共有し、通行ルートを確認した");
    checks.push("□ 急がず、足元確認を徹底することを共有した");
  } else if (/交通|薄暮|ライト|通勤/.test(joined)) {
    checks.push("□ 車両移動・通勤時の注意点を確認した");
    checks.push("□ 早めのライト点灯・反射材・速度低下を共有した");
    checks.push("□ 誘導合図と歩行者確認を共有した");
  } else {
    checks.push("□ 今日の危険箇所を一つ共有した");
    checks.push("□ 誰が何を確認するか決めた");
    checks.push("□ 異常時の報告先を確認した");
  }
  checks.push("□ 参加者から質問・不明点がないか確認した");
  return checks.join("\n");
}

function getExistingSafetyEducationMaterialKeys_(sheet) {
  const set = new Set();
  if (!sheet || sheet.getLastRow() < 2) return set;
  const headers = getHeaders_(sheet);
  const values = sheet.getRange(2, 1, sheet.getLastRow() - 1, headers.length).getValues();
  values.forEach(v => {
    const r = objectFromRow(headers, v);
    if (!isBusinessDataRow_(headers, v, "安全教育資料集")) return;
    set.add(buildSafetyEducationMaterialKey_(r));
  });
  return set;
}

function buildSafetyEducationMaterialKey_(row) {
  return [
    formatYearMonthKey_(row["対象月"] || row["資料日付"]),
    String(row["資料テーマ"] || "").trim(),
    String(row["資料区分"] || "").trim(),
    String(row["タイトル"] || "").trim()
  ].join("||");
}

function sortSafetyEducationMaterialSheet_() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("安全教育資料集");
  if (!sheet || sheet.getLastRow() < 3) return 0;
  return sortSheetRowsByDateTime_(sheet, ["対象月", "資料日付"], []);
}


function createSafetyEducationP61SheetsPack() {
  const lock = acquireCompanyPackLock_("p61安全教育シート一式");
  if (!lock) return;
  try {
    ensureSafetyEducationMaterialSheet_();
    ensureSafetyEducationThemeMasterSheet_();
    ensureSafetyEducationTopicMasterSheet_();
    ensureSafetyEducationCandidateSheet_();
    ensureSafetyEducationOverviewCheckSheet_();
    ensureSafetyEducationUsageHistorySheet_();
    hideSystemColumnsForSheet_(SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SAFETY_EDUCATION_USAGE_HISTORY_SHEET_NAME));
    toast_("p61d安全教育シート一式を作成/修復しました。トピックマスタ→候補作成→概要チェック→承認済み印刷（1〜3資料・表裏想定）の順で使います。");
  } catch (err) {
    toast_("p61安全教育シート一式でエラー: " + err.message);
    throw err;
  } finally {
    releaseCompanyPackLock_(lock);
  }
}

