function ensureSafetyEducationMaterialSheet_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SAFETY_EDUCATION_MATERIAL_SHEET_NAME);
  if (!sheet) sheet = ss.insertSheet(SAFETY_EDUCATION_MATERIAL_SHEET_NAME);
  setupSheet_(sheet, getSheetHeaders_()[SAFETY_EDUCATION_MATERIAL_SHEET_NAME]);
  updateNoticeColumnForSheet_(sheet);
  formatSheetByName_(SAFETY_EDUCATION_MATERIAL_SHEET_NAME);
  hideSystemColumnsForSheet_(sheet);
  return sheet;
}

function ensureSafetyEducationThemeMasterSheet_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SAFETY_EDUCATION_THEME_MASTER_SHEET_NAME);
  if (!sheet) sheet = ss.insertSheet(SAFETY_EDUCATION_THEME_MASTER_SHEET_NAME);
  setupSheet_(sheet, getSheetHeaders_()[SAFETY_EDUCATION_THEME_MASTER_SHEET_NAME]);
  // p61c: テーママスタも対象月は月パターン文字列として扱う。
  try {
    const headers = getHeaders_(sheet);
    const monthCol = headers.indexOf("対象月") + 1;
    if (monthCol > 0) setTextColumn(sheet, monthCol);
  } catch (e) {
    console.log("安全教育テーママスタ対象月の文字列化をスキップ: " + e.message);
  }

  if (sheet.getLastRow() < 2 || !hasBusinessRows_(sheet)) {
    appendObjectsToSheet_(sheet, buildDefaultSafetyEducationThemeRows_());
  }

  formatSheetByName_(SAFETY_EDUCATION_THEME_MASTER_SHEET_NAME);
  hideSystemColumnsForSheet_(sheet);
  return sheet;
}

