function createSafetyEducationDraftsForCurrentMonth() {
  const today = new Date();
  createSafetyEducationDraftsForMonth_(new Date(today.getFullYear(), today.getMonth(), 1));
}

function createSafetyEducationDraftsForNextMonth() {
  const today = new Date();
  createSafetyEducationDraftsForMonth_(new Date(today.getFullYear(), today.getMonth() + 1, 1));
}

function createSafetyEducationDraftsForPromptMonth() {
  const ui = SpreadsheetApp.getUi();
  const res = ui.prompt(
    "月を指定して安全教育文章案を作成",
    "文章案を作成する対象月を yyyy/mm または yyyy-mm で入力してください。例: 2026/07",
    ui.ButtonSet.OK_CANCEL
  );
  if (res.getSelectedButton() !== ui.Button.OK) return;
  const target = parseYearMonthInput_(res.getResponseText());
  if (!target) {
    ui.alert("対象月の形式が正しくありません。例: 2026/07");
    return;
  }
  createSafetyEducationDraftsForMonth_(target);
}

function createSafetyEducationDraftsForMonth_(targetMonthDate) {
  // p61j:
  // 生成AI/APIは使わず、トピックマスタ・資料候補・使用履歴から文章案を作る。
  // 実処理は既存の「資料候補作成」→「概要チェック反映」を連続実行する。
  const targetMonth = firstDayOfMonth_(targetMonthDate);
  createRandomSafetyEducationCandidatesForMonth_(targetMonth);
  reflectSafetyEducationCandidatesToOverviewCheckForMonth_(targetMonth);
  toast_(formatYearMonthLabel_(targetMonth) + "の安全教育文章案を作成しました。概要チェックで確認し、承認済みにしてください。");
}

