function createRandomSafetyEducationCandidatesForMonth_(targetMonthDate) {
  const lock = acquireCompanyPackLock_("安全教育資料候補ランダム作成");
  if (!lock) return;
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    ensureSafetyEducationMaterialSheet_();
    ensureSafetyEducationThemeMasterSheet_();
    ensureSafetyEducationTopicMasterSheet_();
    const candidateSheet = ensureSafetyEducationCandidateSheet_();
    ensureSafetyEducationOverviewCheckSheet_();
    ensureSafetyEducationUsageHistorySheet_();

    const targetMonth = firstDayOfMonth_(targetMonthDate);
    const themes = getSafetyEducationSelectionRowsForMonth_(targetMonth);
    const sources = getSafetyEducationMaterialSourceRows_(ss);
    const usageInfo = getSafetyEducationUsageInfo_();
    const existingKeys = getExistingSafetyEducationCandidateKeys_(candidateSheet);
    const rows = [];
    let skipped = 0;

    const selectedThemes = themes.slice(0, Math.min(SAFETY_EDUCATION_MONTHLY_PRINT_MAX_ITEMS, Math.max(1, themes.length)));
    selectedThemes.forEach(theme => {
      const candidates = buildSafetyEducationCandidatePoolForTheme_(targetMonth, theme, sources, usageInfo);
      const chosen = chooseSafetyEducationCandidate_(candidates);
      if (!chosen) return;
      const key = buildSafetyEducationCandidateKey_(chosen);
      if (existingKeys.has(key)) {
        skipped++;
        return;
      }
      existingKeys.add(key);
      rows.push(chosen);
    });

    if (rows.length) {
      appendObjectsToSheet_(candidateSheet, rows);
      sortSafetyEducationCandidateSheet_();
      formatSheetByName_(SAFETY_EDUCATION_CANDIDATE_SHEET_NAME);
    }

    toast_(formatYearMonthLabel_(targetMonth) + "の安全教育資料候補を作成しました: 新規 " + rows.length + "件 / 既存スキップ " + skipped + "件。次に概要チェックへ反映してください。");
  } catch (err) {
    toast_("安全教育資料候補ランダム作成でエラー: " + err.message);
    throw err;
  } finally {
    releaseCompanyPackLock_(lock);
  }
}

