function reflectSafetyEducationCandidatesToOverviewCheckForMonth_(targetMonthDate) {
  const lock = acquireCompanyPackLock_("安全教育概要チェック反映");
  if (!lock) return;
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const targetMonth = firstDayOfMonth_(targetMonthDate);
    const candidateSheet = ensureSafetyEducationCandidateSheet_();
    const checkSheet = ensureSafetyEducationOverviewCheckSheet_();
    const existing = getExistingSafetyEducationOverviewCheckKeys_(checkSheet);
    const headers = getHeaders_(candidateSheet);
    const rows = candidateSheet.getLastRow() >= 2
      ? candidateSheet.getRange(2, 1, candidateSheet.getLastRow() - 1, headers.length).getValues().map(v => objectFromRow(headers, v))
      : [];

    const targetKey = formatYearMonthKey_(targetMonth);
    const appendRows = [];
    let skipped = 0;
    rows.forEach(row => {
      if (!isSafetyEducationSameMonth_(row["対象月"], targetKey)) return;
      const status = String(row["状態"] || "").trim();
      if (["不要", "差戻し", "印刷済み"].includes(status)) return;
      const obj = {
        "対象月": targetMonth,
        "テーマ": row["テーマ"] || "",
        "タイトル": row["タイトル"] || "",
        "概要案": row["概要案"] || "",
        "重要ポイント": row["重要ポイント"] || "",
        "朝礼で話すこと": row["朝礼で話すこと"] || "",
        "参考元": row["参考元"] || "",
        "参考URL": row["参考URL"] || "",
        "添付ファイルURL": row["添付ファイルURL"] || "",
        "状態": "確認中",
        "確認者": row["確認者"] || "",
        "確認日": "",
        "差戻し理由": "",
        "備考": row["備考"] || "概要確認後、承認済みにすると印刷対象になります。",
        "安全資料候補ID": row["安全資料候補ID"] || "",
        "トピック": row["トピック"] || "",
        "イラスト案": row["イラスト案"] || buildSafetyEducationIllustrationIdea_(row["テーマ"], row["トピック"], row["タイトル"]),
        "イラスト指示": row["イラスト指示"] || buildSafetyEducationIllustrationPrompt_(row["テーマ"], row["トピック"], row["タイトル"]),
        "イラストURL": row["イラストURL"] || "",
        "イラスト状態": row["イラスト状態"] || "案作成",
        "安全概要チェックID": buildRecordId_(SAFETY_EDUCATION_OVERVIEW_CHECK_SHEET_NAME)
      };
      const key = buildSafetyEducationOverviewCheckKey_(obj);
      if (existing.has(key)) {
        skipped++;
        return;
      }
      existing.add(key);
      appendRows.push(obj);
    });

    if (appendRows.length) {
      appendObjectsToSheet_(checkSheet, appendRows);
      updateNoticeColumnForSheet_(checkSheet);
      sortSafetyEducationOverviewCheckSheet_();
      formatSheetByName_(SAFETY_EDUCATION_OVERVIEW_CHECK_SHEET_NAME);
    }

    createScheduleList();
    createAlertList();
    toast_(formatYearMonthLabel_(targetMonth) + "の候補を概要チェックへ反映しました: 新規 " + appendRows.length + "件 / 既存スキップ " + skipped + "件");
  } catch (err) {
    toast_("安全教育概要チェック反映でエラー: " + err.message);
    throw err;
  } finally {
    releaseCompanyPackLock_(lock);
  }
}

