function createSafetyEducationIllustrationPromptsForPromptMonth() {
  const ui = SpreadsheetApp.getUi();
  const res = ui.prompt(
    "安全教育イラスト案を作成",
    "イラスト案を作成する対象月を yyyy/mm または yyyy-mm で入力してください。例: 2026/07\n\n※画像そのものは生成せず、資料に貼るイラスト案・画像生成用指示・URL欄を整えます。",
    ui.ButtonSet.OK_CANCEL
  );
  if (res.getSelectedButton() !== ui.Button.OK) return;
  const target = parseYearMonthInput_(res.getResponseText());
  if (!target) {
    ui.alert("対象月の形式が正しくありません。例: 2026/07");
    return;
  }
  createSafetyEducationIllustrationPromptsForMonth_(target);
}

function createSafetyEducationIllustrationPromptsForMonth_(targetMonthDate) {
  const lock = acquireCompanyPackLock_("安全教育イラスト案作成");
  if (!lock) return;
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const targetMonth = firstDayOfMonth_(targetMonthDate);
    const targetKey = formatYearMonthKey_(targetMonth);
    const targets = [
      ensureSafetyEducationCandidateSheet_(),
      ensureSafetyEducationOverviewCheckSheet_(),
      ensureSafetyEducationMaterialSheet_()
    ];
    let updated = 0;
    targets.forEach(sheet => {
      updated += fillSafetyEducationIllustrationPromptsForSheet_(sheet, targetKey);
      formatSheetByName_(sheet.getName());
    });
    toast_(formatYearMonthLabel_(targetMonth) + "の安全教育イラスト案を作成しました: " + updated + "件。イラストURLは作成後に手入力/貼り付けしてください。");
  } catch (err) {
    toast_("安全教育イラスト案作成でエラー: " + err.message);
    throw err;
  } finally {
    releaseCompanyPackLock_(lock);
  }
}

function fillSafetyEducationIllustrationPromptsForSheet_(sheet, targetKey) {
  if (!sheet || sheet.getLastRow() < 2) return 0;
  const headers = getHeaders_(sheet);
  const monthCol = headers.indexOf("対象月") + 1;
  const themeCol = Math.max(headers.indexOf("テーマ") + 1, headers.indexOf("資料テーマ") + 1);
  const topicCol = headers.indexOf("トピック") + 1;
  const titleCol = headers.indexOf("タイトル") + 1;
  const ideaCol = headers.indexOf("イラスト案") + 1;
  const promptCol = headers.indexOf("イラスト指示") + 1;
  const statusCol = headers.indexOf("イラスト状態") + 1;
  if (monthCol <= 0 || titleCol <= 0 || ideaCol <= 0 || promptCol <= 0) return 0;

  const range = sheet.getRange(2, 1, sheet.getLastRow() - 1, headers.length);
  const values = range.getValues();
  let updated = 0;
  values.forEach((row, index) => {
    const obj = objectFromRow(headers, row);
    if (!isBusinessDataRow_(headers, row, sheet.getName())) return;
    if (formatYearMonthKey_(obj["対象月"]) !== targetKey) return;
    const theme = themeCol > 0 ? obj[headers[themeCol - 1]] : "";
    const topic = topicCol > 0 ? obj["トピック"] : "";
    const title = obj["タイトル"] || topic || theme || "安全教育";
    let changed = false;
    if (!String(obj["イラスト案"] || "").trim()) {
      row[ideaCol - 1] = buildSafetyEducationIllustrationIdea_(theme, topic, title);
      changed = true;
    }
    if (!String(obj["イラスト指示"] || "").trim()) {
      row[promptCol - 1] = buildSafetyEducationIllustrationPrompt_(theme, topic, title);
      changed = true;
    }
    if (statusCol > 0 && !String(obj["イラスト状態"] || "").trim()) {
      row[statusCol - 1] = "案作成";
      changed = true;
    }
    if (changed) updated++;
  });
  if (updated) range.setValues(values);
  return updated;
}

function buildSafetyEducationIllustrationIdea_(theme, topic, title) {
  const t = String(topic || title || theme || "安全教育").trim();
  return t + "を一目で説明する、現場向けのシンプルな注意喚起イラスト";
}

function buildSafetyEducationIllustrationPrompt_(theme, topic, title) {
  const themeText = String(theme || "安全教育").trim();
  const topicText = String(topic || title || themeText).trim();
  return "建設現場の安全教育資料に使う、" + topicText + "を説明するシンプルで分かりやすいイラスト。作業員はヘルメットと安全ベストを着用。危険行動ではなく安全な確認・声かけ・対策をしている場面。社内資料向け、落ち着いた説明図、文字やロゴは入れない。テーマ: " + themeText;
}

function ensureMinimumColumns_(sheet, minCols) {
  const current = sheet.getMaxColumns();
  if (current < minCols) sheet.insertColumnsAfter(current, minCols - current);
}

function ensureMinimumRows_(sheet, minRows) {
  const current = sheet.getMaxRows();
  if (current < minRows) sheet.insertRowsAfter(current, minRows - current);
}

function createEstimateSheet() {
  const sheet = ensureEstimateSheet_();
  toast_("見積書シートを作成/修復しました。列順は 件名/依頼主/場所/金額/税/提出年月日/工事内容/状態/通知/既読 です。");
  return sheet;
}

function ensureEstimateSheet_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("見積書");
  if (!sheet) sheet = ss.insertSheet("見積書");

  // p61cc-p61ce: 旧「日時」または「日付」列が残っている場合は、提出年月日へ移行してからヘッダーと入力規則を貼る。
  migrateEstimateDateTimeColumnToDateAndTime_(sheet);

  const headers = getSheetHeaders_()["見積書"];
  setupSheet_(sheet, headers);
  applyEstimateSheetSpecificSettings_(sheet);
  updateNoticeColumnForSheet_(sheet);
  ensureIdsForSheet_(sheet);
  setCheckboxesForDataRows(sheet);
  formatSheetByName_("見積書");
  hideSystemColumnsForSheet_(sheet);
  return sheet;
}

function getEstimateStatusList_() {
  // p61cd: 日常入力で迷わないよう、見積状態は3つだけに絞る。
  return [CLEAR_LABEL, "提出依頼", "提出済み", "返答待ち"];
}

function normalizeEstimateStatus_(value) {
  const s = String(value || "").trim();
  if (!s || s === CLEAR_LABEL || s === "空欄" || s === "空欄に戻す") return "";

  // 自社側でまだ提出・修正作業が残る旧値は「提出依頼」へ寄せる。
  if (["作成中", "未提出", "提出待ち", "提出依頼", "差戻し", "差し戻し", "修正", "修正依頼"].includes(s)) return "提出依頼";

  // 相手の返事待ちは、プルダウン表示を「返答待ち」に統一する。
  if (["返答待ち", "回答待ち", "相手待ち"].includes(s)) return "返答待ち";

  // 見積として結果が出た旧値は、3択運用では提出済み側へ寄せる。結果詳細は必要なら備考へ残す。
  if (["提出済", "提出済み", "完了", "受注", "成約", "失注", "不成約"].includes(s)) return "提出済み";

  // 3択から外した中止・不要系は通知対象外として空欄へ戻す。
  if (["中止", "不要", "対象外"].includes(s)) return "";

  return s;
}

function isMeaningfulEstimateRow_(row) {
  if (!row) return false;
  return ["件名", "依頼主", "場所", "金額", "税", "提出年月日", "日付", "日時", "工事内容", "備考", "状態"].some(header => {
    const value = row[header];
    if (value instanceof Date && !isNaN(value.getTime())) return true;
    return String(value || "").trim() !== "";
  });
}

function getEstimateNoticeText_(row) {
  if (!isMeaningfulEstimateRow_(row)) return "";
  const status = normalizeEstimateStatus_(row["状態"]);
  if (status === "提出依頼") return "要確認";
  if (["提出済み", "返答待ち"].includes(status)) return "完了";

  // 状態が空欄なら通知も空欄。要確認にしたい見積は「提出依頼」を選ぶ。
  if (!status) return "";

  // 想定外の状態が手入力された場合は、見落とし防止で要確認。
  return "要確認";
}

function shouldIncludeEstimateInSchedule_(row) {
  if (!isMeaningfulEstimateRow_(row)) return false;

  const status = normalizeEstimateStatus_(row["状態"]);
  const notice = getEstimateNoticeText_(row);

  // p61cn: 提出済み・返答待ちは通知上「完了」なので一覧スケジュールへ出さない。
  // 返答待ちは見積書シート内の手動整理で提出依頼の次に残して確認する。
  if (["提出済み", "返答待ち"].includes(status)) return false;
  if (notice === "完了") return false;

  // 提出依頼、または想定外手入力で要確認になったものだけ一覧へ出す。
  return notice === "要確認";
}

function migrateEstimateDateTimeColumnToDateAndTime_(sheet) {
  if (!sheet || sheet.getName() !== "見積書") return;

  const oldHeaders = getHeaders_(sheet);
  if (!oldHeaders.length) return;

  const newHeaders = getSheetHeaders_()["見積書"];
  const oldDateTimeIndex = oldHeaders.indexOf("日時");

  // p61cc-p61ce: p44の「日時」列、p45/p46の「日付」「時間」列、税列追加、見積書列順変更などを、ヘッダー名基準で安全に再配置する。
  const sameOrder = newHeaders.length === oldHeaders.length && newHeaders.every((header, i) => oldHeaders[i] === header);
  if (sameOrder && oldDateTimeIndex < 0) return;

  const lastRow = sheet.getLastRow();
  const oldColCount = Math.max(oldHeaders.length, sheet.getLastColumn());
  const newColCount = newHeaders.length;
  const rowCount = Math.max(lastRow - 1, 0);
  const migratedRows = [];

  if (rowCount > 0) {
    const values = sheet.getRange(2, 1, rowCount, oldColCount).getValues();
    values.forEach(rowValues => {
      const oldObj = objectFromRow(oldHeaders, rowValues);
      const newObj = {};

      newHeaders.forEach(header => {
        if (header === "提出年月日") {
          newObj[header] = oldObj["提出年月日"] || oldObj["日付"] || toDateOnly_(oldObj["日時"]);
        } else if (header === "税") {
          newObj[header] = oldObj["税"] || oldObj["税区分"] || extractTaxLabelFromAmount_(oldObj["金額"]);
        } else if (header === "金額") {
          newObj[header] = normalizeConstructionAmountValue_(oldObj["金額"]);
        } else if (header === "状態") {
          newObj[header] = normalizeEstimateStatus_(oldObj["状態"]);
        } else {
          const value = oldObj[header];
          newObj[header] = value === undefined || value === null ? "" : value;
        }
      });

      const hasAnyValue = newHeaders.some(header => {
        const value = newObj[header];
        return value !== "" && value !== null && value !== undefined;
      });
      if (hasAnyValue) migratedRows.push(newObj);
    });
  }

  try { removeFilter_(sheet); } catch (e) {}
  ensureColumns_(sheet, Math.max(oldColCount, newColCount));

  // 旧列の内容を一度消してから、新しい列順で戻す。
  // 列削除はしないが、旧「時間」列は新ヘッダーへ戻さないため日常入力項目から外れる。
  const clearCols = Math.max(oldColCount, newColCount);
  sheet.getRange(1, 1, Math.max(rowCount + 1, 1), clearCols).clearContent();
  sheet.getRange(1, 1, 1, newColCount).setValues([newHeaders]);

  if (migratedRows.length) {
    const out = migratedRows.map(obj => newHeaders.map(header => {
      const value = obj[header];
      return value === undefined || value === null ? "" : value;
    }));
    sheet.getRange(2, 1, out.length, newColCount).setValues(out);
  }
}

function applyEstimateSheetSpecificSettings_(sheet) {
  if (!sheet || sheet.getName() !== "見積書") return;

  const headers = getHeaders_(sheet);
  const rowCount = getApplyRowCount_(sheet);

  const amountCol = headers.indexOf("金額") + 1;
  const taxCol = headers.indexOf("税") + 1;
  const dateCol = headers.indexOf("提出年月日") + 1;
  const oldDateCol = headers.indexOf("日付") + 1;
  const timeCol = headers.indexOf("時間") + 1;
  const statusCol = headers.indexOf("状態") + 1;

  if (amountCol > 0) {
    sheet.getRange(2, amountCol, rowCount, 1)
      .setNumberFormat("¥#,##0")
      .clearDataValidations();
  }

  if (taxCol > 0) {
    const taxRule = SpreadsheetApp.newDataValidation()
      .requireValueInList([CLEAR_LABEL, "税込", "税抜", "不明"], true)
      .setAllowInvalid(false)
      .build();
    sheet.getRange(2, taxCol, rowCount, 1).setDataValidation(taxRule);
  }

  const targetDateCol = dateCol > 0 ? dateCol : oldDateCol;
  if (targetDateCol > 0) {
    const dateRule = SpreadsheetApp.newDataValidation()
      .requireDate()
      .setAllowInvalid(false)
      .build();
    sheet.getRange(2, targetDateCol, rowCount, 1)
      .setNumberFormat("yyyy/mm/dd")
      .setDataValidation(dateRule);
  }

  // p61cc-p61ce: 旧「時間」列が残っていても、入力規則は貼らず日常入力では使わない。
  if (timeCol > 0) {
    sheet.getRange(2, timeCol, rowCount, 1).clearDataValidations();
  }

  if (statusCol > 0) {
    normalizeEstimateStatusColumnForDropdown_(sheet, statusCol, rowCount);
    const statusRule = SpreadsheetApp.newDataValidation()
      .requireValueInList(getEstimateStatusList_(), true)
      .setAllowInvalid(false)
      .build();
    sheet.getRange(2, statusCol, rowCount, 1).setDataValidation(statusRule);
  }
}

function normalizeEstimateStatusColumnForDropdown_(sheet, statusCol, rowCount) {
  if (!sheet || statusCol <= 0 || rowCount <= 0) return;
  const range = sheet.getRange(2, statusCol, rowCount, 1);
  const values = range.getValues();
  let changed = false;
  const normalized = values.map(row => {
    const before = row[0];
    const after = normalizeEstimateStatus_(before);
    if (String(before || "") !== String(after || "")) changed = true;
    return [after];
  });
  if (changed) range.setValues(normalized);
}

function getEstimateScheduleDateTime_(rowObj) {
  return toDateOnly_(rowObj["提出年月日"] || rowObj["日付"] || rowObj["日時"]);
}

function combineDateAndTimeForSheet_(dateValue, timeValue) {
  const d = toDateOnly_(dateValue);
  if (!d) return null;

  const hm = extractHourMinuteForSheet_(timeValue);
  if (hm) d.setHours(hm.hour, hm.minute, 0, 0);
  return d;
}

function extractTimeForSheet_(value) {
  const hm = extractHourMinuteForSheet_(value);
  if (!hm) return "";
  return Utilities.formatString("%02d:%02d", hm.hour, hm.minute);
}

function extractHourMinuteForSheet_(value) {
  if (!value) return null;

  if (value instanceof Date && !isNaN(value.getTime())) {
    const hour = value.getHours();
    const minute = value.getMinutes();
    if (hour || minute) return {hour: hour, minute: minute};
    return null;
  }

  const text = String(value || "").trim();
  const m = text.match(/(\d{1,2})[:：](\d{2})/);
  if (!m) return null;

  const hour = Number(m[1]);
  const minute = Number(m[2]);
  if (isNaN(hour) || isNaN(minute)) return null;
  if (hour < 0 || hour > 23 || minute < 0 || minute > 59) return null;
  return {hour: hour, minute: minute};
}

