function getPhoneHistoryInternalTailHeaders_() {
  // p61bw: 「通知」は日常確認用として表示するため、非表示対象から外す。
  return [
    PHONE_MOBILE_NOTIFY_HEADER,
    PHONE_MOBILE_MESSAGE_HEADER,
    PHONE_NOTIFY_TO_HEADER,
    PHONE_NOTIFY_EMAIL_HEADER,
    PHONE_NOTIFY_METHOD_HEADER,
    PHONE_EMAIL_NOTIFY_HEADER,
    PHONE_EMAIL_SENT_AT_HEADER,
    "電話ID"
  ];
}

function isPhoneHistoryInternalTailHeader_(header) {
  const h = String(header || "").trim();
  return getPhoneHistoryInternalTailHeaders_().indexOf(h) >= 0;
}

function repairPhoneHistoryNotificationTailLayout() {
  const lock = acquireCompanyPackLock_("電話履歴：通知表示＋既読グループ復旧");
  if (!lock) return;
  try {
    const result = repairPhoneHistoryNotificationTailLayout_();
    toast_("電話履歴の通知系を最後尾へ移動し、内部列として非表示にしました（完了チェック:" + (result.doneRows || 0) + "行 / 通知更新:" + (result.mobileRows || 0) + "行 / 通知先更新:" + (result.notifyRows || 0) + "行）。");
  } catch (err) {
    toast_("電話履歴の通知系整理でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function repairPhoneHistoryNotificationTailLayout_(sheet) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  if (!sheet) sheet = ss.getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {reordered: false, doneRows: 0, mobileRows: 0, notifyRows: 0};

  // 期待ヘッダー順をp61bdの「日常入力列 → 内部通知列」へ寄せる。
  ensureSheetHeadersPreserveData_("電話履歴");
  sheet = ss.getSheetByName("電話履歴");

  let doneRows = 0;
  let mobileRows = 0;
  let notifyRows = 0;
  try {
    const done = repairPhoneHistoryDoneCheckColumn_(sheet);
    doneRows = done.rows || 0;
  } catch (e) {
    console.log("電話履歴通知系整理: 完了チェック修復をスキップ: " + e.message);
  }
  try {
    const mobile = repairPhoneHistoryMobileNotifyColumns_(sheet);
    mobileRows = mobile.updated || 0;
  } catch (e) {
    console.log("電話履歴通知系整理: スマホ通知列修復をスキップ: " + e.message);
  }
  try {
    const notify = repairPhoneHistoryNotifyRecipientColumns_(sheet);
    notifyRows = notify.updated || 0;
  } catch (e) {
    console.log("電話履歴通知系整理: 通知先列修復をスキップ: " + e.message);
  }
  try { deleteDeprecatedPhoneHistoryStatusColumns_(sheet); } catch (e) {}
  try { repairPhoneHistoryStatusDropdown_(sheet); } catch (e) {}
  try { applyPhoneHistoryDirectInputLayout_(); } catch (e) {}
  try { rebuildPersonalCheckGroupForSheet_(sheet); } catch (e) {}
  try { hidePhoneHistoryInternalColumnsUltraLight_(sheet); } catch (e) {}
  try { showPhoneHistoryNoticeColumn_(sheet); } catch (eShow) {}
  try { createFilterSafely_(sheet, sheet.getLastColumn()); } catch (e) {}
  return {reordered: true, doneRows: doneRows, mobileRows: mobileRows, notifyRows: notifyRows};
}


function repairPhoneHistoryDisplayOnlyPack() {
  const lock = acquireCompanyPackLock_("電話履歴の表示だけ超軽量修復");
  if (!lock) return;
  try {
    const result = repairPhoneHistoryDisplayOnlyPack_();
    toast_("電話履歴の表示だけ超軽量修復しました（対象:" + (result.scanned || 0) + "行 / チェック復旧:" + (result.fixed || 0) + "セル / 空行掃除:" + (result.cleared || 0) + "セル / 内部列非表示:" + (result.hiddenColumns || 0) + "列）。新着・通知の再計算は別メニューです。");
  } catch (err) {
    toast_("電話履歴の表示だけ超軽量修復でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function repairPhoneHistoryDisplayOnlyPack_(sheet) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  if (!sheet) sheet = ss.getSheetByName("電話履歴");
  const result = {scanned: 0, fixed: 0, cleared: 0, hiddenColumns: 0, created: 0};
  if (!sheet || sheet.getName() !== "電話履歴") return result;

  // p61bh:
  // 日常用の超軽量処理。全行の新着/通知再計算や列移動はしない。
  // 目的は「FALSE/TRUEが文字で見える」「内部列が見えてしまった」だけを短時間で戻すこと。
  const ensure = ensurePhoneHistoryDoneCheckColumnHeaderOnly_(sheet);
  result.created = ensure.created || 0;
  const doneCol = ensure.col || 0;
  if (doneCol > 0) {
    const repaired = repairPhoneHistoryDoneCheckDisplayOnly_(sheet, doneCol);
    result.scanned = repaired.scanned || 0;
    result.fixed = repaired.fixed || 0;
    result.cleared = repaired.cleared || 0;
  }

  try {
    result.hiddenColumns = hidePhoneHistoryInternalColumnsUltraLight_(sheet);
    try { showPhoneHistoryNoticeColumn_(sheet); } catch (eShow) {}
  } catch (e) {
    console.log("電話履歴表示だけ超軽量修復: 内部列非表示をスキップ: " + e.message);
  }

  try {
    if (doneCol > 0) {
      sheet.getRange(1, doneCol)
        .setFontWeight("bold")
        .setHorizontalAlignment("center")
        .setVerticalAlignment("middle")
        .setWrap(true)
        .setBackground("#d9ead3")
        .setFontColor("#274e13");
    }
  } catch (e) {}

  return result;
}

function ensurePhoneHistoryDoneCheckColumnHeaderOnly_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return {col: 0, created: 0};
  let headers = getHeaders_(sheet);
  let doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  if (doneCol > 0) return {col: doneCol, created: 0};

  // 超軽量版では、旧操作列の統合や全行同期はしない。列が無い時だけヘッダーを追加する。
  let insertAfterCol = headers.indexOf("担当") + 1;
  if (insertAfterCol <= 0) insertAfterCol = headers.indexOf("内容") + 1;
  if (insertAfterCol <= 0) insertAfterCol = headers.indexOf("電話対応") + 1;
  if (insertAfterCol <= 0) insertAfterCol = Math.max(headers.length, 1);

  sheet.insertColumnAfter(insertAfterCol);
  doneCol = insertAfterCol + 1;
  sheet.getRange(1, doneCol).setValue(PHONE_DONE_CHECK_HEADER);
  return {col: doneCol, created: 1};
}

function repairPhoneHistoryDoneCheckDisplayOnly_(sheet, doneCol) {
  const result = {scanned: 0, fixed: 0, cleared: 0};
  if (!sheet || sheet.getName() !== "電話履歴" || doneCol <= 0) return result;

  const headers = getHeaders_(sheet);
  if (!headers.length) return result;

  const ranges = getPhoneHistoryDisplayOnlyScanRanges_(sheet);
  ranges.forEach(function(part) {
    const startRow = part.start;
    const endRow = part.end;
    if (endRow < startRow) return;

    const rowCount = endRow - startRow + 1;
    const rowValues = sheet.getRange(startRow, 1, rowCount, headers.length).getValues();
    const doneRange = sheet.getRange(startRow, doneCol, rowCount, 1);
    const doneValues = doneRange.getValues();
    const validations = doneRange.getDataValidations();

    for (let i = 0; i < rowCount; i++) {
      const row = startRow + i;
      const rowObj = objectFromRow(headers, rowValues[i]);
      const meaningful = isMeaningfulPhoneHistoryRowObject_(rowObj);
      const raw = doneValues[i][0];
      const rawText = String(raw || "").toUpperCase();
      const hasCheckbox = isCheckboxValidationRule_(validations[i] && validations[i][0]);
      const looksBoolean = raw === true || raw === false || rawText === "TRUE" || rawText === "FALSE";
      result.scanned++;

      if (!meaningful) {
        if (raw !== "" || hasCheckbox) {
          sheet.getRange(row, doneCol).clearContent().clearDataValidations();
          result.cleared++;
        }
        continue;
      }

      if (!hasCheckbox) {
        const cell = sheet.getRange(row, doneCol);
        const checked = raw === true || rawText === "TRUE";
        cell.insertCheckboxes();
        cell.setValue(looksBoolean ? checked : false);
        result.fixed++;
      }
    }
  });

  return result;
}

function getPhoneHistoryDisplayOnlyScanRanges_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return [];
  const maxRows = Math.max(sheet.getMaxRows(), 2);
  const lastRow = Math.max(sheet.getLastRow(), 2);
  const topEnd = Math.min(maxRows, Math.max(2, Math.min(Math.max(lastRow + 10, 80), PHONE_DISPLAY_ONLY_REPAIR_MAX_ROWS)));
  const ranges = [{start: 2, end: topEnd}];

  // 選択中の行が下の方にある場合だけ、その周辺も小さく見る。
  // 全行スキャンはしないため、大量行でも日常用は軽いままにする。
  try {
    const activeRange = sheet.getActiveRange();
    const activeRow = activeRange ? activeRange.getRow() : 0;
    if (activeRow > topEnd && activeRow <= maxRows) {
      const start = Math.max(2, activeRow - PHONE_DISPLAY_ONLY_REPAIR_ACTIVE_MARGIN);
      const end = Math.min(maxRows, activeRow + PHONE_DISPLAY_ONLY_REPAIR_ACTIVE_MARGIN);
      ranges.push({start: start, end: end});
    }
  } catch (e) {}

  return mergeRowRanges_(ranges);
}

function mergeRowRanges_(ranges) {
  const sorted = (ranges || [])
    .filter(function(r) { return r && r.start <= r.end; })
    .sort(function(a, b) { return a.start - b.start; });
  const merged = [];
  sorted.forEach(function(r) {
    if (!merged.length || r.start > merged[merged.length - 1].end + 1) {
      merged.push({start: r.start, end: r.end});
    } else {
      merged[merged.length - 1].end = Math.max(merged[merged.length - 1].end, r.end);
    }
  });
  return merged;
}

function hidePhoneHistoryInternalColumnsUltraLight_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  const headers = getHeaders_(sheet);
  let hidden = 0;
  getPhoneHistoryInternalTailHeaders_().forEach(function(header) {
    const col = headers.indexOf(header) + 1;
    if (col <= 0) return;
    try {
      if (!sheet.isColumnHiddenByUser(col)) {
        sheet.hideColumns(col);
        hidden++;
      }
    } catch (e) {
      try {
        sheet.hideColumns(col);
        hidden++;
      } catch (e2) {}
    }
  });
  return hidden;
}

function showPhoneHistoryNoticeColumn_(sheet) {
  // p61bw: 通知列は日常確認対象なので、過去版で非表示になっていても表示へ戻す。
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  const headers = getHeaders_(sheet);
  const col = headers.indexOf("通知") + 1;
  if (col <= 0) return 0;
  try {
    sheet.showColumns(col);
    try { sheet.setColumnWidth(col, 76); } catch (e2) {}
    return 1;
  } catch (e) {
    return 0;
  }
}



