function repairPhoneHistorySelectedRowQuickPack_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getActiveSheet();
  if (!sheet || sheet.getName() !== "電話履歴") return {scanned: 0, updated: 0, cleared: 0, checkboxFixed: 0, noActivePhoneSheet: true};
  const active = sheet.getActiveRange();
  if (!active || active.getRow() <= 1) return {scanned: 0, updated: 0, cleared: 0, checkboxFixed: 0, noActivePhoneSheet: true};
  const start = Math.max(2, active.getRow());
  const end = Math.max(start, active.getRow() + active.getNumRows() - 1);
  return repairPhoneHistoryRowsQuickPack_(sheet, [{start: start, end: end}], {label: "selected"});
}

