function repairPhoneHistoryDirectInputLightPack_(sheet) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  if (!sheet) sheet = ss.getSheetByName("電話履歴");
  const result = {
    doneRows: 0,
    doneCleaned: 0,
    newRows: 0,
    mobileRows: 0,
    notifyRows: 0,
    layout: false
  };
  if (!sheet || sheet.getName() !== "電話履歴") return result;

  // p61bf:
  // 日常向け軽量修復。電話履歴内だけを対象にし、全シート検査・列移動・ガイド再作成は行わない。
  // FALSE表示、未着手印、AppSheet/メール通知判定、内部列非表示を短時間で戻す用途。
  try {
    const done = repairPhoneHistoryDoneCheckColumn_(sheet);
    result.doneRows = done.rows || 0;
    result.doneCleaned = done.cleaned || 0;
  } catch (e) {
    console.log("電話履歴軽量修復: 完了チェック修復をスキップ: " + e.message);
  }

  try {
    const marks = repairPhoneHistoryNewMarks_();
    result.newRows = marks.updated || 0;
  } catch (e) {
    console.log("電話履歴軽量修復: 新着印再計算をスキップ: " + e.message);
  }

  try {
    const mobile = repairPhoneHistoryMobileNotifyColumns_(sheet);
    result.mobileRows = mobile.updated || 0;
  } catch (e) {
    console.log("電話履歴軽量修復: スマホ通知再計算をスキップ: " + e.message);
  }

  try {
    const notify = repairPhoneHistoryNotifyRecipientColumns_(sheet);
    result.notifyRows = notify.updated || 0;
  } catch (e) {
    console.log("電話履歴軽量修復: 通知先再計算をスキップ: " + e.message);
  }

  try {
    result.layout = applyPhoneHistoryDirectInputLayoutLight_(sheet);
  } catch (e) {
    console.log("電話履歴軽量修復: 表示整理をスキップ: " + e.message);
  }

  return result;
}

