function applyPhoneHistoryDirectInputLayoutLight_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return false;

  const headers = getHeaders_(sheet);
  if (!headers.length) return false;

  // 内部列は非表示へ戻す。列移動は重いためここでは行わない。
  getPhoneHistoryInternalTailHeaders_().forEach(function(header) {
    const col = headers.indexOf(header) + 1;
    if (col > 0) {
      try { sheet.hideColumns(col); } catch (e) {}
    }
  });

  // 日常入力列は表示へ戻す。
  const showHeaders = uniqueList_([
    PHONE_NEW_MARK_HEADER,
    "日付",
    "時間",
    "相手",
    "折り返し電話番号",
    "内容",
    "担当",
    PHONE_DONE_CHECK_HEADER,
    "通知",
    "対応メモ"
  ].concat(getCheckboxHeadersForSheet_(sheet), ["備考"]));

  showHeaders.forEach(function(header) {
    const col = headers.indexOf(header) + 1;
    if (col > 0) {
      try { sheet.showColumns(col); } catch (e) {}
    }
  });

  try {
    const widths = {
      "新着": 34,
      "日付": 95,
      "時間": 65,
      "相手": 160,
      "折り返し電話番号": 125,
      "内容": 260,
      "担当": 100,
      "完了チェック": 62,
      "通知": 76,
      "対応メモ": 240,
      "既読": 42,
      "備考": 220
    };
    headers.forEach(function(header, index) {
      const width = widths[String(header || "")];
      if (width) sheet.setColumnWidth(index + 1, width);
    });
  } catch (e) {}

  return true;
}

