function formatSheetDirectInputGuideSheet_(sheet, rowCount, colCount) {
  if (!sheet) return;
  try {
    sheet.setFrozenRows(1);
    sheet.getRange(1, 1, 1, colCount)
      .setBackground("#d9ead3")
      .setFontWeight("bold")
      .setHorizontalAlignment("center")
      .setVerticalAlignment("middle");
    if (rowCount > 1) {
      sheet.getRange(2, 1, rowCount - 1, colCount).setVerticalAlignment("middle").setWrap(true);
    }
    sheet.setColumnWidth(1, 130);
    sheet.setColumnWidth(2, 180);
    sheet.setColumnWidth(3, 220);
    sheet.setColumnWidth(4, 360);
    sheet.setColumnWidth(5, 420);
    createFilterSafely_(sheet, colCount);
  } catch (e) {
    console.log("シート直接入力ガイド整形をスキップ: " + e.message);
  }
}

function applyPhoneHistoryDirectInputLayout_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("電話履歴");
  if (!sheet) return false;

  // p61bv: 電話履歴だけを対象に、通知系の古い列グループを解除し、後で既読グループだけ復旧する。
  try { clearColumnGroupsForSheet_(sheet); } catch (e0) {}
  try { repairPhoneHistoryDoneCheckColumn_(sheet); } catch (e) {}
  try { deleteDeprecatedPhoneHistoryStatusColumns_(sheet); } catch (eDel) {}
  try { repairPhoneHistoryNewMarks_(); } catch (e) {}
  let headers = getHeaders_(sheet);
  if (!headers.length) return false;

  const hideHeaders = getPhoneHistoryInternalTailHeaders_();

  // p61bd: 通知列・AppSheet通知列・メール通知列は削除せず、最後尾の内部列として非表示にする。
  hideHeaders.forEach(function(header) {
    const col = headers.indexOf(header) + 1;
    if (col > 0) {
      try { sheet.hideColumns(col); } catch (e) {}
    }
  });

  const showHeaders = uniqueList_([
    PHONE_NEW_MARK_HEADER,
    "日付",
    "時間",
    "相手",
    "折り返し電話番号",
    "内容",
    "担当",
    PHONE_DONE_CHECK_HEADER,
    "通知",
    "対応メモ"
  ].concat(getCheckboxHeadersForSheet_(sheet), ["備考"]));
  showHeaders.forEach(function(header) {
    const col = headers.indexOf(header) + 1;
    if (col > 0) {
      try { sheet.showColumns(col); } catch (e) {}
    }
  });

  try {
    const widths = {
      "新着": 34,
      "日付": 95,
      "時間": 65,
      "相手": 160,
      "折り返し電話番号": 125,
      "内容": 260,
      "担当": 100,
      "完了チェック": 62,
      "通知": 76,
      "対応メモ": 240,
      "既読": 42,
      "備考": 220
    };
    headers.forEach(function(header, index) {
      const width = widths[String(header || "")];
      if (width) sheet.setColumnWidth(index + 1, width);
    });
  } catch (e) {}

  try { hideSystemColumnsForSheet_(sheet); } catch (e) {}
  try { rebuildPersonalCheckGroupForSheet_(sheet); } catch (e2) {}
  try { hidePhoneHistoryInternalColumnsUltraLight_(sheet); } catch (e3) {}
  return true;
}

