function repairSharedSheetNoColumnGroups() {
  const lock = acquireCompanyPackLock_("電話履歴：通知表示＋既読グループ復旧");
  if (!lock) return;
  try {
    const result = repairSharedSheetNoColumnGroups_();
    toast_("電話履歴の通知列を表示し、内部通知列を非表示に戻して既読グループを復旧しました（対象:" + result.sheets + "シート / 不要列削除:" + (result.deleted || 0) + "列 / グループ解除:" + result.groups + "回 / 非表示:" + result.hidden + "列 / 既読グループ:" + result.personalGroups + "件）。");
    return result;
  } catch (err) {
    toast_("電話履歴の通知表示＋既読グループ復旧でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

function repairSharedSheetNoColumnGroups_() {
  // p61bv:
  // 全シートのグループ解除は行わない。
  // 対象は電話履歴だけに限定し、旧「電話対応」「対応完了日時」を削除、「通知」は表示、その他通知系は非表示、最後に既読グループだけ復旧する。
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const result = {sheets: 0, groups: 0, hidden: 0, personalGroups: 0, deleted: 0};
  const sheet = ss.getSheetByName("電話履歴");
  if (!sheet) return result;

  result.sheets = 1;
  try { ensurePhoneHistoryDoneCheckColumn_(sheet); } catch (e0) {}
  try { result.deleted += deleteDeprecatedPhoneHistoryStatusColumns_(sheet) || 0; } catch (e1) {}
  try { result.groups += clearColumnGroupsForSheet_(sheet) || 0; } catch (e2) {}
  try { result.hidden += hidePhoneHistoryInternalColumnsUltraLight_(sheet) || 0; } catch (e3) {}
  try { showPhoneHistoryNoticeColumn_(sheet); } catch (eShow) {}
  try { result.hidden += hideSystemColumnsForSheet_(sheet) || 0; } catch (e4) {}
  try { result.personalGroups += createPersonalCheckColumnGroupForSheet_(sheet) || 0; } catch (e5) {}
  try { createFilterSafely_(sheet, sheet.getLastColumn()); } catch (e6) {}
  return result;
}

function deleteDeprecatedPhoneHistoryStatusColumns_(sheet) {
  // p61bv:
  // 電話履歴では「完了チェック」と「対応メモ」を正にするため、旧内部列の電話対応/対応完了日時は不要。
  // 右から削除して列ズレを防ぐ。
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  const removeHeaders = ["対応完了日時", "電話対応"];
  let removed = 0;
  let headers = getHeaders_(sheet);
  removeHeaders
    .map(function(header) { return {header: header, col: headers.indexOf(header) + 1}; })
    .filter(function(item) { return item.col > 0; })
    .sort(function(a, b) { return b.col - a.col; })
    .forEach(function(item) {
      try {
        sheet.deleteColumn(item.col);
        removed++;
      } catch (e) {
        console.log("電話履歴の不要列削除をスキップ: " + item.header + " " + e.message);
      }
    });
  return removed;
}

function applyPhoneHistoryDirectInputLayoutNoGroups_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return false;
  clearColumnGroupsForSheet_(sheet);
  try { deleteDeprecatedPhoneHistoryStatusColumns_(sheet); } catch (e) {}
  hidePhoneHistoryInternalColumnsUltraLight_(sheet);
  try { showPhoneHistoryNoticeColumn_(sheet); } catch (e) {}
  return true;
}

