function sortPhoneHistoryDateTimeUltraLight() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("電話履歴");
  if (!sheet || sheet.getLastRow() < 3) {
    toast_("電話履歴に整理対象の行がありません。");
    return;
  }

  const headers = getHeaders_(sheet);
  if (!headers.length) return;

  // p61bp:
  // トリガー自動ソートではなく、手動で押す超軽量日時ソート。
  // 使用行＋5行だけを触り、通知全件再計算・一覧再作成・重い表示調整はしない。
  const lastCol = headers.length;
  const rowCount = getPhoneHistoryDateTimeUltraLightRowCount_(sheet);
  if (rowCount <= 1) {
    toast_("電話履歴に整理対象の行がありません。");
    return;
  }

  const filterRangeA1 = removePhoneHistoryFilterBeforeSort_(sheet);
  try {
    const range = sheet.getRange(2, 1, rowCount, lastCol);
    let values = range.getValues();
    values = normalizePhoneHistoryRowsForSortValues_(values, headers);
    values = sortPhoneHistoryRowsByDateTimeUltraLight_(values, headers);
    range.setValues(values);

    try { repairPhoneHistoryDoneCheckDisplayForRange_(sheet, 2, rowCount); } catch (e) {}
    SpreadsheetApp.flush();
    toast_("電話履歴を日時順に整理しました（超軽量）。");
  } finally {
    restorePhoneHistoryFilterAfterSort_(sheet, filterRangeA1);
  }
}

function getPhoneHistoryDateTimeUltraLightRowCount_(sheet) {
  if (!sheet) return 0;
  const availableRows = Math.max(sheet.getMaxRows() - 1, 1);
  const usedRows = Math.max(sheet.getLastRow() - 1, 1);
  return Math.min(availableRows, usedRows + 5);
}

function sortPhoneHistoryRowsByDateTimeUltraLight_(values, headers) {
  const dataRows = [];
  const draftRows = [];
  const emptyRows = [];

  (values || []).forEach(function(row) {
    if (isMeaningfulPhoneHistoryRow_(headers, row)) {
      dataRows.push(row);
    } else if (isBusinessDataRow_(headers, row, "電話履歴")) {
      draftRows.push(row);
    } else {
      emptyRows.push(row);
    }
  });

  dataRows.sort(function(a, b) {
    const ac = getPhoneDateTimeValue_(a, headers);
    const bc = getPhoneDateTimeValue_(b, headers);
    const ah = ac > 0;
    const bh = bc > 0;
    if (ah && !bh) return -1;
    if (!ah && bh) return 1;
    if (ah && bh && ac !== bc) return ac - bc;

    // 同時刻なら未完了を完了より上にするだけ。細かい通知・新着順までは見ない。
    const ao = getPhoneSortOrder_(a, headers);
    const bo = getPhoneSortOrder_(b, headers);
    return ao - bo;
  });

  draftRows.sort(function(a, b) {
    return comparePhoneDraftDateTime_(a, b, headers);
  });

  return dataRows.concat(draftRows, emptyRows);
}

function menuSafe_sortPhoneHistoryDateTimeUltraLight() {
  return runExclusiveMenuOperation_("電話履歴を日時順に整理（超軽量）", function() {
    return sortPhoneHistoryDateTimeUltraLight();
  });
}

