/******************************
 * v9.7.48p61cb 電話履歴 チェックボックス/通知判定 安全修正
 * - 通常メニューでは電話履歴だけを触る。
 * - 完了チェック/既読/個人確認者列の false/FALSE 文字をチェックボックス値へ戻す。
 * - 電話履歴の通知は日付基準ではなく、完了チェック基準へ統一する。
 ******************************/

function getPhoneHistoryCheckboxColumnsP61CB_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return [];
  const headers = getHeaders_(sheet);
  const cols = [];

  function addHeader(header) {
    const col = headers.indexOf(header) + 1;
    if (col > 0 && cols.indexOf(col) < 0) cols.push(col);
  }

  addHeader(PHONE_DONE_CHECK_HEADER);
  addHeader(READ_HEADER);

  try {
    getPersonalMembers_().forEach(addHeader);
  } catch (e) {}

  const readCol = headers.indexOf(READ_HEADER) + 1;
  if (readCol > 0) {
    const anchors = [
      "備考",
      "電話ID",
      PHONE_NOTIFY_TO_HEADER,
      PHONE_NOTIFY_EMAIL_HEADER,
      PHONE_NOTIFY_METHOD_HEADER,
      PHONE_MOBILE_NOTIFY_HEADER,
      PHONE_MOBILE_MESSAGE_HEADER,
      PHONE_EMAIL_NOTIFY_HEADER,
      PHONE_EMAIL_SENT_AT_HEADER,
      CALENDAR_ID_HEADER,
      "ID"
    ];
    let endCol = headers.length + 1;
    anchors.forEach(function(anchor) {
      const col = headers.indexOf(anchor) + 1;
      if (col > readCol && col < endCol) endCol = col;
    });
    for (let col = readCol + 1; col < endCol; col++) {
      const header = String(headers[col - 1] || "").trim();
      if (!header) continue;
      if (["通知", "対応メモ", "備考"].indexOf(header) >= 0) continue;
      if (cols.indexOf(col) < 0) cols.push(col);
    }
  }

  return cols.sort(function(a, b) { return a - b; });
}

function isPhoneHistoryCheckboxActiveRowP61CB_(headers, rowValues) {
  return isMeaningfulPhoneHistoryRow_(headers, rowValues);
}

function repairPhoneHistoryCheckboxColumnsP61CB_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  const headers = getHeaders_(sheet);
  if (!headers.length || sheet.getLastRow() < 2) return 0;

  const checkboxCols = getPhoneHistoryCheckboxColumnsP61CB_(sheet);
  if (!checkboxCols.length) return 0;

  const lastRow = sheet.getLastRow();
  const rowCount = lastRow - 1;
  const allValues = sheet.getRange(2, 1, rowCount, headers.length).getValues();
  const activeFlags = allValues.map(function(rowValues) {
    return isPhoneHistoryCheckboxActiveRowP61CB_(headers, rowValues);
  });

  let repaired = 0;
  checkboxCols.forEach(function(col) {
    const range = sheet.getRange(2, col, rowCount, 1);
    const oldValues = range.getValues().map(function(row) { return row[0]; });

    try {
      range.clearDataValidations();
      range.clearContent();
    } catch (e0) {}

    let start = -1;
    for (let i = 0; i <= activeFlags.length; i++) {
      const active = i < activeFlags.length && activeFlags[i];
      if (active && start < 0) start = i;
      if ((!active || i === activeFlags.length) && start >= 0) {
        const len = i - start;
        const seg = sheet.getRange(2 + start, col, len, 1);
        try { seg.insertCheckboxes(); } catch (e1) {}
        const values = [];
        for (let j = start; j < i; j++) {
          values.push([isCheckboxTrueValueP61BZ_(oldValues[j])]);
        }
        try {
          seg.setValues(values);
          repaired += len;
        } catch (e2) {
          try {
            seg.clearDataValidations();
            seg.clearContent();
            seg.insertCheckboxes();
            seg.setValues(values.map(function(v) { return [v[0] === true]; }));
            repaired += len;
          } catch (e3) {}
        }
        start = -1;
      }
    }
  });

  try { applyPersonalCheckColumnLayout_(sheet); } catch (e4) {}
  return repaired;
}

function getPhoneNoticeText_(dateValue, phoneStatus, rowObj) {
  const hasPhoneContent = rowObj ? isMeaningfulPhoneHistoryRowObject_(rowObj) : true;
  if (!hasPhoneContent) return "";

  const status = resolvePhoneStatusForRow_(phoneStatus, rowObj);
  if (status === "完了") return "完了";
  if (status === "中止" || status === "不要" || status === "対象外") return "";
  return "要確認";
}

function refreshPhoneHistoryNewMarkAndNoticeP61CB_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return {newMarks: 0, notices: 0};
  const result = {newMarks: 0, notices: 0};
  const headers = getHeaders_(sheet);
  if (!headers.length || sheet.getLastRow() < 2) return result;
  const newCol = headers.indexOf(PHONE_NEW_MARK_HEADER) + 1;
  const noticeCol = headers.indexOf("通知") + 1;
  const rowCount = sheet.getLastRow() - 1;
  const values = sheet.getRange(2, 1, rowCount, headers.length).getValues();

  if (newCol > 0) {
    const newValues = values.map(function(rowValues) {
      const obj = objectFromRow(headers, rowValues);
      return [getPhoneNewMarkText_(obj["電話対応"], obj)];
    });
    sheet.getRange(2, newCol, rowCount, 1).setValues(newValues);
    result.newMarks = rowCount;
  }

  if (noticeCol > 0) {
    const noticeValues = values.map(function(rowValues) {
      const obj = objectFromRow(headers, rowValues);
      return [getPhoneNoticeText_(obj["日付"], obj["電話対応"], obj)];
    });
    sheet.getRange(2, noticeCol, rowCount, 1).setValues(noticeValues);
    result.notices = rowCount;
  }

  return result;
}

