/******************************
 * v9.7.48p61ci 電話履歴 false 残り 再修正
 * - p61ch実行後も「既読」の隣や個人確認周辺に false が残るケース向け。
 * - 電話履歴だけを対象にし、他シートは触らない。
 ******************************/

function isBooleanResidueValueP61CI_(value, displayValue) {
  if (value === true || value === false) return true;
  const s = String(displayValue !== undefined ? displayValue : value || "").trim().toLowerCase();
  return ["true", "false", "TRUE", "FALSE"].map(function(x){ return String(x).toLowerCase(); }).indexOf(s) >= 0;
}

function hasBooleanResidueInColumnP61CI_(sheet, col, rowCount) {
  if (!sheet || col <= 0 || rowCount <= 0) return false;
  try {
    const range = sheet.getRange(2, col, rowCount, 1);
    const values = range.getValues();
    const displays = range.getDisplayValues();
    for (let i = 0; i < values.length; i++) {
      if (isBooleanResidueValueP61CI_(values[i][0], displays[i][0])) return true;
    }
  } catch (e) {}
  return false;
}

function columnHasCheckboxRuleP61CI_(sheet, col, rowCount) {
  if (!sheet || col <= 0 || rowCount <= 0) return false;
  try {
    const checkRows = Math.min(rowCount, 40);
    const validations = sheet.getRange(2, col, checkRows, 1).getDataValidations();
    for (let r = 0; r < validations.length; r++) {
      const rule = validations[r][0];
      if (rule && rule.getCriteriaType && String(rule.getCriteriaType()) === String(SpreadsheetApp.DataValidationCriteria.CHECKBOX)) return true;
    }
  } catch (e) {}
  return false;
}

function isDefinitelyNonCheckboxPhoneHeaderP61CI_(header) {
  const h = String(header || "").trim();
  if (!h) return false;
  return [
    PHONE_NEW_MARK_HEADER,
    "日付",
    "時間",
    "相手",
    "折り返し電話番号",
    "内容",
    "担当",
    "通知",
    "対応メモ",
    "備考",
    PHONE_NOTIFY_TO_HEADER,
    PHONE_NOTIFY_EMAIL_HEADER,
    PHONE_NOTIFY_METHOD_HEADER,
    PHONE_MOBILE_NOTIFY_HEADER,
    PHONE_MOBILE_MESSAGE_HEADER,
    PHONE_EMAIL_NOTIFY_HEADER,
    PHONE_EMAIL_SENT_AT_HEADER,
    "電話ID",
    "ID",
    CALENDAR_ID_HEADER,
    "カレンダーID"
  ].indexOf(h) >= 0;
}

function getPhoneHistoryCheckboxColumnsP61CB_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return [];
  const headers = getHeaders_(sheet);
  const cols = [];
  const rowCount = getPhoneHistoryCheckboxRepairRowLimitP61CH_(sheet);

  function add(col) {
    if (col > 0 && col <= sheet.getLastColumn() && cols.indexOf(col) < 0) cols.push(col);
  }

  function addHeader(header) {
    const col = headers.indexOf(header) + 1;
    if (col > 0) add(col);
  }

  addHeader(PHONE_DONE_CHECK_HEADER);
  addHeader(READ_HEADER);
  addHeader("個人確認");

  try { getPersonalMembers_().forEach(addHeader); } catch (e) {}

  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  const readCol = headers.indexOf(READ_HEADER) + 1;
  const memoCol = headers.indexOf("対応メモ") + 1;
  const remarksCol = headers.indexOf("備考") + 1;

  // 既読の右側から備考/通知内部列の手前までは、個人確認系の候補。
  if (readCol > 0) {
    const anchors = [
      "備考",
      "電話ID",
      "ID",
      CALENDAR_ID_HEADER,
      "カレンダーID",
      PHONE_NOTIFY_TO_HEADER,
      PHONE_NOTIFY_EMAIL_HEADER,
      PHONE_NOTIFY_METHOD_HEADER,
      PHONE_MOBILE_NOTIFY_HEADER,
      PHONE_MOBILE_MESSAGE_HEADER,
      PHONE_EMAIL_NOTIFY_HEADER,
      PHONE_EMAIL_SENT_AT_HEADER,
      "通知",
      "対応メモ"
    ];
    let endCol = headers.length + 1;
    anchors.forEach(function(anchor) {
      const c = headers.indexOf(anchor) + 1;
      if (c > readCol && c < endCol) endCol = c;
    });
    for (let c = readCol; c < endCol; c++) {
      const h = String(headers[c - 1] || "").trim();
      if (isDefinitelyNonCheckboxPhoneHeaderP61CI_(h)) continue;
      if (h || hasBooleanResidueInColumnP61CI_(sheet, c, rowCount) || columnHasCheckboxRuleP61CI_(sheet, c, rowCount)) add(c);
    }
  }

  // 完了チェック〜備考の間で、false/trueだけが残っている列も拾う。
  // 通知・対応メモなど通常列は後段で空欄掃除だけ行う。
  const scanStart = doneCol > 0 ? doneCol : Math.max(1, readCol - 3);
  const scanEnd = remarksCol > 0 ? remarksCol - 1 : Math.min(sheet.getLastColumn(), (readCol > 0 ? readCol + 8 : sheet.getLastColumn()));
  for (let c = scanStart; c <= scanEnd; c++) {
    const h = String(headers[c - 1] || "").trim();
    if (isDefinitelyNonCheckboxPhoneHeaderP61CI_(h)) continue;
    if (hasBooleanResidueInColumnP61CI_(sheet, c, rowCount) || columnHasCheckboxRuleP61CI_(sheet, c, rowCount)) add(c);
  }

  return cols.sort(function(a, b) { return a - b; });
}

function clearPhoneHistoryFalseFromNonCheckboxColumnsP61CI_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return 0;
  const headers = getHeaders_(sheet);
  if (!headers.length) return 0;
  const rowCount = getPhoneHistoryCheckboxRepairRowLimitP61CH_(sheet);
  if (rowCount <= 0) return 0;

  const checkboxCols = getPhoneHistoryCheckboxColumnsP61CB_(sheet);
  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  const remarksCol = headers.indexOf("備考") + 1;
  const scanStart = doneCol > 0 ? doneCol : 1;
  const scanEnd = remarksCol > 0 ? remarksCol : Math.min(sheet.getLastColumn(), scanStart + 12);

  const width = Math.min(headers.length, sheet.getLastColumn());
  const rowValues = sheet.getRange(2, 1, rowCount, width).getValues();
  const activeFlags = rowValues.map(function(row) { return isPhoneHistoryCheckboxActiveRowP61CB_(headers, row); });
  let cleared = 0;

  for (let c = scanStart; c <= scanEnd; c++) {
    if (checkboxCols.indexOf(c) >= 0) continue;
    const h = String(headers[c - 1] || "").trim();
    if (!isDefinitelyNonCheckboxPhoneHeaderP61CI_(h) && h !== "通知" && h !== "対応メモ" && h !== "備考") continue;

    const range = sheet.getRange(2, c, rowCount, 1);
    const values = range.getValues();
    const displays = range.getDisplayValues();
    let changed = false;
    for (let r = 0; r < values.length; r++) {
      if (activeFlags[r] && isBooleanResidueValueP61CI_(values[r][0], displays[r][0])) {
        values[r][0] = "";
        changed = true;
        cleared++;
      }
    }
    if (changed) {
      try { range.setValues(values); } catch (e) {}
    }
  }
  return cleared;
}

// p61ci: p61chの既読/チェックボックス修復をさらに強化して上書き。
