/******************************
 * v9.7.48p61ck 電話履歴 二人目個人確認 false 再修正
 * - p61ci後も「既読」右側の2人目個人確認列に false が残るケース向け。
 * - 既読〜備考の間は個人確認ブロックとして扱い、ヘッダー名が空欄/旧名でもチェックボックスへ戻す。
 * - 電話履歴だけを対象にし、他シートは触らない。
 ******************************/

function getPhoneHistoryReadPersonalBlockColumnsP61CJ_(sheet) {
  if (!sheet || sheet.getName() !== "電話履歴") return [];
  const headers = getHeaders_(sheet);
  if (!headers.length) return [];

  const cols = [];
  function add(col) {
    if (col > 0 && col <= sheet.getLastColumn() && cols.indexOf(col) < 0) cols.push(col);
  }

  const readCol = headers.indexOf(READ_HEADER) + 1;
  const doneCol = headers.indexOf(PHONE_DONE_CHECK_HEADER) + 1;
  add(doneCol);
  add(readCol);

  // 設定シート上の既読確認者名は必ず対象にする。
  try {
    getPersonalMembers_().forEach(function(name) {
      const col = headers.indexOf(name) + 1;
      add(col);
    });
  } catch (e) {}

  if (readCol <= 0) return cols.sort(function(a, b) { return a - b; });

  // 既読の右から、次の通常列の手前までを個人確認ブロックとして扱う。
  // ここは共有シートの列グループや縦書きでヘッダー取得が不安定でも false を取り残さないため、
  // ヘッダー名が空欄でも範囲ごとチェックボックス候補に含める。
  const anchors = [
    "備考",
    PHONE_NOTIFY_TO_HEADER,
    PHONE_NOTIFY_EMAIL_HEADER,
    PHONE_NOTIFY_METHOD_HEADER,
    PHONE_MOBILE_NOTIFY_HEADER,
    PHONE_MOBILE_MESSAGE_HEADER,
    PHONE_EMAIL_NOTIFY_HEADER,
    PHONE_EMAIL_SENT_AT_HEADER,
    "電話ID",
    "ID",
    CALENDAR_ID_HEADER,
    "カレンダーID"
  ];

  let endCol = headers.length + 1;
  anchors.forEach(function(anchor) {
    const c = headers.indexOf(anchor) + 1;
    if (c > readCol && c < endCol) endCol = c;
  });

  // 備考などが見つからない場合でも、既読の右側を必要最小限だけ見る。
  if (!endCol || endCol <= readCol) {
    endCol = Math.min(sheet.getLastColumn() + 1, readCol + 8);
  }

  for (let c = readCol; c < endCol; c++) {
    const h = String(headers[c - 1] || "").trim();
    // 既読〜備考の間に通常列が紛れ込んだ場合は除外する。
    if (["通知", "対応メモ", "備考", PHONE_NOTIFY_TO_HEADER, PHONE_NOTIFY_EMAIL_HEADER, PHONE_NOTIFY_METHOD_HEADER, PHONE_MOBILE_NOTIFY_HEADER, PHONE_MOBILE_MESSAGE_HEADER, PHONE_EMAIL_NOTIFY_HEADER, PHONE_EMAIL_SENT_AT_HEADER, "電話ID", "ID", CALENDAR_ID_HEADER, "カレンダーID"].indexOf(h) >= 0) continue;
    add(c);
  }

  return cols.sort(function(a, b) { return a - b; });
}

function forceRepairPhoneHistoryReadPersonalBlockP61CJ_(sheet) {
  if (!sheet) sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("電話履歴");
  if (!sheet || sheet.getName() !== "電話履歴") return 0;

  const headers = getHeaders_(sheet);
  if (!headers.length || sheet.getMaxRows() < 2) return 0;

  const rowCount = getPhoneHistoryCheckboxRepairRowLimitP61CH_(sheet);
  if (rowCount <= 0) return 0;

  const cols = getPhoneHistoryReadPersonalBlockColumnsP61CJ_(sheet);
  if (!cols.length) return 0;

  const width = Math.min(headers.length, sheet.getLastColumn());
  const rowValues = sheet.getRange(2, 1, rowCount, width).getValues();
  const activeFlags = rowValues.map(function(row) {
    return isPhoneHistoryCheckboxActiveRowP61CB_(headers, row);
  });

  const checkboxRule = SpreadsheetApp.newDataValidation().requireCheckbox().build();
  let repaired = 0;

  cols.forEach(function(col) {
    if (col <= 0 || col > sheet.getLastColumn()) return;
    const range = sheet.getRange(2, col, rowCount, 1);
    const oldValues = range.getValues().map(function(r) { return r[0]; });
    const oldDisplays = range.getDisplayValues().map(function(r) { return r[0]; });

    try { range.clearDataValidations(); } catch (e0) {}
    try { range.clearContent(); } catch (e1) {}

    let start = -1;
    for (let i = 0; i <= activeFlags.length; i++) {
      const active = i < activeFlags.length && activeFlags[i];
      if (active && start < 0) start = i;
      if ((!active || i === activeFlags.length) && start >= 0) {
        const len = i - start;
        const seg = sheet.getRange(2 + start, col, len, 1);
        const values = [];
        for (let j = start; j < i; j++) {
          values.push([isCheckboxTrueValueP61CH_(oldValues[j], oldDisplays[j])]);
        }
        try {
          seg.setDataValidation(checkboxRule);
          seg.setValues(values);
          repaired += len;
        } catch (e2) {
          try {
            seg.insertCheckboxes();
            seg.setValues(values.map(function(v) { return [v[0] === true]; }));
            repaired += len;
          } catch (e3) {}
        }
        start = -1;
      }
    }
  });

  try { applyPersonalCheckColumnLayout_(sheet); } catch (e4) {}
  return repaired;
}

