/******************************
 * v9.7.48p61df 既読セル崩れの軽量修復
 * - セル調整/コンパクト表示で既読・個人確認セルのチェックボックス表示が崩れた時の対策。
 * - 開いているシートだけを対象にし、列順・行グループ・条件付き書式は触らない。
 * - 実データ行にはチェックボックスを戻し、空行/下書き行は空欄へ戻す。
 * - 電話履歴では完了チェックも同時に軽量復旧する。
 ******************************/
function menuSafe_repairActiveSheetReadCellsP61DE() {
  return runExclusiveMenuOperation_("今のシートだけ既読セル修復", function() {
    return repairActiveSheetReadCellsP61DE();
  });
}

function repairActiveSheetReadCellsP61DE() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  if (!sheet) return;
  const result = repairReadCellsForSheetLightP61DE_(sheet, {layout: true});
  if (!result || result.skipped) {
    toast_((result && result.message) ? result.message : "入力シートを開いてから実行してください");
    return result;
  }
  toast_("既読セルを修復しました（軽量）: " + sheet.getName()
    + " / 対象列 " + result.columns
    + " / チェック " + result.checkboxCells
    + " / 空欄戻し " + result.clearedCells);
  return result;
}

function repairReadCellsForSheetLightP61DE_(sheet, options) {
  options = options || {};
  if (!sheet || !sheet.getName) return {skipped: true, message: "シートを開いてから実行してください"};

  const sheetName = sheet.getName();
  if (isAutoOutputSheet_(sheetName) || SUPPORT_SHEETS.includes(sheetName)) {
    return {skipped: true, message: "入力シートを開いてから実行してください: " + sheetName};
  }

  const headers = getHeaders_(sheet);
  if (!headers.length) return {skipped: true, message: "ヘッダー行が見つかりません: " + sheetName};

  const lastRow = sheet.getLastRow();
  if (lastRow < 2) return {skipped: true, message: "修復対象の入力行がありません: " + sheetName};

  const targetHeaders = getReadCellTargetHeadersP61DE_(sheet, headers);
  if (!targetHeaders.length) return {skipped: true, message: "既読・個人確認列が見つかりません: " + sheetName};

  const rowCount = lastRow - 1;
  const values = sheet.getRange(2, 1, rowCount, headers.length).getValues();
  const hasDataFlags = values.map(function(rowValues) {
    return isBusinessDataRow_(headers, rowValues, sheetName);
  });

  const dataRuns = getTrueRuns_(hasDataFlags);
  const blankRuns = getFalseRunsP61DE_(hasDataFlags);
  let checkboxCells = 0;
  let clearedCells = 0;
  let columns = 0;

  targetHeaders.forEach(function(header) {
    const col = headers.indexOf(header) + 1;
    if (col <= 0) return;
    columns++;

    const targetRange = sheet.getRange(2, col, rowCount, 1);
    const oldValues = targetRange.getValues();

    dataRuns.forEach(function(run) {
      const startRow = run.start + 2;
      const length = run.length;
      if (length <= 0) return;
      const range = sheet.getRange(startRow, col, length, 1);
      range.insertCheckboxes();
      const newValues = oldValues
        .slice(run.start, run.start + length)
        .map(function(row) { return [isTruthy_(row[0])]; });
      range.setValues(newValues);
      try { range.setHorizontalAlignment("center").setVerticalAlignment("middle"); } catch (e) {}
      checkboxCells += length;
    });

    blankRuns.forEach(function(run) {
      const startRow = run.start + 2;
      const length = run.length;
      if (length <= 0) return;
      const range = sheet.getRange(startRow, col, length, 1);
      range.clearDataValidations();
      range.clearContent();
      try { range.setHorizontalAlignment("center").setVerticalAlignment("middle"); } catch (e) {}
      clearedCells += length;
    });

    try {
      sheet.setColumnWidth(col, 38);
      const headerCell = sheet.getRange(1, col);
      headerCell
        .setVerticalText(true)
        .setHorizontalAlignment("center")
        .setVerticalAlignment("middle")
        .setWrap(false);
    } catch (e2) {}
  });

  // 電話履歴は既読グループ/列順は触らず、内部列だけ軽く隠す。
  if (sheetName === "電話履歴") {
    try { hidePhoneHistoryInternalColumnsUltraLight_(sheet); } catch (e3) {}
  }
  try { hideSystemColumnsForSheet_(sheet); } catch (e4) {}

  return {
    skipped: false,
    sheetName: sheetName,
    columns: columns,
    checkboxCells: checkboxCells,
    clearedCells: clearedCells
  };
}

function getReadCellTargetHeadersP61DE_(sheet, headers) {
  const existing = {};
  (headers || []).forEach(function(header) {
    const h = String(header || "").trim();
    if (h) existing[h] = true;
  });

  const targets = [];
  function add(header) {
    const h = String(header || "").trim();
    if (!h || !existing[h] || targets.indexOf(h) >= 0) return;
    targets.push(h);
  }

  add(READ_HEADER);
  try {
    getCheckboxHeadersForSheet_(sheet).forEach(add);
  } catch (e) {}

  // 会社によって「個人確認」という単独列で残っている場合も拾う。
  (headers || []).forEach(function(header) {
    const h = String(header || "").trim();
    if (h && h.indexOf("個人確認") >= 0) add(h);
  });

  // 電話履歴はAppSheet投稿後に完了チェックもFALSE文字化しやすいので一緒に復旧。
  if (sheet && sheet.getName && sheet.getName() === "電話履歴") add(PHONE_DONE_CHECK_HEADER);
  return targets;
}

function getFalseRunsP61DE_(flags) {
  const runs = [];
  let start = -1;
  (flags || []).forEach(function(flag, index) {
    if (!flag && start < 0) start = index;
    if ((flag || index === flags.length - 1) && start >= 0) {
      const end = (!flag && index === flags.length - 1) ? index + 1 : index;
      runs.push({start: start, length: end - start});
      start = -1;
    }
  });
  return runs;
}

function formatActiveSheetOnly() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  if (!sheet) return;
  const res = applyActiveSheetCellAdjustLightP61DC_(sheet, "standard");
  if (!res || res.ok === false) {
    toast_((res && res.message) ? res.message : "入力シートを開いてから実行してください");
    return;
  }
  let checkResult = null;
  try { checkResult = repairReadCellsForSheetLightP61DE_(sheet, {layout: true}); } catch (e) {}
  const sheetName = sheet.getName();
  const suffix = checkResult && !checkResult.skipped ? " / 既読セル修復 " + checkResult.checkboxCells + "個" : "";
  toast_(sheetName === "電話履歴"
    ? "電話履歴をセル調整しました（軽量版：列順・既読グループは触っていません）" + suffix
    : "今のシートだけセル調整しました（軽量版）: " + sheetName + suffix);
}

