function writeDataDesignSheetP61DL_(sheet, rows, widths, headerColor) {
  sheet.clear();
  sheet.clearFormats();
  if (!rows || !rows.length) return;

  const colCount = rows[0].length;
  sheet.getRange(1, 1, rows.length, colCount).setValues(rows);
  sheet.getRange(1, 1, 1, colCount)
    .setFontWeight("bold")
    .setBackground(headerColor || "#d9ead3")
    .setHorizontalAlignment("center");
  sheet.setFrozenRows(1);
  sheet.getRange(1, 1, rows.length, colCount)
    .setWrap(true)
    .setVerticalAlignment("middle");

  for (let i = 0; i < colCount; i++) {
    sheet.setColumnWidth(i + 1, widths && widths[i] ? widths[i] : 180);
  }

  try {
    const filter = sheet.getFilter();
    if (filter) filter.remove();
  } catch (e) {}

  try {
    sheet.getRange(1, 1, Math.max(rows.length, 2), colCount).createFilter();
  } catch (e) {}

  try {
    const lastRow = Math.max(rows.length, 2);
    const lastCol = colCount;
    sheet.getRange(1, 1, lastRow, lastCol).setBorder(true, true, true, true, true, true, "#cccccc", SpreadsheetApp.BorderStyle.SOLID);
  } catch (e) {}

  try {
    if (rows.length > 1) {
      sheet.getRange(2, 1, rows.length - 1, 1).setFontWeight("bold");
    }
  } catch (e) {}

  try {
    sheet.setRowHeights(1, Math.min(rows.length, 120), 36);
  } catch (e) {}
}



/**
 * p61dm/p61do互換用の旧確認用資料作成処理は、p61dqで作成対象から外した。
 * 現行は menuSafe_createCheckMaterialSheetsP61DQ() を使用する。
 */

/**
 * p61do: 説明用語が入った旧シート名や確認用シートを日常画面から隠す。
 * 削除はせず、必要な時だけシート一覧から再表示して確認する運用にする。
 */
function hideExternalCheckSheetsP61DO_(ss) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const oldPrefix = "G" + "PT";
  const namesToHide = [
    ("外" + "部" + "確認用まとめ"),
    "変更差分メモ",
    "動作確認結果",
    "確認依頼文",
    ("外" + "部" + "確認注意点"),
    "診断用",
    // p61dm以前に作成済みの旧名称。社内画面では見せない。
    oldPrefix + "チェック用まとめ",
    oldPrefix + "差分メモ",
    oldPrefix + "動作確認結果",
    oldPrefix + "貼付用プロンプト",
    oldPrefix + "注意点",
    oldPrefix + "診断用"
  ];

  namesToHide.forEach(function(name) {
    const sheet = ss.getSheetByName(name);
    if (!sheet) return;
    hideSheetSafelyP61DO_(ss, sheet);
  });
}

function hideSheetSafelyP61DO_(ss, sheet) {
  try {
    const sheets = ss.getSheets();
    const visibleSheets = sheets.filter(function(s) { return !s.isSheetHidden(); });
    if (visibleSheets.length <= 1 && visibleSheets[0] && visibleSheets[0].getSheetId() === sheet.getSheetId()) return;

    const active = ss.getActiveSheet();
    if (active && active.getSheetId() === sheet.getSheetId()) {
      const fallback = sheets.find(function(s) {
        return s.getSheetId() !== sheet.getSheetId() && !s.isSheetHidden();
      });
      if (fallback) ss.setActiveSheet(fallback);
    }
    sheet.hideSheet();
  } catch (e) {}
}


/**
 * p61dp: 確認用資料の文言を社内向けに中立化する。
 * - シートを隠すだけではなく、旧名称・旧表現を社内向けの表現へ置き換える。
 * - 業務ロジック、電話履歴、資格管理、一覧抽出、過去整理は触らない。
 */
function menuSafe_createCheckMaterialSheetsP61DP() {
  return runExclusiveMenuOperation_("確認用資料作成/更新", function() {
    return createCheckMaterialSheetsP61DP();
  });
}

function createCheckMaterialSheetsP61DP() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  // p61dp: 旧名称シートが残っている場合は、隠すだけでなく社内向け名称へ整理する。
  try { neutralizeOldCheckMaterialSheetsP61DP_(ss); } catch (e) {}

  createCheckMaterialSummarySheetP61DP_(ss);
  createCheckMaterialDiffMemoSheetP61DP_(ss);
  createCheckMaterialOperationResultSheetP61DP_(ss);
  createCheckMaterialRequestTextSheetP61DP_(ss);
  createCheckMaterialCautionSheetP61DP_(ss);

  // p61dp: 作成済みの確認・設計・診断系シート内に旧表現が残っていれば置換する。
  try { sanitizeCheckMaterialTermsP61DP_(ss); } catch (e) {}

  try { hideSystemColumnsForAllInputSheets && hideSystemColumnsForAllInputSheets(); } catch (e) {}
  try { toast_("確認用資料を作成/更新しました。社内画面向けに用語を置き換え済みです。"); } catch (e) {}
}

