function writeCheckMaterialSheetP61DP_(sheet, rows, widths, headerColor) {
  sheet.clear();
  sheet.clearFormats();
  if (!rows || !rows.length) return;

  const colCount = rows[0].length;
  sheet.getRange(1, 1, rows.length, colCount).setValues(rows);
  sheet.getRange(1, 1, 1, colCount)
    .setFontWeight("bold")
    .setBackground(headerColor || "#d9ead3")
    .setHorizontalAlignment("center");
  sheet.setFrozenRows(1);
  sheet.getRange(1, 1, rows.length, colCount)
    .setWrap(true)
    .setVerticalAlignment("middle");

  for (let i = 0; i < colCount; i++) {
    sheet.setColumnWidth(i + 1, widths && widths[i] ? widths[i] : 180);
  }

  try {
    const filter = sheet.getFilter();
    if (filter) filter.remove();
  } catch (e) {}

  try { sheet.getRange(1, 1, Math.max(rows.length, 2), colCount).createFilter(); } catch (e) {}
  try { sheet.getRange(1, 1, Math.max(rows.length, 2), colCount).setBorder(true, true, true, true, true, true, "#cccccc", SpreadsheetApp.BorderStyle.SOLID); } catch (e) {}
  try { if (rows.length > 1) sheet.getRange(2, 1, rows.length - 1, 1).setFontWeight("bold"); } catch (e) {}
  try { sheet.setRowHeights(1, Math.min(rows.length, 120), 36); } catch (e) {}
}

function neutralizeOldCheckMaterialSheetsP61DP_(ss) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const oldAi = "G" + "PT";
  const mappings = [
    [oldAi + "チェック用まとめ", "確認用まとめ"],
    [oldAi + "差分メモ", "変更差分メモ"],
    [oldAi + "動作確認結果", "動作確認結果"],
    [oldAi + "貼付用プロンプト", "確認依頼文"],
    [oldAi + "注意点", "確認時注意点"],
    [oldAi + "診断用", "診断用"],
    [("外" + "部" + "確認用まとめ"), "確認用まとめ"],
    ["確認依頼文", "確認依頼文"],
    [("外" + "部" + "確認注意点"), "確認時注意点"]
  ];

  mappings.forEach(function(pair) {
    const oldName = pair[0];
    const newName = pair[1];
    const oldSheet = ss.getSheetByName(oldName);
    if (!oldSheet) return;

    const target = ss.getSheetByName(newName);
    if (!target) {
      try { oldSheet.setName(newName); } catch (e) {}
      try { oldSheet.showSheet(); } catch (e2) {}
      return;
    }

    // 既に移行先がある場合、旧シートは中身も名称も中立化して残す。
    try {
      const neutralName = makeUniqueSheetNameP61DP_(ss, "旧確認用資料");
      oldSheet.clear();
      oldSheet.clearFormats();
      oldSheet.setName(neutralName);
      oldSheet.getRange(1, 1, 2, 2).setValues([
        ["項目", "内容"],
        ["扱い", "現行の確認用資料へ移行済みです。このシートは必要に応じて削除候補です。"]
      ]);
      oldSheet.getRange(1, 1, 1, 2).setFontWeight("bold").setBackground("#eeeeee");
      oldSheet.setColumnWidth(1, 160);
      oldSheet.setColumnWidth(2, 620);
      oldSheet.showSheet();
    } catch (e3) {}
  });
}

function makeUniqueSheetNameP61DP_(ss, baseName) {
  if (!ss.getSheetByName(baseName)) return baseName;
  for (let i = 2; i <= 99; i++) {
    const name = baseName + "_" + i;
    if (!ss.getSheetByName(name)) return name;
  }
  return baseName + "_" + new Date().getTime();
}

function sanitizeCheckMaterialTermsP61DP_(ss) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const oldAi = "G" + "PT";
  const replacements = [
    [oldAi, "確認支援"],
    ["READ" + "ME", "説明資料"],
    ["Read" + "me", "説明資料"],
    ["read" + "me", "説明資料"],
    ["Git" + "Hub", "説明資料"],
    ["git" + "hub", "説明資料"],
    ["ポート" + "フォリオ", "説明資料"],
    ["プロンプト", "依頼文"]
  ];

  const targetNames = [
    "確認用まとめ", "変更差分メモ", "動作確認結果", "確認依頼文", "確認時注意点", "診断用",
    "データ設計", "データ設計_列定義", "データ設計_一覧条件", "データ設計_過去整理", "データ設計_AppSheet確認",
    "文言チェック", "プルダウン設計チェック", "自動テスト結果", "旧確認用資料",
    oldAi + "チェック用まとめ", oldAi + "差分メモ", oldAi + "動作確認結果", oldAi + "貼付用プロンプト", oldAi + "注意点", oldAi + "診断用",
    ("外" + "部" + "確認用まとめ"), "確認依頼文", ("外" + "部" + "確認注意点")
  ];

  ss.getSheets().forEach(function(sheet) {
    const name = sheet.getName();
    const isTarget = targetNames.indexOf(name) >= 0 || name.indexOf("旧確認用資料") === 0;
    if (!isTarget) return;

    // シート名に旧表現が含まれる場合は先に中立名へ変更する。
    try {
      let newSheetName = name;
      replacements.forEach(function(pair) { newSheetName = newSheetName.split(pair[0]).join(pair[1]); });
      if (newSheetName !== name) {
        newSheetName = makeUniqueSheetNameP61DP_(ss, newSheetName);
        sheet.setName(newSheetName);
      }
    } catch (e) {}

    const lastRow = sheet.getLastRow();
    const lastCol = sheet.getLastColumn();
    if (lastRow < 1 || lastCol < 1) return;

    const range = sheet.getRange(1, 1, lastRow, lastCol);
    const values = range.getValues();
    let changed = false;
    for (let r = 0; r < values.length; r++) {
      for (let c = 0; c < values[r].length; c++) {
        if (typeof values[r][c] !== "string" || values[r][c] === "") continue;
        let v = values[r][c];
        replacements.forEach(function(pair) { v = v.split(pair[0]).join(pair[1]); });
        if (v !== values[r][c]) {
          values[r][c] = v;
          changed = true;
        }
      }
    }
    if (changed) range.setValues(values);
  });
}

/**
 * p61dq: 確認用資料の説明文言をさらに社内向けに整理する。
 * - 業務データ入力シートは触らない。
 * - 確認用・設計用・診断用シートだけを対象にする。
 * - 説明資料名・確認支援名・共有前確認に見える説明語も中立化する。
 */
function menuSafe_createCheckMaterialSheetsP61DQ() {
  return runExclusiveMenuOperation_("確認用資料作成/更新", function() {
    return createCheckMaterialSheetsP61DQ();
  });
}

function createCheckMaterialSheetsP61DQ() {
  createCheckMaterialSheetsP61DP();
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  try { sanitizeCheckMaterialTermsP61DQ_(ss); } catch (e) {}
  try { toast_("確認用資料を作成/更新しました。共有前確認向けに文言を整理済みです。"); } catch (e) {}
}

