function writeCheckMaterialSheetLightP61DR_(sheet, rows, widths, headerColor) {
  if (!sheet || !rows || !rows.length) return;

  // 軽量化：フィルタ作成、全セル罫線、行高一括変更、全シート走査はしない。
  sheet.clear();
  sheet.clearFormats();

  const colCount = rows[0].length;
  sheet.getRange(1, 1, rows.length, colCount).setValues(rows);
  sheet.getRange(1, 1, 1, colCount)
    .setFontWeight("bold")
    .setBackground(headerColor || "#d9ead3")
    .setHorizontalAlignment("center")
    .setVerticalAlignment("middle");
  try { sheet.setFrozenRows(1); } catch (e) {}
  try { sheet.getRange(1, 1, rows.length, colCount).setWrap(true).setVerticalAlignment("middle"); } catch (e2) {}

  for (let i = 0; i < colCount; i++) {
    try { sheet.setColumnWidth(i + 1, widths && widths[i] ? widths[i] : 180); } catch (e3) {}
  }
}

function neutralizeOldCheckMaterialSheetNamesP61DR_(ss) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const oldAi = "G" + "PT";
  const oldNames = [
    oldAi + "チェック用まとめ",
    oldAi + "差分メモ",
    oldAi + "動作確認結果",
    oldAi + "貼付用プロンプト",
    oldAi + "注意点",
    oldAi + "診断用",
    ("外" + "部" + "確認用まとめ"),
    ("外" + "部" + "確認注意点"),
    "確認支援チェック用まとめ",
    "確認支援差分メモ",
    "確認支援動作確認結果",
    "確認支援貼付用依頼文",
    "確認支援注意点",
    "確認支援診断用"
  ];

  oldNames.forEach(function(name) {
    const sheet = ss.getSheetByName(name);
    if (!sheet) return;
    try {
      const neutralName = makeUniqueSheetNameP61DR_(ss, "旧確認用資料");
      sheet.clear();
      sheet.clearFormats();
      sheet.setName(neutralName);
      sheet.getRange(1, 1, 2, 2).setValues([
        ["項目", "内容"],
        ["扱い", "現行の確認用資料へ移行済みです。このシートは必要に応じて削除候補です。"]
      ]);
      sheet.getRange(1, 1, 1, 2).setFontWeight("bold").setBackground("#eeeeee");
      hideSheetSafelyP61DR_(ss, sheet);
    } catch (e) {}
  });
}

function makeUniqueSheetNameP61DR_(ss, baseName) {
  if (!ss.getSheetByName(baseName)) return baseName;
  for (let i = 2; i <= 99; i++) {
    const name = baseName + "_" + i;
    if (!ss.getSheetByName(name)) return name;
  }
  return baseName + "_" + new Date().getTime();
}

function hideSheetSafelyP61DR_(ss, sheet) {
  try {
    const sheets = ss.getSheets();
    const visibleSheets = sheets.filter(function(s) { return !s.isSheetHidden(); });
    if (visibleSheets.length <= 1 && visibleSheets[0] && visibleSheets[0].getSheetId() === sheet.getSheetId()) return;
    const active = ss.getActiveSheet();
    if (active && active.getSheetId() === sheet.getSheetId()) {
      const fallback = sheets.find(function(s) { return s.getSheetId() !== sheet.getSheetId() && !s.isSheetHidden(); });
      if (fallback) ss.setActiveSheet(fallback);
    }
    sheet.hideSheet();
  } catch (e) {}
}


/******************************
 * v9.7.48p61dt 軽量安定化追加
 * - 電話履歴に電話ID列が無い場合だけ、最後尾へ追加して実データ行へIDを採番する。
 * - 診断用シートでは「個人確認」という固定列名だけで判定せず、既読確認者列があればOK扱いにする。
 * - 各入力シートの個別ID名は、共通のID列がある場合も互換OKとして診断する。
 * - 過去整理・月次メニューに「今のシート：月ごとに畳む」を見える位置へ戻す。
 ******************************/

function normalizeHeaderP61DT_(value) {
  return String(value || "").replace(/\s+/g, "").trim();
}

function hasHeaderP61DT_(headers, header) {
  const target = normalizeHeaderP61DT_(header);
  return (headers || []).some(function(h) { return normalizeHeaderP61DT_(h) === target; });
}

function isIdLikeHeaderP61DT_(header) {
  const h = normalizeHeaderP61DT_(header);
  return h === "ID" || /ID$/.test(h) || /ＩＤ$/.test(h);
}

function hasCompatibleHeaderP61DT_(headers, expectedHeader) {
  if (hasHeaderP61DT_(headers, expectedHeader)) return true;
  const expected = normalizeHeaderP61DT_(expectedHeader);
  if (isIdLikeHeaderP61DT_(expected)) {
    return (headers || []).some(function(h) { return isIdLikeHeaderP61DT_(h); });
  }
  if (expected === "個人確認") {
    return hasAnyPersonalCheckHeaderP61DT_(headers);
  }
  return false;
}

function hasAnyPersonalCheckHeaderP61DT_(headers) {
  headers = headers || [];
  if (hasHeaderP61DT_(headers, "個人確認")) return true;
  let members = [];
  try { members = getPersonalMembers_(); } catch (e) { members = []; }
  const normalizedHeaders = headers.map(normalizeHeaderP61DT_);
  for (let i = 0; i < members.length; i++) {
    if (normalizedHeaders.indexOf(normalizeHeaderP61DT_(members[i])) >= 0) return true;
  }
  // 既読列の右側に、備考/通知/ID等の前まで確認者らしい列がある場合もOK扱いにする。
  const readIndex = normalizedHeaders.indexOf(normalizeHeaderP61DT_(READ_HEADER));
  if (readIndex < 0) return false;
  const stopWords = ["備考", "通知", "電話ID", "資格ID", "ID", "カレンダーID", "対応メモ", "通知先", "通知先メール", "通知方法", "スマホ通知", "通知メッセージ", "メール通知", "通知送信日時"];
  const stopKeys = stopWords.map(normalizeHeaderP61DT_);
  for (let col = readIndex + 1; col < headers.length; col++) {
    const key = normalizedHeaders[col];
    if (!key) continue;
    if (stopKeys.indexOf(key) >= 0 || /ID$/.test(key)) break;
    if (key !== normalizeHeaderP61DT_(READ_HEADER)) return true;
  }
  return false;
}

function getMissingHeadersRelaxedP61DT_(headers, expected) {
  return (expected || []).filter(function(h) { return !hasCompatibleHeaderP61DT_(headers, h); });
}

function getPhoneHistoryIdColumnP61DT_(sheet) {
  if (!sheet) return 0;
  const headers = getHeaders_(sheet);
  let col = headers.indexOf("電話ID") + 1;
  if (col > 0) return col;
  // 旧共通IDがある場合でも、電話履歴は電話IDを正として追加する。
  const lastCol = Math.max(sheet.getLastColumn(), 1);
  col = lastCol + 1;
  sheet.getRange(1, col).setValue("電話ID");
  try { sheet.getRange(1, col).setFontWeight("bold").setBackground("#d9ead3"); } catch (e) {}
  return col;
}

function isMeaningfulPhoneHistoryForIdP61DT_(headers, rowValues) {
  const keys = ["相手", "折り返し電話番号", "内容", "担当", "対応メモ"];
  for (let i = 0; i < keys.length; i++) {
    const idx = headers.indexOf(keys[i]);
    if (idx >= 0 && String(rowValues[idx] || "").trim() !== "") return true;
  }
  return false;
}

function ensurePhoneHistoryIdColumnLightP61DT_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("電話履歴");
  const result = {added: 0, filled: 0, hidden: 0};
  if (!sheet) return result;

  const before = getHeaders_(sheet);
  const hadPhoneId = before.indexOf("電話ID") >= 0;
  const idCol = getPhoneHistoryIdColumnP61DT_(sheet);
  if (!hadPhoneId) result.added = 1;

  const headers = getHeaders_(sheet);
  if (sheet.getLastRow() >= 2 && idCol > 0) {
    const rowCount = sheet.getLastRow() - 1;
    const width = Math.max(headers.length, idCol);
    const values = sheet.getRange(2, 1, rowCount, width).getValues();
    const idValues = sheet.getRange(2, idCol, rowCount, 1).getValues();
    let changed = false;
    for (let i = 0; i < rowCount; i++) {
      if (String(idValues[i][0] || "").trim()) continue;
      if (!isMeaningfulPhoneHistoryForIdP61DT_(headers, values[i])) continue;
      idValues[i][0] = "TEL-" + Utilities.getUuid();
      result.filled++;
      changed = true;
    }
    if (changed) sheet.getRange(2, idCol, rowCount, 1).setValues(idValues);
  }

  try {
    sheet.hideColumns(idCol);
    result.hidden = 1;
  } catch (e) {}
  return result;
}

function repairSharedSheetNoColumnGroups() {
  const lock = acquireCompanyPackLock_("電話履歴：通知表示＋既読グループ復旧");
  if (!lock) return;
  try {
    const idResult = ensurePhoneHistoryIdColumnLightP61DT_();
    const result = repairPhoneHistoryNoticeReadGroupOnlyP61CA_();
    toast_("電話履歴を軽量復旧しました（電話ID列追加:" + (idResult.added || 0) + " / ID採番:" + (idResult.filled || 0) + "行 / チェック修復:" + (result.checkboxes || 0) + "セル / false掃除:" + (result.cleared || 0) + "セル / 既読グループ:" + (result.personalGroups || 0) + "件）。");
    return result;
  } catch (err) {
    toast_("電話履歴の軽量復旧でエラー: " + err.message);
    throw err;
  } finally {
    try { lock.releaseLock(); } catch (e) {}
  }
}

