/******************************
 * v9.7.48p61du 電話ID復旧の実行経路修正
 * - p61dtでは「電話履歴：通知表示＋既読グループ復旧」が二重ロックになり、電話ID復旧が実行されない場合があった。
 * - メニューからは共通ロックを1回だけ取得し、その中で電話ID復旧→既読グループ復旧を実行する。
 * - 「電話IDだけ復旧（軽量）」を追加し、原因切り分けしやすくする。
 * - 電話ID列は復旧後に非表示にするため、画面上に見えなくても診断では確認できる。
 ******************************/

function ensurePhoneHistoryIdColumnLightP61DU_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("電話履歴");
  const result = {added: 0, filled: 0, hidden: 0, col: 0};
  if (!sheet) return result;

  const beforeHeaders = getHeaders_(sheet);
  let idCol = beforeHeaders.indexOf("電話ID") + 1;
  if (idCol <= 0) {
    idCol = Math.max(sheet.getLastColumn(), 1) + 1;
    sheet.getRange(1, idCol).setValue("電話ID");
    try { sheet.getRange(1, idCol).setFontWeight("bold").setBackground("#d9ead3"); } catch (e) {}
    result.added = 1;
  }
  result.col = idCol;

  const headers = getHeaders_(sheet);
  const lastRow = sheet.getLastRow();
  if (lastRow >= 2) {
    const rowCount = lastRow - 1;
    const width = Math.max(headers.length, idCol);
    const values = sheet.getRange(2, 1, rowCount, width).getValues();
    const idValues = sheet.getRange(2, idCol, rowCount, 1).getValues();
    let changed = false;
    for (let i = 0; i < rowCount; i++) {
      if (String(idValues[i][0] || "").trim()) continue;
      if (!isMeaningfulPhoneHistoryForIdP61DT_(headers, values[i])) continue;
      idValues[i][0] = "TEL-" + Utilities.getUuid();
      result.filled++;
      changed = true;
    }
    if (changed) sheet.getRange(2, idCol, rowCount, 1).setValues(idValues);
  }

  try {
    sheet.hideColumns(idCol);
    result.hidden = 1;
  } catch (e) {}
  return result;
}

function repairPhoneHistoryNoticeReadGroupWithIdCoreP61DU_() {
  const idResult = ensurePhoneHistoryIdColumnLightP61DU_();
  let result = {};
  try {
    result = repairPhoneHistoryNoticeReadGroupOnlyP61CA_() || {};
  } catch (e) {
    // 既読グループ側で止まっても電話ID復旧結果は残す。
    result = {error: e.message};
  }
  result.phoneIdAdded = idResult.added || 0;
  result.phoneIdFilled = idResult.filled || 0;
  result.phoneIdHidden = idResult.hidden || 0;
  result.phoneIdCol = idResult.col || 0;
  return result;
}

function menuSafe_ensurePhoneHistoryIdOnlyP61DU() {
  return runExclusiveMenuOperation_("電話IDだけ復旧（軽量）", function() {
    const result = ensurePhoneHistoryIdColumnLightP61DU_();
    toast_("電話IDだけ復旧しました（列追加:" + (result.added || 0) + " / ID採番:" + (result.filled || 0) + "行 / 非表示:" + (result.hidden || 0) + "）。電話ID列は通常非表示です。");
    return result;
  });
}

// 既存メニュー名から呼ばれる関数を、二重ロックなしの実体へ差し替える。
function repairSharedSheetNoColumnGroups() {
  const result = repairPhoneHistoryNoticeReadGroupWithIdCoreP61DU_();
  toast_("電話履歴を軽量復旧しました（電話ID列追加:" + (result.phoneIdAdded || 0) + " / ID採番:" + (result.phoneIdFilled || 0) + "行 / チェック修復:" + (result.checkboxes || 0) + "セル / false掃除:" + (result.cleared || 0) + "セル / 既読グループ:" + (result.personalGroups || 0) + "件）。電話ID列は通常非表示です。");
  return result;
}

